-- Q1
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem disse: \"Penso, logo existo\"?", "options": [{"id": "a", "text": "René Descartes"}, {"id": "b", "text": "Immanuel Kant"}, {"id": "c", "text": "John Locke"}, {"id": "d", "text": "Platão"}], "explanation": "René Descartes escreveu \"Cogito, ergo sum\" (Penso, logo existo) na sua obra de 1637 \"Discurso do Método\". Tornou-se o elemento fundador da filosofia racionalista ocidental, estabelecendo que o próprio ato de duvidar da existência prova que se existe como ser pensante.", "wrong_explanations": {"b": "Kant construiu sobre o racionalismo de Descartes, mas é conhecido pelo imperativo categórico, não por esta frase.", "c": "Locke era empirista e acreditava que o conhecimento vem da experiência sensorial, não da razão inata.", "d": "Platão viveu quase 2000 anos antes de Descartes e focou-se na teoria das Formas."}}, "es": {"question": "¿Quién dijo: \"Pienso, luego existo\"?", "options": [{"id": "a", "text": "René Descartes"}, {"id": "b", "text": "Immanuel Kant"}, {"id": "c", "text": "John Locke"}, {"id": "d", "text": "Platón"}], "explanation": "René Descartes escribió \"Cogito, ergo sum\" (Pienso, luego existo) en su obra de 1637 \"Discurso del Método\". Se convirtió en el pilar de la filosofía racionalista occidental, demostrando que el acto mismo de dudar prueba la existencia como ser pensante.", "wrong_explanations": {"b": "Kant se basó en el racionalismo de Descartes, pero es conocido por el imperativo categórico, no por esta frase.", "c": "Locke era empirista y creía que el conocimiento proviene de la experiencia sensorial, no de la razón innata.", "d": "Platón vivió casi 2000 años antes de Descartes y se centró en la teoría de las Formas."}}, "fr": {"question": "Qui a dit : \"Je pense, donc je suis\" ?", "options": [{"id": "a", "text": "René Descartes"}, {"id": "b", "text": "Emmanuel Kant"}, {"id": "c", "text": "John Locke"}, {"id": "d", "text": "Platon"}], "explanation": "René Descartes a écrit \"Cogito, ergo sum\" (Je pense, donc je suis) dans son œuvre de 1637 \"Discours de la méthode\". C''est devenu le fondement de la philosophie rationaliste occidentale, établissant que l''acte même de douter prouve l''existence en tant qu''être pensant.", "wrong_explanations": {"b": "Kant a construit sur le rationalisme de Descartes mais est connu pour l''impératif catégorique, pas pour cette citation.", "c": "Locke était empiriste et croyait que la connaissance vient de l''expérience sensorielle, pas de la raison innée.", "d": "Platon a vécu près de 2000 ans avant Descartes et se concentrait sur la théorie des Formes."}}}'::jsonb WHERE question = 'Who said: "I think, therefore I am"?';

