UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem disse: \"A única coisa que temos a temer é o próprio medo\"?", "options": [{"id": "a", "text": "Winston Churchill"}, {"id": "b", "text": "Franklin D. Roosevelt"}, {"id": "c", "text": "Theodore Roosevelt"}, {"id": "d", "text": "John F. Kennedy"}], "explanation": "Franklin D. Roosevelt disse estas palavras no seu discurso inaugural de 1933, durante a Grande Depressão. A citação completa enfatiza que o medo irracional paralisa a ação, enquanto a coragem permite o progresso.", "wrong_explanations": {"a": "Churchill é famoso por ''Lutaremos nas praias'' e ''Sangue, trabalho, lágrimas e suor''.", "c": "Theodore Roosevelt é conhecido por ''Fale suavemente e carregue um grande porrete''.", "d": "JFK é lembrado por ''Não pergunte o que o seu país pode fazer por você''."}}, "es": {"question": "¿Quién dijo: \"Lo único que debemos temer es al miedo mismo\"?", "options": [{"id": "a", "text": "Winston Churchill"}, {"id": "b", "text": "Franklin D. Roosevelt"}, {"id": "c", "text": "Theodore Roosevelt"}, {"id": "d", "text": "John F. Kennedy"}], "explanation": "Franklin D. Roosevelt pronunció estas palabras en su discurso inaugural de 1933, durante la Gran Depresión. La cita completa enfatiza que el miedo irracional paraliza la acción, mientras el coraje permite el progreso.", "wrong_explanations": {"a": "Churchill es famoso por ''Lucharemos en las playas'' y ''Sangre, esfuerzo, lágrimas y sudor''.", "c": "Theodore Roosevelt es conocido por ''Habla suave y lleva un gran garrote''.", "d": "JFK es recordado por ''No preguntes qué puede hacer tu país por ti''."}}, "fr": {"question": "Qui a dit : \"La seule chose que nous devons craindre, c''est la crainte elle-même\" ?", "options": [{"id": "a", "text": "Winston Churchill"}, {"id": "b", "text": "Franklin D. Roosevelt"}, {"id": "c", "text": "Theodore Roosevelt"}, {"id": "d", "text": "John F. Kennedy"}], "explanation": "Franklin D. Roosevelt a prononcé ces mots lors de son discours inaugural de 1933, pendant la Grande Dépression. La citation complète souligne que la peur irrationnelle paralyse l''action, tandis que le courage permet le progrès.", "wrong_explanations": {"a": "Churchill est célèbre pour ''Nous nous battrons sur les plages'' et ''Du sang, du labeur, des larmes et de la sueur''.", "c": "Theodore Roosevelt est connu pour ''Parlez doucement et portez un gros bâton''.", "d": "JFK est connu pour ''Ne demandez pas ce que votre pays peut faire pour vous''."}}}'::jsonb WHERE question = 'Who said: "The only thing we have to fear is fear itself"?';

-- Q3
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem escreveu: \"O homem nasce livre, e por toda parte encontra-se acorrentado\"?", "options": [{"id": "a", "text": "John Locke"}, {"id": "b", "text": "Thomas Hobbes"}, {"id": "c", "text": "Jean-Jacques Rousseau"}, {"id": "d", "text": "Voltaire"}], "explanation": "Jean-Jacques Rousseau abriu \"O Contrato Social\" (1762) com esta frase célebre. Embora Rousseau tenha identificado o problema da liberdade perdida, a sua solução coletivista da ''vontade geral'' paradoxalmente justificou mais correntes através da tirania democrática.", "wrong_explanations": {"a": "Locke defendia os direitos naturais e o governo limitado, mas esta citação é de Rousseau.", "b": "Hobbes acreditava que o homem na natureza vivia numa ''guerra de todos contra todos'' — um sentimento bem oposto.", "d": "Voltaire defendia a liberdade individual e a razão, mas não escreveu esta frase específica."}}, "es": {"question": "¿Quién escribió: \"El hombre nace libre, y en todas partes se encuentra encadenado\"?", "options": [{"id": "a", "text": "John Locke"}, {"id": "b", "text": "Thomas Hobbes"}, {"id": "c", "text": "Jean-Jacques Rousseau"}, {"id": "d", "text": "Voltaire"}], "explanation": "Jean-Jacques Rousseau abrió \"El Contrato Social\" (1762) con esta famosa frase. Aunque Rousseau identificó el problema de la libertad perdida, su solución colectivista de la ''voluntad general'' paradójicamente justificó más cadenas a través de la tiranía democrática.", "wrong_explanations": {"a": "Locke defendía los derechos naturales y el gobierno limitado, pero esta cita es de Rousseau.", "b": "Hobbes creía que el hombre en estado natural vivía en una ''guerra de todos contra todos'' — un sentimiento muy opuesto.", "d": "Voltaire defendía la libertad individual y la razón, pero no escribió esta frase específica."}}, "fr": {"question": "Qui a écrit : \"L''homme est né libre, et partout il est dans les fers\" ?", "options": [{"id": "a", "text": "John Locke"}, {"id": "b", "text": "Thomas Hobbes"}, {"id": "c", "text": "Jean-Jacques Rousseau"}, {"id": "d", "text": "Voltaire"}], "explanation": "Jean-Jacques Rousseau a ouvert \"Du Contrat social\" (1762) avec cette phrase célèbre. Bien que Rousseau ait identifié le problème de la liberté perdue, sa solution collectiviste de la ''volonté générale'' a paradoxalement justifié davantage de chaînes par la tyrannie démocratique.", "wrong_explanations": {"a": "Locke défendait les droits naturels et le gouvernement limité, mais cette citation est de Rousseau.", "b": "Hobbes pensait que l''homme à l''état de nature vivait une ''guerre de tous contre tous'' — un sentiment bien opposé.", "d": "Voltaire défendait la liberté individuelle et la raison, mais n''a pas écrit cette phrase."}}}'::jsonb WHERE question = 'Who wrote: "Man is born free, and everywhere he is in chains"?';

-- Q4
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem disse: \"A é A\"?", "options": [{"id": "a", "text": "Ayn Rand"}, {"id": "b", "text": "Aristóteles"}, {"id": "c", "text": "Ludwig Wittgenstein"}, {"id": "d", "text": "Bertrand Russell"}], "explanation": "Aristóteles formulou a Lei da Identidade (A é A) como fundamento da lógica. Ayn Rand posteriormente tornou este princípio central do Objetivismo, enfatizando que a existência existe e as coisas são o que são, independentemente da consciência.", "wrong_explanations": {"a": "Rand popularizou ''A é A'' na filosofia moderna, mas creditou Aristóteles como seu criador.", "c": "Wittgenstein focou-se na linguagem e no significado, não na lógica clássica.", "d": "Russell trabalhou com lógica matemática, mas a Lei da Identidade o precede por milénios."}}, "es": {"question": "¿Quién dijo: \"A es A\"?", "options": [{"id": "a", "text": "Ayn Rand"}, {"id": "b", "text": "Aristóteles"}, {"id": "c", "text": "Ludwig Wittgenstein"}, {"id": "d", "text": "Bertrand Russell"}], "explanation": "Aristóteles formuló la Ley de Identidad (A es A) como fundamento de la lógica. Ayn Rand luego hizo de este principio algo central en el Objetivismo, enfatizando que la existencia existe y las cosas son lo que son, independientemente de la conciencia.", "wrong_explanations": {"a": "Rand popularizó ''A es A'' en la filosofía moderna, pero acreditó a Aristóteles como su creador.", "c": "Wittgenstein se centró en el lenguaje y el significado, no en la lógica clásica.", "d": "Russell trabajó en lógica matemática, pero la Ley de Identidad lo precede por milenios."}}, "fr": {"question": "Qui a dit : \"A est A\" ?", "options": [{"id": "a", "text": "Ayn Rand"}, {"id": "b", "text": "Aristote"}, {"id": "c", "text": "Ludwig Wittgenstein"}, {"id": "d", "text": "Bertrand Russell"}], "explanation": "Aristote a formulé la Loi d''Identité (A est A) comme fondement de la logique. Ayn Rand a ensuite fait de ce principe un élément central de l''Objectivisme, soulignant que l''existence existe et que les choses sont ce qu''elles sont, indépendamment de la conscience.", "wrong_explanations": {"a": "Rand a popularisé ''A est A'' dans la philosophie moderne, mais a crédité Aristote comme son auteur.", "c": "Wittgenstein se concentrait sur le langage et le sens, pas sur la logique classique.", "d": "Russell a travaillé sur la logique mathématique, mais la Loi d''Identité le précède de millénaires."}}}'::jsonb WHERE question = 'Who said: "A is A"?';

