UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem escreveu: \"A mente não é um vaso a ser enchido, mas um fogo a ser aceso\"?", "options": [{"id": "a", "text": "Sócrates"}, {"id": "b", "text": "Plutarco"}, {"id": "c", "text": "Aristóteles"}, {"id": "d", "text": "Séneca"}], "explanation": "Plutarco escreveu isto em \"Sobre Ouvir Palestras\". Enfatiza que a verdadeira educação não é receber informação passivamente, mas envolver a mente ativamente através da razão e da curiosidade.", "wrong_explanations": {"a": "Sócrates usava o método socrático, mas esta citação é de Plutarco.", "c": "Aristóteles fundou o Liceu, mas não escreveu esta metáfora específica.", "d": "Séneca era filósofo estoico com metáforas educacionais diferentes."}}, "es": {"question": "¿Quién escribió: \"La mente no es un vaso por llenar, sino un fuego por encender\"?", "options": [{"id": "a", "text": "Sócrates"}, {"id": "b", "text": "Plutarco"}, {"id": "c", "text": "Aristóteles"}, {"id": "d", "text": "Séneca"}], "explanation": "Plutarco escribió esto en \"Sobre cómo escuchar conferencias\". Enfatiza que la verdadera educación no es recibir información pasivamente, sino involucrar la mente activamente a través de la razón y la curiosidad.", "wrong_explanations": {"a": "Sócrates usaba el método socrático, pero esta cita es de Plutarco.", "c": "Aristóteles fundó el Liceo, pero no escribió esta metáfora específica.", "d": "Séneca era filósofo estoico con metáforas educativas diferentes."}}, "fr": {"question": "Qui a écrit : \"L''esprit n''est pas un vase à remplir, mais un feu à allumer\" ?", "options": [{"id": "a", "text": "Socrate"}, {"id": "b", "text": "Plutarque"}, {"id": "c", "text": "Aristote"}, {"id": "d", "text": "Sénèque"}], "explanation": "Plutarque a écrit ceci dans \"Comment écouter les conférences\". Cela souligne que la véritable éducation ne consiste pas à recevoir passivement des informations, mais à engager activement l''esprit par la raison et la curiosité.", "wrong_explanations": {"a": "Socrate utilisait la méthode socratique, mais cette citation est de Plutarque.", "c": "Aristote a fondé le Lycée, mais n''a pas écrit cette métaphore spécifique.", "d": "Sénèque était un philosophe stoïcien avec des métaphores éducatives différentes."}}}'::jsonb WHERE question = 'Who wrote: "The mind is not a vessel to be filled, but a fire to be kindled"?';

