UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem disse: \"Dê-me a liberdade ou dê-me a morte!\"?", "options": [{"id": "a", "text": "Thomas Jefferson"}, {"id": "b", "text": "Benjamin Franklin"}, {"id": "c", "text": "Patrick Henry"}, {"id": "d", "text": "George Washington"}], "explanation": "Patrick Henry fez esta famosa declaração em 1775, instando a Virgínia a juntar-se à Revolução Americana. Exemplifica o princípio de que a liberdade é tão essencial à vida humana que a morte é preferível à escravidão.", "wrong_explanations": {"a": "Jefferson escreveu a Declaração de Independência, mas não disse isto.", "b": "Franklin disse ''Aqueles que abrem mão da Liberdade essencial para comprar um pouco de Segurança temporária não merecem nenhuma das duas''.", "d": "Washington liderou o Exército Continental, mas Patrick Henry fez este discurso."}}, "es": {"question": "¿Quién dijo: \"¡Denme libertad o denme la muerte!\"?", "options": [{"id": "a", "text": "Thomas Jefferson"}, {"id": "b", "text": "Benjamin Franklin"}, {"id": "c", "text": "Patrick Henry"}, {"id": "d", "text": "George Washington"}], "explanation": "Patrick Henry hizo esta famosa declaración en 1775, instando a Virginia a unirse a la Revolución Americana. Ejemplifica el principio de que la libertad es tan esencial para la vida humana que la muerte es preferible a la esclavitud.", "wrong_explanations": {"a": "Jefferson escribió la Declaración de Independencia, pero no dijo esto.", "b": "Franklin dijo ''Quienes renuncian a la Libertad esencial para obtener un poco de Seguridad temporal no merecen ninguna de las dos''.", "d": "Washington lideró el Ejército Continental, pero Patrick Henry pronunció este discurso."}}, "fr": {"question": "Qui a dit : \"Donnez-moi la liberté ou donnez-moi la mort !\" ?", "options": [{"id": "a", "text": "Thomas Jefferson"}, {"id": "b", "text": "Benjamin Franklin"}, {"id": "c", "text": "Patrick Henry"}, {"id": "d", "text": "George Washington"}], "explanation": "Patrick Henry a fait cette célèbre déclaration en 1775, exhortant la Virginie à rejoindre la Révolution américaine. Elle illustre le principe que la liberté est si essentielle à la vie humaine que la mort est préférable à l''esclavage.", "wrong_explanations": {"a": "Jefferson a écrit la Déclaration d''Indépendance, mais n''a pas dit cela.", "b": "Franklin a dit ''Ceux qui renoncent à la Liberté essentielle pour obtenir un peu de Sécurité temporaire ne méritent ni l''une ni l''autre''.", "d": "Washington a dirigé l''armée continentale, mais c''est Patrick Henry qui a prononcé ce discours."}}}'::jsonb WHERE question = 'Who said: "Give me liberty, or give me death!"?';

-- Q7
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem escreveu: \"A menor minoria na terra é o indivíduo\"?", "options": [{"id": "a", "text": "Friedrich Hayek"}, {"id": "b", "text": "Milton Friedman"}, {"id": "c", "text": "Ayn Rand"}, {"id": "d", "text": "Ludwig von Mises"}], "explanation": "Ayn Rand escreveu isto para enfatizar que os direitos individuais são a base de todos os direitos. Se você afirma defender minorias mas viola direitos individuais, contradiz-se no nível mais fundamental.", "wrong_explanations": {"a": "Hayek defendia a liberdade individual, mas esta citação específica é de Rand.", "b": "Friedman defendia mercados livres, mas não cunhou esta frase.", "d": "Mises focava-se no individualismo económico, mas esta é a formulação de Rand."}}, "es": {"question": "¿Quién escribió: \"La minoría más pequeña en la tierra es el individuo\"?", "options": [{"id": "a", "text": "Friedrich Hayek"}, {"id": "b", "text": "Milton Friedman"}, {"id": "c", "text": "Ayn Rand"}, {"id": "d", "text": "Ludwig von Mises"}], "explanation": "Ayn Rand escribió esto para enfatizar que los derechos individuales son la base de todos los derechos. Si dices defender minorías pero violas derechos individuales, te contradices en el nivel más fundamental.", "wrong_explanations": {"a": "Hayek defendía la libertad individual, pero esta cita específica es de Rand.", "b": "Friedman abogaba por los mercados libres, pero no acuñó esta frase.", "d": "Mises se enfocaba en el individualismo económico, pero esta es la formulación de Rand."}}, "fr": {"question": "Qui a écrit : \"La plus petite minorité sur terre est l''individu\" ?", "options": [{"id": "a", "text": "Friedrich Hayek"}, {"id": "b", "text": "Milton Friedman"}, {"id": "c", "text": "Ayn Rand"}, {"id": "d", "text": "Ludwig von Mises"}], "explanation": "Ayn Rand a écrit cela pour souligner que les droits individuels sont le fondement de tous les droits. Si vous prétendez défendre les minorités tout en violant les droits individuels, vous vous contredisez au niveau le plus fondamental.", "wrong_explanations": {"a": "Hayek défendait la liberté individuelle, mais cette citation est de Rand.", "b": "Friedman prônait les marchés libres, mais n''a pas inventé cette phrase.", "d": "Mises se concentrait sur l''individualisme économique, mais c''est la formulation de Rand."}}}'::jsonb WHERE question = 'Who wrote: "The smallest minority on earth is the individual"?';

-- Q8
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem disse: \"Desaprovo o que dizes, mas defenderei até à morte o teu direito de dizê-lo\"?", "options": [{"id": "a", "text": "Voltaire"}, {"id": "b", "text": "John Stuart Mill"}, {"id": "c", "text": "Evelyn Beatrice Hall"}, {"id": "d", "text": "Thomas Paine"}], "explanation": "Evelyn Beatrice Hall escreveu isto na sua biografia de Voltaire em 1906 para resumir as crenças dele. É frequentemente atribuída erroneamente ao próprio Voltaire. O princípio capta a essência da liberdade de expressão: defender o direito dos outros de falar mesmo quando discordamos.", "wrong_explanations": {"a": "Voltaire defendia a liberdade de expressão, mas Hall escreveu este resumo das suas ideias.", "b": "Mill escreveu ''Sobre a Liberdade'' defendendo a livre expressão, mas não esta citação exata.", "d": "Paine defendeu a liberdade em ''Senso Comum'', mas não escreveu esta frase."}}, "es": {"question": "¿Quién dijo: \"Desapruebo lo que dices, pero defenderé hasta la muerte tu derecho a decirlo\"?", "options": [{"id": "a", "text": "Voltaire"}, {"id": "b", "text": "John Stuart Mill"}, {"id": "c", "text": "Evelyn Beatrice Hall"}, {"id": "d", "text": "Thomas Paine"}], "explanation": "Evelyn Beatrice Hall escribió esto en su biografía de Voltaire en 1906 para resumir sus creencias. A menudo se atribuye erróneamente al propio Voltaire. El principio capta la esencia de la libertad de expresión: defender el derecho de otros a hablar incluso cuando discrepamos.", "wrong_explanations": {"a": "Voltaire defendía la libertad de expresión, pero Hall escribió este resumen de sus ideas.", "b": "Mill escribió ''Sobre la Libertad'' defendiendo la libre expresión, pero no esta cita exacta.", "d": "Paine defendió la libertad en ''Sentido Común'', pero no escribió esta frase."}}, "fr": {"question": "Qui a dit : \"Je désapprouve ce que vous dites, mais je défendrai jusqu''à la mort votre droit de le dire\" ?", "options": [{"id": "a", "text": "Voltaire"}, {"id": "b", "text": "John Stuart Mill"}, {"id": "c", "text": "Evelyn Beatrice Hall"}, {"id": "d", "text": "Thomas Paine"}], "explanation": "Evelyn Beatrice Hall a écrit ceci dans sa biographie de Voltaire en 1906 pour résumer ses convictions. C''est souvent attribué à tort à Voltaire lui-même. Le principe capture l''essence de la liberté d''expression : défendre le droit des autres à parler même quand on est en désaccord.", "wrong_explanations": {"a": "Voltaire défendait la liberté d''expression, mais Hall a écrit ce résumé de ses idées.", "b": "Mill a écrit ''De la Liberté'' en défense de la libre expression, mais pas cette citation exacte.", "d": "Paine a défendu la liberté dans ''Le Sens commun'', mais n''a pas écrit cette phrase."}}}'::jsonb WHERE question = 'Who said: "I disapprove of what you say, but I will defend to the death your right to say it"?';

-- Q9
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem escreveu: \"Há dois romances que podem mudar a vida de um jovem de catorze anos apaixonado por livros: O Senhor dos Anéis e A Revolta de Atlas\"?", "options": [{"id": "a", "text": "Ayn Rand"}, {"id": "b", "text": "Paul Krugman"}, {"id": "c", "text": "Christopher Hitchens"}, {"id": "d", "text": "William F. Buckley"}], "explanation": "Paul Krugman escreveu isto, continuando: \"Um é uma fantasia infantil que frequentemente gera uma obsessão vitalícia com seus heróis incríveis... O outro envolve orcs.\" Apesar da hostilidade, Krugman inadvertidamente reconheceu o profundo impacto de A Revolta de Atlas nos leitores.", "wrong_explanations": {"a": "Rand escreveu A Revolta de Atlas, mas não esta citação sobre o livro.", "c": "Hitchens era um intelectual polémico, mas não escreveu isto.", "d": "Buckley era comentarista conservador que teve debates com Rand."}}, "es": {"question": "¿Quién escribió: \"Hay dos novelas que pueden cambiar la vida de un joven de catorce años aficionado a los libros: El Señor de los Anillos y La Rebelión de Atlas\"?", "options": [{"id": "a", "text": "Ayn Rand"}, {"id": "b", "text": "Paul Krugman"}, {"id": "c", "text": "Christopher Hitchens"}, {"id": "d", "text": "William F. Buckley"}], "explanation": "Paul Krugman escribió esto, continuando: \"Una es una fantasía infantil que a menudo engendra una obsesión de por vida con sus héroes increíbles... La otra involucra orcos.\" A pesar de su hostilidad, Krugman inadvertidamente reconoció el profundo impacto de La Rebelión de Atlas en los lectores.", "wrong_explanations": {"a": "Rand escribió La Rebelión de Atlas, pero no esta cita sobre el libro.", "c": "Hitchens era un intelectual polémico, pero no escribió esto.", "d": "Buckley era comentarista conservador que tuvo debates con Rand."}}, "fr": {"question": "Qui a écrit : \"Il y a deux romans qui peuvent changer la vie d''un jeune de quatorze ans passionné de livres : Le Seigneur des Anneaux et La Grève\" ?", "options": [{"id": "a", "text": "Ayn Rand"}, {"id": "b", "text": "Paul Krugman"}, {"id": "c", "text": "Christopher Hitchens"}, {"id": "d", "text": "William F. Buckley"}], "explanation": "Paul Krugman a écrit ceci, ajoutant : \"L''un est un conte de fées infantile qui engendre souvent une obsession permanente pour ses héros invraisemblables... L''autre parle d''orques.\" Malgré son hostilité, Krugman a involontairement reconnu l''impact profond de La Grève sur les lecteurs.", "wrong_explanations": {"a": "Rand a écrit La Grève, mais pas cette citation à son sujet.", "c": "Hitchens était un intellectuel controversé, mais n''a pas écrit cela.", "d": "Buckley était un commentateur conservateur qui a eu des débats avec Rand."}}}'::jsonb WHERE question = 'Who wrote: "There are two novels that can change a bookish fourteen-year old''s life: The Lord of the Rings and Atlas Shrugged"?';

-- Q10
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem escreveu: \"Quem luta com monstros deve cuidar para não se tornar um monstro\"?", "options": [{"id": "a", "text": "Carl Jung"}, {"id": "b", "text": "Friedrich Nietzsche"}, {"id": "c", "text": "Sigmund Freud"}, {"id": "d", "text": "Arthur Schopenhauer"}], "explanation": "Nietzsche escreveu isto em \"Para Além do Bem e do Mal\" (1886). A citação completa continua: \"E quando olhas longamente para um abismo, o abismo também olha para ti.\" Adverte que combater o mal exige manter a própria integridade moral.", "wrong_explanations": {"a": "Jung estudou a sombra do eu, mas esta citação é de Nietzsche.", "c": "Freud focou-se no inconsciente, mas não escreveu isto.", "d": "Schopenhauer influenciou Nietzsche, mas isto é de Para Além do Bem e do Mal."}}, "es": {"question": "¿Quién escribió: \"Quien lucha con monstruos debe cuidar de no convertirse en uno\"?", "options": [{"id": "a", "text": "Carl Jung"}, {"id": "b", "text": "Friedrich Nietzsche"}, {"id": "c", "text": "Sigmund Freud"}, {"id": "d", "text": "Arthur Schopenhauer"}], "explanation": "Nietzsche escribió esto en \"Más allá del bien y del mal\" (1886). La cita completa continúa: \"Y cuando miras largo tiempo al abismo, el abismo también mira dentro de ti.\" Advierte que combatir el mal exige mantener la propia integridad moral.", "wrong_explanations": {"a": "Jung estudió la sombra del yo, pero esta cita es de Nietzsche.", "c": "Freud se enfocó en el inconsciente, pero no escribió esto.", "d": "Schopenhauer influyó en Nietzsche, pero esto es de Más allá del bien y del mal."}}, "fr": {"question": "Qui a écrit : \"Celui qui combat les monstres doit veiller à ne pas devenir un monstre lui-même\" ?", "options": [{"id": "a", "text": "Carl Jung"}, {"id": "b", "text": "Friedrich Nietzsche"}, {"id": "c", "text": "Sigmund Freud"}, {"id": "d", "text": "Arthur Schopenhauer"}], "explanation": "Nietzsche a écrit cela dans \"Par-delà le bien et le mal\" (1886). La citation complète poursuit : \"Et si tu regardes longtemps dans un abîme, l''abîme regarde aussi en toi.\" Elle avertit que combattre le mal exige de préserver sa propre intégrité morale.", "wrong_explanations": {"a": "Jung a étudié l''ombre du moi, mais cette citation est de Nietzsche.", "c": "Freud se concentrait sur l''inconscient, mais n''a pas écrit cela.", "d": "Schopenhauer a influencé Nietzsche, mais ceci vient de Par-delà le bien et le mal."}}}'::jsonb WHERE question = 'Who wrote: "He who fights with monsters should look to it that he himself does not become a monster"?';

-- Q11
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem disse: \"O governo que governa melhor é o que governa menos\"?", "options": [{"id": "a", "text": "Thomas Jefferson"}, {"id": "b", "text": "Henry David Thoreau"}, {"id": "c", "text": "John O''Sullivan"}, {"id": "d", "text": "Thomas Paine"}], "explanation": "John O''Sullivan escreveu isto em 1837 na United States Magazine and Democratic Review. Thoreau citou e expandiu a ideia em \"Desobediência Civil\" (1849). O princípio capta a visão liberal clássica de que o poder do governo deve ser minimizado.", "wrong_explanations": {"a": "Jefferson tinha visões semelhantes, mas não cunhou esta frase.", "b": "Thoreau citou isto, mas atribuiu-o a ''aquele governo é melhor que governa menos''.", "d": "Paine criticou o governo, mas esta frase específica é de O''Sullivan."}}, "es": {"question": "¿Quién dijo: \"El gobierno que mejor gobierna es el que menos gobierna\"?", "options": [{"id": "a", "text": "Thomas Jefferson"}, {"id": "b", "text": "Henry David Thoreau"}, {"id": "c", "text": "John O''Sullivan"}, {"id": "d", "text": "Thomas Paine"}], "explanation": "John O''Sullivan escribió esto en 1837 en la United States Magazine and Democratic Review. Thoreau citó y amplió la idea en \"Desobediencia civil\" (1849). El principio capta la visión liberal clásica de que el poder del gobierno debe ser minimizado.", "wrong_explanations": {"a": "Jefferson tenía visiones similares, pero no acuñó esta frase.", "b": "Thoreau la citó, pero la atribuyó a ''aquel gobierno es mejor que gobierna menos''.", "d": "Paine criticó al gobierno, pero esta frase específica es de O''Sullivan."}}, "fr": {"question": "Qui a dit : \"Le gouvernement qui gouverne le mieux est celui qui gouverne le moins\" ?", "options": [{"id": "a", "text": "Thomas Jefferson"}, {"id": "b", "text": "Henry David Thoreau"}, {"id": "c", "text": "John O''Sullivan"}, {"id": "d", "text": "Thomas Paine"}], "explanation": "John O''Sullivan a écrit cela en 1837 dans la United States Magazine and Democratic Review. Thoreau l''a cité et développé dans \"La Désobéissance civile\" (1849). Le principe résume la vision libérale classique selon laquelle le pouvoir du gouvernement doit être minimisé.", "wrong_explanations": {"a": "Jefferson partageait des vues similaires, mais n''a pas inventé cette phrase.", "b": "Thoreau l''a citée, mais l''a attribuée à ''le meilleur gouvernement est celui qui gouverne le moins''.", "d": "Paine a critiqué le gouvernement, mais cette phrase spécifique est de O''Sullivan."}}}'::jsonb WHERE question = 'Who said: "The government that governs best, governs least"?';

-- Q12
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem escreveu: \"O caminho para o inferno está pavimentado de boas intenções\"?", "options": [{"id": "a", "text": "São Bernardo de Claraval"}, {"id": "b", "text": "Samuel Johnson"}, {"id": "c", "text": "Karl Marx"}, {"id": "d", "text": "John Milton"}], "explanation": "São Bernardo de Claraval (século XII) é creditado com a frase original em latim. Enfatiza que as intenções sozinhas são inúteis — o que importa são as consequências reais das ações. Boas intenções combinadas com más ideias levam ao desastre.", "wrong_explanations": {"a": "Johnson disse ''O inferno está pavimentado de boas intenções'', mas Bernardo originou o conceito.", "c": "Marx tinha muitas más intenções E maus resultados.", "d": "Milton escreveu Paraíso Perdido, mas não este provérbio."}}, "es": {"question": "¿Quién escribió: \"El camino al infierno está pavimentado de buenas intenciones\"?", "options": [{"id": "a", "text": "San Bernardo de Claraval"}, {"id": "b", "text": "Samuel Johnson"}, {"id": "c", "text": "Karl Marx"}, {"id": "d", "text": "John Milton"}], "explanation": "San Bernardo de Claraval (siglo XII) es acreditado con la frase original en latín. Enfatiza que las intenciones solas no sirven — lo que importa son las consecuencias reales de las acciones. Buenas intenciones combinadas con malas ideas llevan al desastre.", "wrong_explanations": {"a": "Johnson dijo ''El infierno está pavimentado de buenas intenciones'', pero Bernardo originó el concepto.", "c": "Marx tenía muchas malas intenciones Y malos resultados.", "d": "Milton escribió El Paraíso Perdido, pero no este proverbio."}}, "fr": {"question": "Qui a écrit : \"L''enfer est pavé de bonnes intentions\" ?", "options": [{"id": "a", "text": "Saint Bernard de Clairvaux"}, {"id": "b", "text": "Samuel Johnson"}, {"id": "c", "text": "Karl Marx"}, {"id": "d", "text": "John Milton"}], "explanation": "Saint Bernard de Clairvaux (XIIe siècle) est crédité de la phrase originale en latin. Elle souligne que les intentions seules sont inutiles — ce qui compte, ce sont les conséquences réelles des actions. De bonnes intentions combinées à de mauvaises idées mènent au désastre.", "wrong_explanations": {"a": "Johnson a dit ''L''enfer est pavé de bonnes intentions'', mais Bernard a créé le concept.", "c": "Marx avait beaucoup de mauvaises intentions ET de mauvais résultats.", "d": "Milton a écrit Le Paradis perdu, mais pas ce proverbe."}}}'::jsonb WHERE question = 'Who wrote: "The road to hell is paved with good intentions"?';

