-- Q13
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que a Lei da Identidade (A é A) estabelece?", "options": [{"id": "a", "text": "As coisas são o que são, independentemente do que alguém pense"}, {"id": "b", "text": "Tudo é relativo ao observador"}, {"id": "c", "text": "A realidade é criada pela consciência"}, {"id": "d", "text": "A verdade depende do contexto cultural"}], "explanation": "A Lei da Identidade estabelece que a existência existe e que as coisas têm uma natureza específica independente dos desejos, sentimentos ou crenças de qualquer pessoa. Uma coisa é ela mesma (A é A). Este é o fundamento da realidade objetiva e do pensamento racional.", "wrong_explanations": {"b": "O relativismo contradiz a Lei da Identidade ao negar a realidade objetiva.", "c": "A primazia da consciência é o erro oposto — a realidade existe independentemente da percepção.", "d": "O relativismo cultural é uma forma de subjetivismo que nega a verdade objetiva."}}, "es": {"question": "¿Qué establece la Ley de Identidad (A es A)?", "options": [{"id": "a", "text": "Las cosas son lo que son, sin importar lo que alguien piense"}, {"id": "b", "text": "Todo es relativo al observador"}, {"id": "c", "text": "La realidad es creada por la conciencia"}, {"id": "d", "text": "La verdad depende del contexto cultural"}], "explanation": "La Ley de Identidad establece que la existencia existe y que las cosas tienen una naturaleza específica independiente de los deseos, sentimientos o creencias de cualquiera. Una cosa es sí misma (A es A). Este es el fundamento de la realidad objetiva y el pensamiento racional.", "wrong_explanations": {"b": "El relativismo contradice la Ley de Identidad al negar la realidad objetiva.", "c": "La primacía de la conciencia es el error opuesto — la realidad existe independientemente de la percepción.", "d": "El relativismo cultural es una forma de subjetivismo que niega la verdad objetiva."}}, "fr": {"question": "Qu''établit la Loi d''Identité (A est A) ?", "options": [{"id": "a", "text": "Les choses sont ce qu''elles sont, peu importe ce que quiconque pense"}, {"id": "b", "text": "Tout est relatif à l''observateur"}, {"id": "c", "text": "La réalité est créée par la conscience"}, {"id": "d", "text": "La vérité dépend du contexte culturel"}], "explanation": "La Loi d''Identité établit que l''existence existe et que les choses ont une nature spécifique indépendante des souhaits, sentiments ou croyances de quiconque. Une chose est elle-même (A est A). C''est le fondement de la réalité objective et de la pensée rationnelle.", "wrong_explanations": {"b": "Le relativisme contredit la Loi d''Identité en niant la réalité objective.", "c": "La primauté de la conscience est l''erreur opposée — la réalité existe indépendamment de la perception.", "d": "Le relativisme culturel est une forme de subjectivisme qui nie la vérité objective."}}}'::jsonb WHERE question = 'What does the Law of Identity (A is A) establish?';

-- Q14
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a \"primazia da existência\" em filosofia?", "options": [{"id": "a", "text": "A consciência cria a realidade"}, {"id": "b", "text": "A realidade existe independentemente da consciência"}, {"id": "c", "text": "Existência e consciência são iguais"}, {"id": "d", "text": "Nada pode ser sabido sobre a realidade"}], "explanation": "A primazia da existência sustenta que a realidade existe independentemente de qualquer consciência. A consciência não cria a realidade; ela percebe e identifica a realidade. Este é o fundamento da objetividade — factos são factos independentemente da percepção ou desejos de qualquer pessoa.", "wrong_explanations": {"a": "Esta é a falácia da ''primazia da consciência'' — a ideia de que desejar torna real.", "c": "A existência é primária; a consciência depende da existência para ter algo DE QUE ser consciente.", "d": "Isto é ceticismo, que se contradiz a si mesmo (alegar saber que nada pode ser sabido)."}}, "es": {"question": "¿Qué es la \"primacía de la existencia\" en filosofía?", "options": [{"id": "a", "text": "La conciencia crea la realidad"}, {"id": "b", "text": "La realidad existe independientemente de la conciencia"}, {"id": "c", "text": "Existencia y conciencia son iguales"}, {"id": "d", "text": "Nada puede saberse sobre la realidad"}], "explanation": "La primacía de la existencia sostiene que la realidad existe independientemente de cualquier conciencia. La conciencia no crea la realidad; la percibe e identifica. Este es el fundamento de la objetividad — los hechos son hechos independientemente de la percepción o deseos de cualquiera.", "wrong_explanations": {"a": "Esta es la falacia de la ''primacía de la conciencia'' — la idea de que desear hace real.", "c": "La existencia es primaria; la conciencia depende de la existencia para tener algo DE QUÉ ser consciente.", "d": "Esto es escepticismo, que se contradice a sí mismo (afirmar saber que nada puede saberse)."}}, "fr": {"question": "Qu''est-ce que la \"primauté de l''existence\" en philosophie ?", "options": [{"id": "a", "text": "La conscience crée la réalité"}, {"id": "b", "text": "La réalité existe indépendamment de la conscience"}, {"id": "c", "text": "L''existence et la conscience sont égales"}, {"id": "d", "text": "Rien ne peut être connu sur la réalité"}], "explanation": "La primauté de l''existence soutient que la réalité existe indépendamment de toute conscience. La conscience ne crée pas la réalité ; elle la perçoit et l''identifie. C''est le fondement de l''objectivité — les faits sont des faits indépendamment de la perception ou des souhaits de quiconque.", "wrong_explanations": {"a": "C''est le sophisme de la ''primauté de la conscience'' — l''idée que souhaiter rend réel.", "c": "L''existence est primaire ; la conscience dépend de l''existence pour avoir quelque chose DONT être conscient.", "d": "C''est le scepticisme, qui se contredit lui-même (prétendre savoir que rien ne peut être su)."}}}'::jsonb WHERE question = 'What is the "primacy of existence" in philosophy?';

-- Q15
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Segundo Aristóteles, qual é a relação entre uma coisa e a sua natureza?", "options": [{"id": "a", "text": "Uma coisa pode agir contra a sua natureza pela força de vontade"}, {"id": "b", "text": "Uma coisa só pode agir de acordo com a sua natureza"}, {"id": "c", "text": "A natureza é uma ilusão criada pela linguagem"}, {"id": "d", "text": "As coisas não têm natureza fixa"}], "explanation": "Aristóteles estabeleceu que toda entidade tem uma identidade específica e só pode agir de acordo com a sua natureza. Uma pedra não pode decidir voar; a água não pode escolher fluir para cima. Este princípio de causalidade decorre da Lei da Identidade: as coisas são o que são e agem de acordo.", "wrong_explanations": {"a": "Ações contra a própria natureza são impossíveis — só se pode agir dentro das possibilidades que a natureza permite.", "c": "Esta é uma visão pós-modernista que Aristóteles rejeitaria como autorrefutante.", "d": "Negar naturezas fixas é negar a própria identidade, o que é autocontraditório."}}, "es": {"question": "Según Aristóteles, ¿cuál es la relación entre una cosa y su naturaleza?", "options": [{"id": "a", "text": "Una cosa puede actuar contra su naturaleza por fuerza de voluntad"}, {"id": "b", "text": "Una cosa solo puede actuar según su naturaleza"}, {"id": "c", "text": "La naturaleza es una ilusión creada por el lenguaje"}, {"id": "d", "text": "Las cosas no tienen naturaleza fija"}], "explanation": "Aristóteles estableció que toda entidad tiene una identidad específica y solo puede actuar según su naturaleza. Una piedra no puede decidir volar; el agua no puede elegir fluir hacia arriba. Este principio de causalidad se deriva de la Ley de Identidad: las cosas son lo que son y actúan de acuerdo.", "wrong_explanations": {"a": "Las acciones contra la propia naturaleza son imposibles — solo se puede actuar dentro de las posibilidades que la naturaleza permite.", "c": "Esta es una visión posmodernista que Aristóteles rechazaría como autorrefutante.", "d": "Negar naturalezas fijas es negar la identidad misma, lo cual es autocontradictorio."}}, "fr": {"question": "Selon Aristote, quelle est la relation entre une chose et sa nature ?", "options": [{"id": "a", "text": "Une chose peut agir contre sa nature par la volonté"}, {"id": "b", "text": "Une chose ne peut agir que selon sa nature"}, {"id": "c", "text": "La nature est une illusion créée par le langage"}, {"id": "d", "text": "Les choses n''ont pas de nature fixe"}], "explanation": "Aristote a établi que chaque entité a une identité spécifique et ne peut agir que selon sa nature. Une pierre ne peut décider de voler ; l''eau ne peut choisir de couler vers le haut. Ce principe de causalité découle de la Loi d''Identité : les choses sont ce qu''elles sont et agissent en conséquence.", "wrong_explanations": {"a": "Les actions contre sa propre nature sont impossibles — on ne peut agir que dans les limites de ce que sa nature permet.", "c": "C''est une vision postmoderniste qu''Aristote rejetterait comme auto-réfutante.", "d": "Nier les natures fixes, c''est nier l''identité elle-même, ce qui est auto-contradictoire."}}}'::jsonb WHERE question = 'According to Aristotle, what is the relationship between a thing and its nature?';

-- Q16
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Qual é o erro filosófico em dizer \"a realidade é o que você acredita que seja\"?", "options": [{"id": "a", "text": "Não é um erro — a crença molda a realidade"}, {"id": "b", "text": "Inverte a relação entre consciência e existência"}, {"id": "c", "text": "Só é verdade para algumas pessoas"}, {"id": "d", "text": "É verdade, mas impraticável"}], "explanation": "Isto inverte a causalidade: a consciência não cria a existência; ela identifica a existência. Se a realidade fosse o que você acredita, crenças contraditórias criariam realidades contraditórias, o que é impossível. O facto de podermos estar errados prova que a realidade é independente da crença.", "wrong_explanations": {"a": "Se a crença moldasse a realidade, poderíamos acreditar que voamos. A independência da realidade é provada pela existência do erro.", "c": "A verdade não é seletiva — as leis da realidade aplicam-se a todos igualmente.", "d": "Não é impraticável — é impossível. Contradições não podem existir."}}, "es": {"question": "¿Cuál es el error filosófico en decir \"la realidad es lo que crees que es\"?", "options": [{"id": "a", "text": "No es un error — la creencia moldea la realidad"}, {"id": "b", "text": "Invierte la relación entre conciencia y existencia"}, {"id": "c", "text": "Solo es verdad para algunas personas"}, {"id": "d", "text": "Es verdad, pero impracticable"}], "explanation": "Esto invierte la causalidad: la conciencia no crea la existencia; la identifica. Si la realidad fuera lo que crees, creencias contradictorias crearían realidades contradictorias, lo cual es imposible. El hecho de que podamos equivocarnos prueba que la realidad es independiente de la creencia.", "wrong_explanations": {"a": "Si la creencia moldeara la realidad, podríamos creer que volamos. La independencia de la realidad se prueba por la existencia del error.", "c": "La verdad no es selectiva — las leyes de la realidad se aplican a todos por igual.", "d": "No es impracticable — es imposible. Las contradicciones no pueden existir."}}, "fr": {"question": "Quelle est l''erreur philosophique dans l''affirmation \"la réalité est ce que vous croyez qu''elle est\" ?", "options": [{"id": "a", "text": "Ce n''est pas une erreur — la croyance façonne la réalité"}, {"id": "b", "text": "Cela inverse la relation entre conscience et existence"}, {"id": "c", "text": "Ce n''est vrai que pour certaines personnes"}, {"id": "d", "text": "C''est vrai mais impraticable"}], "explanation": "Cela inverse la causalité : la conscience ne crée pas l''existence ; elle l''identifie. Si la réalité était ce que l''on croit, des croyances contradictoires créeraient des réalités contradictoires, ce qui est impossible. Le fait que l''on puisse se tromper prouve que la réalité est indépendante de la croyance.", "wrong_explanations": {"a": "Si la croyance façonnait la réalité, on pourrait se croire capable de voler. L''indépendance de la réalité est prouvée par l''existence de l''erreur.", "c": "La vérité n''est pas sélective — les lois de la réalité s''appliquent à tous également.", "d": "Ce n''est pas impraticable — c''est impossible. Les contradictions ne peuvent pas exister."}}}'::jsonb WHERE question = 'What is the philosophical error in saying "reality is whatever you believe it to be"?';

-- Q17
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que significa \"a existência existe\" como axioma?", "options": [{"id": "a", "text": "Algo teve que criar a existência"}, {"id": "b", "text": "A existência é autoevidente e não requer prova"}, {"id": "c", "text": "A existência é uma ilusão"}, {"id": "d", "text": "Não podemos saber se a existência existe"}], "explanation": "O axioma \"a existência existe\" é autoevidente e inegável. Qualquer tentativa de negá-lo usa a existência para fazer a negação. Não requer prova porque todas as provas o pressupõem. Axiomas são pontos de partida do conhecimento, não conclusões derivadas de premissas anteriores.", "wrong_explanations": {"a": "Perguntar ''o que criou a existência?'' comete a falácia de pedir uma causa da própria causalidade.", "c": "Chamar a existência de ilusão pressupõe a existência para ter a ilusão.", "d": "Afirmar que não podemos saber SE a existência existe é autorrefutante — existimos para fazer a afirmação."}}, "es": {"question": "¿Qué significa \"la existencia existe\" como axioma?", "options": [{"id": "a", "text": "Algo tuvo que crear la existencia"}, {"id": "b", "text": "La existencia es autoevidente y no requiere prueba"}, {"id": "c", "text": "La existencia es una ilusión"}, {"id": "d", "text": "No podemos saber si la existencia existe"}], "explanation": "El axioma \"la existencia existe\" es autoevidente e innegable. Cualquier intento de negarlo usa la existencia para hacer la negación. No requiere prueba porque todas las pruebas lo presuponen. Los axiomas son puntos de partida del conocimiento, no conclusiones derivadas de premisas anteriores.", "wrong_explanations": {"a": "Preguntar ''¿qué creó la existencia?'' comete la falacia de pedir una causa de la causalidad misma.", "c": "Llamar a la existencia una ilusión presupone la existencia para tener la ilusión.", "d": "Afirmar que no podemos saber SI la existencia existe es autorrefutante — existimos para hacer la afirmación."}}, "fr": {"question": "Que signifie \"l''existence existe\" en tant qu''axiome ?", "options": [{"id": "a", "text": "Quelque chose a dû créer l''existence"}, {"id": "b", "text": "L''existence est évidente par elle-même et ne nécessite aucune preuve"}, {"id": "c", "text": "L''existence est une illusion"}, {"id": "d", "text": "Nous ne pouvons pas savoir si l''existence existe"}], "explanation": "L''axiome \"l''existence existe\" est évident par lui-même et indéniable. Toute tentative de le nier utilise l''existence pour faire la négation. Il ne nécessite aucune preuve car toutes les preuves le présupposent. Les axiomes sont les points de départ de la connaissance, pas des conclusions dérivées de prémisses antérieures.", "wrong_explanations": {"a": "Demander ''qu''est-ce qui a créé l''existence ?'' commet le sophisme de demander une cause de la causalité elle-même.", "c": "Qualifier l''existence d''illusion présuppose l''existence pour avoir l''illusion.", "d": "Affirmer qu''on ne peut pas savoir SI l''existence existe est auto-réfutant — on existe pour faire cette affirmation."}}}'::jsonb WHERE question = 'What does "existence exists" mean as an axiom?';

-- === SEED FILE 1: EPISTEMOLOGY ===

-- Q18
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Qual é o único meio válido de obter conhecimento segundo a filosofia racional?", "options": [{"id": "a", "text": "Fé e revelação"}, {"id": "b", "text": "Razão aplicada à evidência sensorial"}, {"id": "c", "text": "Intuição e emoção"}, {"id": "d", "text": "Autoridade e tradição"}], "explanation": "A razão — a faculdade que identifica e integra dados sensoriais em conceitos — é o único meio válido de conhecimento. A fé aceita afirmações sem evidência; a intuição é pouco fiável; a autoridade pode estar errada. Só a razão pode validar afirmações e detetar erros.", "wrong_explanations": {"a": "A fé é crença sem evidência, o que não fornece meios para distinguir afirmações verdadeiras das falsas.", "c": "Intuição e emoção não são ferramentas de cognição — são respostas ao pensamento, não substitutos dele.", "d": "Autoridades podem estar erradas. O apelo à autoridade é uma falácia lógica."}}, "es": {"question": "¿Cuál es el único medio válido de obtener conocimiento según la filosofía racional?", "options": [{"id": "a", "text": "Fe y revelación"}, {"id": "b", "text": "Razón aplicada a la evidencia sensorial"}, {"id": "c", "text": "Intuición y emoción"}, {"id": "d", "text": "Autoridad y tradición"}], "explanation": "La razón — la facultad que identifica e integra datos sensoriales en conceptos — es el único medio válido de conocimiento. La fe acepta afirmaciones sin evidencia; la intuición es poco confiable; la autoridad puede equivocarse. Solo la razón puede validar afirmaciones y detectar errores.", "wrong_explanations": {"a": "La fe es creencia sin evidencia, lo que no proporciona medios para distinguir afirmaciones verdaderas de falsas.", "c": "La intuición y la emoción no son herramientas de cognición — son respuestas al pensamiento, no sustitutos de él.", "d": "Las autoridades pueden equivocarse. La apelación a la autoridad es una falacia lógica."}}, "fr": {"question": "Quel est le seul moyen valide d''acquérir la connaissance selon la philosophie rationnelle ?", "options": [{"id": "a", "text": "La foi et la révélation"}, {"id": "b", "text": "La raison appliquée aux données sensorielles"}, {"id": "c", "text": "L''intuition et l''émotion"}, {"id": "d", "text": "L''autorité et la tradition"}], "explanation": "La raison — la faculté qui identifie et intègre les données sensorielles en concepts — est le seul moyen valide de connaissance. La foi accepte des affirmations sans preuve ; l''intuition est peu fiable ; l''autorité peut se tromper. Seule la raison peut valider les affirmations et détecter les erreurs.", "wrong_explanations": {"a": "La foi est une croyance sans preuve, ce qui ne fournit aucun moyen de distinguer les affirmations vraies des fausses.", "c": "L''intuition et l''émotion ne sont pas des outils de cognition — ce sont des réponses à la pensée, pas des substituts.", "d": "Les autorités peuvent se tromper. L''appel à l''autorité est un sophisme logique."}}}'::jsonb WHERE question = 'What is the only valid means of gaining knowledge according to rational philosophy?';

-- Q19
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é um conceito em epistemologia?", "options": [{"id": "a", "text": "Um sentimento sobre algo"}, {"id": "b", "text": "Uma integração mental de coisas semelhantes"}, {"id": "c", "text": "Uma ideia inata presente desde o nascimento"}, {"id": "d", "text": "Uma construção social sem base na realidade"}], "explanation": "Um conceito é uma integração mental de dois ou mais concretos semelhantes (coisas específicas) numa única unidade mental, abstraindo as suas características essenciais. Por exemplo, ''cadeira'' integra todas as cadeiras pela sua função essencial: algo para se sentar.", "wrong_explanations": {"a": "Sentimentos são respostas emocionais, não ferramentas cognitivas para compreender a realidade.", "c": "Conceitos não são inatos — são formados através de um processo de abstração da experiência sensorial.", "d": "Conceitos válidos são fundamentados na realidade, não em acordos sociais arbitrários."}}, "es": {"question": "¿Qué es un concepto en epistemología?", "options": [{"id": "a", "text": "Un sentimiento sobre algo"}, {"id": "b", "text": "Una integración mental de cosas similares"}, {"id": "c", "text": "Una idea innata presente desde el nacimiento"}, {"id": "d", "text": "Una construcción social sin base en la realidad"}], "explanation": "Un concepto es una integración mental de dos o más concretos similares (cosas específicas) en una sola unidad mental, abstrayendo sus características esenciales. Por ejemplo, ''silla'' integra todas las sillas por su función esencial: algo para sentarse.", "wrong_explanations": {"a": "Los sentimientos son respuestas emocionales, no herramientas cognitivas para comprender la realidad.", "c": "Los conceptos no son innatos — se forman a través de un proceso de abstracción de la experiencia sensorial.", "d": "Los conceptos válidos están fundamentados en la realidad, no en acuerdos sociales arbitrarios."}}, "fr": {"question": "Qu''est-ce qu''un concept en épistémologie ?", "options": [{"id": "a", "text": "Un sentiment à propos de quelque chose"}, {"id": "b", "text": "Une intégration mentale de choses similaires"}, {"id": "c", "text": "Une idée innée présente dès la naissance"}, {"id": "d", "text": "Une construction sociale sans fondement dans la réalité"}], "explanation": "Un concept est une intégration mentale de deux ou plusieurs concrets similaires (choses spécifiques) en une seule unité mentale, en abstrayant leurs caractéristiques essentielles. Par exemple, ''chaise'' intègre toutes les chaises par leur fonction essentielle : quelque chose pour s''asseoir.", "wrong_explanations": {"a": "Les sentiments sont des réponses émotionnelles, pas des outils cognitifs pour comprendre la réalité.", "c": "Les concepts ne sont pas innés — ils sont formés par un processus d''abstraction de l''expérience sensorielle.", "d": "Les concepts valides sont fondés sur la réalité, pas sur des accords sociaux arbitraires."}}}'::jsonb WHERE question = 'What is a concept in epistemology?';

-- Q20
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a falácia do \"apelo à autoridade\"?", "options": [{"id": "a", "text": "Aceitar uma afirmação porque uma autoridade a disse"}, {"id": "b", "text": "Questionar opiniões de especialistas"}, {"id": "c", "text": "Usar lógica para avaliar afirmações"}, {"id": "d", "text": "Confiar no próprio julgamento"}], "explanation": "O apelo à autoridade aceita uma afirmação como verdadeira simplesmente porque alguém importante ou credenciado a disse, em vez de avaliar a evidência e a lógica. Especialistas podem estar errados, tendenciosos ou desonestos. A verdade depende de evidência e lógica, não de quem diz.", "wrong_explanations": {"b": "Questionar especialistas é na verdade o antídoto para esta falácia — pense por si mesmo.", "c": "Usar lógica é o método correto, o oposto desta falácia.", "d": "Confiar no seu julgamento fundamentado é correto — confiar cegamente nos outros é que é a falácia."}}, "es": {"question": "¿Qué es la falacia de \"apelación a la autoridad\"?", "options": [{"id": "a", "text": "Aceptar una afirmación porque una autoridad la dijo"}, {"id": "b", "text": "Cuestionar opiniones de expertos"}, {"id": "c", "text": "Usar lógica para evaluar afirmaciones"}, {"id": "d", "text": "Confiar en el propio juicio"}], "explanation": "La apelación a la autoridad acepta una afirmación como verdadera simplemente porque alguien importante o con credenciales la dijo, en vez de evaluar la evidencia y la lógica. Los expertos pueden equivocarse, ser parciales o deshonestos. La verdad depende de evidencia y lógica, no de quién lo dice.", "wrong_explanations": {"b": "Cuestionar expertos es en realidad el antídoto de esta falacia — piensa por ti mismo.", "c": "Usar lógica es el método correcto, lo opuesto a esta falacia.", "d": "Confiar en tu juicio razonado es correcto — confiar ciegamente en otros es la falacia."}}, "fr": {"question": "Qu''est-ce que le sophisme de l''\"appel à l''autorité\" ?", "options": [{"id": "a", "text": "Accepter une affirmation parce qu''une autorité l''a dite"}, {"id": "b", "text": "Remettre en question les opinions des experts"}, {"id": "c", "text": "Utiliser la logique pour évaluer les affirmations"}, {"id": "d", "text": "Faire confiance à son propre jugement"}], "explanation": "L''appel à l''autorité accepte une affirmation comme vraie simplement parce qu''une personne importante ou diplômée l''a dite, au lieu d''évaluer les preuves et la logique. Les experts peuvent se tromper, être biaisés ou malhonnêtes. La vérité dépend des preuves et de la logique, pas de qui parle.", "wrong_explanations": {"b": "Questionner les experts est en fait l''antidote de ce sophisme — pensez par vous-même.", "c": "Utiliser la logique est la bonne méthode, l''opposé de ce sophisme.", "d": "Faire confiance à votre jugement raisonné est correct — c''est la confiance aveugle envers les autres qui est le sophisme."}}}'::jsonb WHERE question = 'What is the fallacy of "appeal to authority"?';

-- Q21
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Qual é a diferença entre conhecimento a priori e a posteriori?", "options": [{"id": "a", "text": "A priori é obtido pela razão; a posteriori requer experiência"}, {"id": "b", "text": "São a mesma coisa"}, {"id": "c", "text": "A priori é emocional; a posteriori é lógico"}, {"id": "d", "text": "A priori é incerto; a posteriori é certo"}], "explanation": "O conhecimento a priori é obtido apenas pela razão (como matemática: 2+2=4). O conhecimento a posteriori requer experiência sensorial (como saber que o fogo é quente). Ambos são válidos quando derivados corretamente. A distinção é metodológica, não sobre certeza.", "wrong_explanations": {"b": "Descrevem métodos diferentes de obter conhecimento — razão sozinha vs. experiência.", "c": "Nenhum é emocional — ambos são métodos cognitivos. A priori é puramente racional.", "d": "Ambos podem ser certos quando validados adequadamente. Verdades matemáticas são a priori e certas."}}, "es": {"question": "¿Cuál es la diferencia entre el conocimiento a priori y a posteriori?", "options": [{"id": "a", "text": "A priori se obtiene por la razón; a posteriori requiere experiencia"}, {"id": "b", "text": "Son lo mismo"}, {"id": "c", "text": "A priori es emocional; a posteriori es lógico"}, {"id": "d", "text": "A priori es incierto; a posteriori es cierto"}], "explanation": "El conocimiento a priori se obtiene solo por la razón (como las matemáticas: 2+2=4). El conocimiento a posteriori requiere experiencia sensorial (como saber que el fuego quema). Ambos son válidos cuando se derivan correctamente. La distinción es metodológica, no de certeza.", "wrong_explanations": {"b": "Describen métodos diferentes de obtener conocimiento — razón sola vs. experiencia.", "c": "Ninguno es emocional — ambos son métodos cognitivos. A priori es puramente racional.", "d": "Ambos pueden ser ciertos cuando se validan adecuadamente. Las verdades matemáticas son a priori y ciertas."}}, "fr": {"question": "Quelle est la différence entre la connaissance a priori et a posteriori ?", "options": [{"id": "a", "text": "A priori s''obtient par la raison ; a posteriori nécessite l''expérience"}, {"id": "b", "text": "C''est la même chose"}, {"id": "c", "text": "A priori est émotionnel ; a posteriori est logique"}, {"id": "d", "text": "A priori est incertain ; a posteriori est certain"}], "explanation": "La connaissance a priori s''obtient par la raison seule (comme les mathématiques : 2+2=4). La connaissance a posteriori nécessite l''expérience sensorielle (comme savoir que le feu brûle). Les deux sont valides quand correctement dérivées. La distinction est méthodologique, pas question de certitude.", "wrong_explanations": {"b": "Ils décrivent des méthodes différentes d''acquisition de la connaissance — raison seule vs. expérience.", "c": "Aucun n''est émotionnel — ce sont des méthodes cognitives. A priori est purement rationnel.", "d": "Les deux peuvent être certains quand correctement validés. Les vérités mathématiques sont a priori et certaines."}}}'::jsonb WHERE question = 'What is the difference between a priori and a posteriori knowledge?';

-- Q22
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que torna uma definição \"válida\" em lógica?", "options": [{"id": "a", "text": "É aceite pela maioria das pessoas"}, {"id": "b", "text": "Identifica as características essenciais que distinguem um conceito"}, {"id": "c", "text": "É aprovada por autoridades"}, {"id": "d", "text": "Soa sofisticada"}], "explanation": "Uma definição válida identifica o género (categoria mais ampla) e a diferença (características essenciais distintas) de um conceito. Por exemplo: ''O homem é um animal racional'' — género: animal; diferença: racional. Isto liga o conceito à realidade.", "wrong_explanations": {"a": "A popularidade não determina a validade. A maioria das pessoas já acreditou que a terra era plana.", "c": "A autoridade não determina a verdade. As definições devem corresponder à realidade.", "d": "A sofisticação é irrelevante. Clareza e precisão é o que importa."}}, "es": {"question": "¿Qué hace que una definición sea \"válida\" en lógica?", "options": [{"id": "a", "text": "Es aceptada por la mayoría de las personas"}, {"id": "b", "text": "Identifica las características esenciales que distinguen un concepto"}, {"id": "c", "text": "Es aprobada por autoridades"}, {"id": "d", "text": "Suena sofisticada"}], "explanation": "Una definición válida identifica el género (categoría más amplia) y la diferencia (características esenciales distintivas) de un concepto. Por ejemplo: ''El hombre es un animal racional'' — género: animal; diferencia: racional. Esto vincula el concepto a la realidad.", "wrong_explanations": {"a": "La popularidad no determina la validez. La mayoría alguna vez creyó que la tierra era plana.", "c": "La autoridad no determina la verdad. Las definiciones deben corresponder a la realidad.", "d": "La sofisticación es irrelevante. Lo que importa es la claridad y la precisión."}}, "fr": {"question": "Qu''est-ce qui rend une définition \"valide\" en logique ?", "options": [{"id": "a", "text": "Elle est acceptée par la plupart des gens"}, {"id": "b", "text": "Elle identifie les caractéristiques essentielles qui distinguent un concept"}, {"id": "c", "text": "Elle est approuvée par les autorités"}, {"id": "d", "text": "Elle semble sophistiquée"}], "explanation": "Une définition valide identifie le genre (catégorie plus large) et la différence (caractéristiques essentielles distinctives) d''un concept. Par exemple : ''L''homme est un animal rationnel'' — genre : animal ; différence : rationnel. Cela relie le concept à la réalité.", "wrong_explanations": {"a": "La popularité ne détermine pas la validité. La plupart des gens croyaient autrefois que la terre était plate.", "c": "L''autorité ne détermine pas la vérité. Les définitions doivent correspondre à la réalité.", "d": "La sophistication est sans importance. La clarté et la précision sont ce qui compte."}}}'::jsonb WHERE question = 'What makes a definition "valid" in logic?';

-- === SEED FILE 1: ETHICS ===

-- Q23
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Qual é o padrão correto de valor moral segundo a ética racional?", "options": [{"id": "a", "text": "O que a sociedade aprova"}, {"id": "b", "text": "A vida humana e a felicidade"}, {"id": "c", "text": "O autossacrifício pelos outros"}, {"id": "d", "text": "A obediência à autoridade"}], "explanation": "A vida humana — a própria vida — é o padrão de valor moral. Valores são aquilo que se age para obter e manter; a vida é o valor fundamental que torna todos os outros valores possíveis. A moralidade existe porque os humanos precisam de orientação para viver com sucesso.", "wrong_explanations": {"a": "A sociedade já aprovou escravidão, sacrifícios humanos e genocídio. A aprovação social não pode ser o padrão.", "c": "O autossacrifício como padrão é uma contradição: torna a morte (o sacrifício de valores) o objetivo da vida.", "d": "A obediência à autoridade requer um padrão para julgar se a autoridade está certa ou errada."}}, "es": {"question": "¿Cuál es el estándar correcto de valor moral según la ética racional?", "options": [{"id": "a", "text": "Lo que la sociedad aprueba"}, {"id": "b", "text": "La vida humana y la felicidad"}, {"id": "c", "text": "El autosacrificio por los demás"}, {"id": "d", "text": "La obediencia a la autoridad"}], "explanation": "La vida humana — la propia vida — es el estándar de valor moral. Los valores son aquello que se actúa para obtener y mantener; la vida es el valor fundamental que hace posibles todos los demás. La moralidad existe porque los humanos necesitan guía para vivir exitosamente.", "wrong_explanations": {"a": "La sociedad ha aprobado esclavitud, sacrificios humanos y genocidio. La aprobación social no puede ser el estándar.", "c": "El autosacrificio como estándar es una contradicción: hace de la muerte (el sacrificio de valores) el objetivo de la vida.", "d": "La obediencia a la autoridad requiere un estándar para juzgar si la autoridad está en lo correcto."}}, "fr": {"question": "Quel est le critère correct de valeur morale selon l''éthique rationnelle ?", "options": [{"id": "a", "text": "Ce que la société approuve"}, {"id": "b", "text": "La vie humaine et le bonheur"}, {"id": "c", "text": "Le sacrifice de soi pour les autres"}, {"id": "d", "text": "L''obéissance à l''autorité"}], "explanation": "La vie humaine — sa propre vie — est le critère de valeur morale. Les valeurs sont ce pour quoi on agit pour obtenir et conserver ; la vie est la valeur fondamentale qui rend toutes les autres possibles. La moralité existe parce que les humains ont besoin de guidance pour vivre avec succès.", "wrong_explanations": {"a": "La société a approuvé l''esclavage, les sacrifices humains et le génocide. L''approbation sociale ne peut être le critère.", "c": "Le sacrifice de soi comme critère est une contradiction : il fait de la mort (le sacrifice des valeurs) l''objectif de la vie.", "d": "L''obéissance à l''autorité nécessite un critère pour juger si l''autorité a raison ou tort."}}}'::jsonb WHERE question = 'What is the proper standard of moral value according to rational ethics?';

-- Q24
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Qual é a diferença entre um \"herói\" e um \"mártir\" em termos morais?", "options": [{"id": "a", "text": "Heróis têm sucesso; mártires falham"}, {"id": "b", "text": "Heróis agem pela razão e autointeresse; mártires sacrificam-se pela fé"}, {"id": "c", "text": "Não há diferença"}, {"id": "d", "text": "Mártires são mais morais que heróis"}], "explanation": "Um herói arrisca ou dá a vida pelos seus valores mais elevados — pelo que torna a sua vida digna de ser vivida. Um mártir sacrifica os seus valores pelo sacrifício em si, geralmente motivado pela fé em vez da razão. A ação do herói afirma a vida; a do mártir nega-a.", "wrong_explanations": {"a": "Sucesso vs. fracasso ignora a distinção essencial sobre motivação e valores.", "c": "A distinção é fundamental para compreender moralidade vs. autodestruição.", "d": "O martírio como ideal glorifica a morte sobre a vida — o oposto da moralidade correta."}}, "es": {"question": "¿Cuál es la diferencia entre un \"héroe\" y un \"mártir\" en términos morales?", "options": [{"id": "a", "text": "Los héroes triunfan; los mártires fracasan"}, {"id": "b", "text": "Los héroes actúan por razón y autointerés; los mártires se sacrifican por fe"}, {"id": "c", "text": "No hay diferencia"}, {"id": "d", "text": "Los mártires son más morales que los héroes"}], "explanation": "Un héroe arriesga o entrega su vida por sus valores más elevados — por lo que hace que su vida valga la pena. Un mártir sacrifica sus valores por el sacrificio en sí, generalmente motivado por la fe en vez de la razón. La acción del héroe afirma la vida; la del mártir la niega.", "wrong_explanations": {"a": "Éxito vs. fracaso ignora la distinción esencial sobre motivación y valores.", "c": "La distinción es fundamental para comprender moralidad vs. autodestrucción.", "d": "El martirio como ideal glorifica la muerte sobre la vida — lo opuesto de la moralidad correcta."}}, "fr": {"question": "Quelle est la différence entre un \"héros\" et un \"martyr\" en termes moraux ?", "options": [{"id": "a", "text": "Les héros réussissent ; les martyrs échouent"}, {"id": "b", "text": "Les héros agissent par raison et intérêt personnel ; les martyrs se sacrifient par foi"}, {"id": "c", "text": "Il n''y a pas de différence"}, {"id": "d", "text": "Les martyrs sont plus moraux que les héros"}], "explanation": "Un héros risque ou donne sa vie pour ses valeurs les plus élevées — pour ce qui rend sa vie digne d''être vécue. Un martyr sacrifie ses valeurs pour le sacrifice en soi, généralement motivé par la foi plutôt que la raison. L''action du héros affirme la vie ; celle du martyr la nie.", "wrong_explanations": {"a": "Réussite vs. échec passe à côté de la distinction essentielle sur la motivation et les valeurs.", "c": "La distinction est fondamentale pour comprendre moralité vs. autodestruction.", "d": "Le martyre comme idéal glorifie la mort au-dessus de la vie — l''opposé de la moralité correcte."}}}'::jsonb WHERE question = 'What is the difference between a "hero" and a "martyr" in moral terms?';

-- Q25
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é \"sacrifício\" em termos éticos corretos?", "options": [{"id": "a", "text": "Qualquer troca entre valores"}, {"id": "b", "text": "Abrir mão de um valor maior por um valor menor"}, {"id": "c", "text": "Ajudar os outros"}, {"id": "d", "text": "Trabalhar duro por objetivos"}], "explanation": "Sacrifício significa entregar um valor maior por um menor (ou não-valor). Trocar um valor menor por um maior não é sacrifício — é um ganho. Ajudar alguém que se valoriza não é sacrifício. Trabalhar duro pelos seus objetivos é investimento, não sacrifício.", "wrong_explanations": {"a": "Nem todas as trocas são sacrifícios. Trocar 5€ por comida que vale mais para si é um ganho.", "c": "Ajudar pessoas que se valoriza não é sacrifício — ganha-se com o bem-estar delas.", "d": "Trabalhar duro pelos SEUS objetivos é autoinvestimento, o oposto de sacrifício."}}, "es": {"question": "¿Qué es el \"sacrificio\" en términos éticos correctos?", "options": [{"id": "a", "text": "Cualquier intercambio entre valores"}, {"id": "b", "text": "Renunciar a un valor mayor por uno menor"}, {"id": "c", "text": "Ayudar a los demás"}, {"id": "d", "text": "Trabajar duro por objetivos"}], "explanation": "Sacrificio significa entregar un valor mayor por uno menor (o un no-valor). Intercambiar un valor menor por uno mayor no es sacrificio — es una ganancia. Ayudar a alguien que valoras no es sacrificio. Trabajar duro por tus objetivos es inversión, no sacrificio.", "wrong_explanations": {"a": "No todos los intercambios son sacrificios. Cambiar $5 por comida que vale más para ti es una ganancia.", "c": "Ayudar a personas que valoras no es sacrificio — ganas con su bienestar.", "d": "Trabajar duro por TUS objetivos es autoinversión, lo opuesto del sacrificio."}}, "fr": {"question": "Qu''est-ce que le \"sacrifice\" en termes éthiques corrects ?", "options": [{"id": "a", "text": "Tout échange entre valeurs"}, {"id": "b", "text": "Renoncer à une valeur supérieure pour une valeur inférieure"}, {"id": "c", "text": "Aider les autres"}, {"id": "d", "text": "Travailler dur pour ses objectifs"}], "explanation": "Le sacrifice signifie abandonner une valeur supérieure pour une inférieure (ou une non-valeur). Échanger une valeur inférieure contre une supérieure n''est pas un sacrifice — c''est un gain. Aider quelqu''un qu''on valorise n''est pas un sacrifice. Travailler dur pour ses objectifs est un investissement, pas un sacrifice.", "wrong_explanations": {"a": "Tous les échanges ne sont pas des sacrifices. Échanger 5€ contre de la nourriture qui vaut plus pour vous est un gain.", "c": "Aider des personnes qu''on valorise n''est pas un sacrifice — on gagne à leur bien-être.", "d": "Travailler dur pour VOS objectifs est un auto-investissement, l''opposé du sacrifice."}}}'::jsonb WHERE question = 'What is "sacrifice" in proper ethical terms?';

-- Q26
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é o \"princípio do comerciante\" em ética?", "options": [{"id": "a", "text": "Sempre procurar lucro à custa dos outros"}, {"id": "b", "text": "Trocar valor por valor com benefício mútuo"}, {"id": "c", "text": "Dar sem esperar nada em troca"}, {"id": "d", "text": "Pegar tudo o que puder"}], "explanation": "O princípio do comerciante sustenta que pessoas morais lidam com os outros por troca voluntária de benefício mútuo. Ambas as partes ganham valor. Isto aplica-se a todas as relações: comércio, amizade, amor. Rejeita tanto a exploração (tomar sem dar) quanto o autossacrifício (dar sem receber).", "wrong_explanations": {"a": "Lucro à custa dos outros é parasitismo, não comércio. O lucro verdadeiro cria valor para ambas as partes.", "c": "Dar sem receber é autossacrifício, que trata a si mesmo como sem valor.", "d": "Pegar tudo o que pode é roubo ou parasitismo — o oposto do comércio honesto."}}, "es": {"question": "¿Qué es el \"principio del comerciante\" en ética?", "options": [{"id": "a", "text": "Siempre buscar ganancias a costa de otros"}, {"id": "b", "text": "Intercambiar valor por valor con beneficio mutuo"}, {"id": "c", "text": "Dar sin esperar nada a cambio"}, {"id": "d", "text": "Tomar lo que puedas"}], "explanation": "El principio del comerciante sostiene que las personas morales tratan con los demás mediante intercambio voluntario de beneficio mutuo. Ambas partes ganan valor. Esto se aplica a todas las relaciones: comercio, amistad, amor. Rechaza tanto la explotación (tomar sin dar) como el autosacrificio (dar sin recibir).", "wrong_explanations": {"a": "Ganancias a costa de otros es parasitismo, no comercio. La ganancia verdadera crea valor para ambas partes.", "c": "Dar sin recibir es autosacrificio, que te trata como si no valieras nada.", "d": "Tomar lo que puedas es robo o parasitismo — lo opuesto del comercio honesto."}}, "fr": {"question": "Qu''est-ce que le \"principe du commerçant\" en éthique ?", "options": [{"id": "a", "text": "Toujours chercher le profit aux dépens des autres"}, {"id": "b", "text": "Échanger valeur contre valeur avec bénéfice mutuel"}, {"id": "c", "text": "Donner sans rien attendre en retour"}, {"id": "d", "text": "Prendre tout ce qu''on peut"}], "explanation": "Le principe du commerçant soutient que les personnes morales traitent avec les autres par échange volontaire à bénéfice mutuel. Les deux parties gagnent de la valeur. Cela s''applique à toutes les relations : commerce, amitié, amour. Il rejette tant l''exploitation (prendre sans donner) que le sacrifice de soi (donner sans recevoir).", "wrong_explanations": {"a": "Le profit aux dépens des autres est du parasitisme, pas du commerce. Le vrai profit crée de la valeur pour les deux parties.", "c": "Donner sans recevoir est du sacrifice de soi, qui vous traite comme sans valeur.", "d": "Prendre tout ce qu''on peut est du vol ou du parasitisme — l''opposé du commerce honnête."}}}'::jsonb WHERE question = 'What is the "trader principle" in ethics?';

-- Q27
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que a honestidade é uma virtude egoísta (no sentido correto)?", "options": [{"id": "a", "text": "Porque mentir ajuda a progredir"}, {"id": "b", "text": "Porque a realidade não pode ser falsificada, e a sua vida depende de lidar com a realidade"}, {"id": "c", "text": "Porque a honestidade faz os outros gostarem de si"}, {"id": "d", "text": "Porque Deus ordena honestidade"}], "explanation": "A honestidade é egoísta porque a sua vida depende de compreender e lidar com a realidade tal como ela é. Falsificar a realidade na própria mente torna-o incapaz de navegar a existência. O mentiroso deve lembrar-se das suas mentiras enquanto a realidade permanece inalterada — uma estratégia condenada.", "wrong_explanations": {"a": "Mentir cria uma falsa realidade na mente enquanto a realidade real continua inalterada — isto é autodestrutivo.", "c": "Embora a honestidade ganhe confiança, o seu valor primário é epistémico: manter a mente clara.", "d": "A ética do comando divino não pode explicar POR QUE a honestidade é boa — apenas que alguém a ordena."}}, "es": {"question": "¿Por qué la honestidad es una virtud egoísta (en el sentido correcto)?", "options": [{"id": "a", "text": "Porque mentir ayuda a progresar"}, {"id": "b", "text": "Porque la realidad no puede falsificarse, y tu vida depende de lidiar con la realidad"}, {"id": "c", "text": "Porque la honestidad hace que otros te quieran"}, {"id": "d", "text": "Porque Dios ordena honestidad"}], "explanation": "La honestidad es egoísta porque tu vida depende de comprender y lidiar con la realidad tal como es. Falsificar la realidad en tu propia mente te hace incapaz de navegar la existencia. El mentiroso debe recordar sus mentiras mientras la realidad permanece inalterada — una estrategia condenada.", "wrong_explanations": {"a": "Mentir crea una falsa realidad en tu mente mientras la realidad real sigue inalterada — esto es autodestructivo.", "c": "Aunque la honestidad gana confianza, su valor primario es epistémico: mantener la mente clara.", "d": "La ética del mandato divino no puede explicar POR QUÉ la honestidad es buena — solo que alguien la ordena."}}, "fr": {"question": "Pourquoi l''honnêteté est-elle une vertu égoïste (au sens correct) ?", "options": [{"id": "a", "text": "Parce que mentir aide à avancer"}, {"id": "b", "text": "Parce que la réalité ne peut être falsifiée, et votre vie dépend de votre rapport à la réalité"}, {"id": "c", "text": "Parce que l''honnêteté fait que les autres vous apprécient"}, {"id": "d", "text": "Parce que Dieu ordonne l''honnêteté"}], "explanation": "L''honnêteté est égoïste parce que votre vie dépend de la compréhension et du rapport à la réalité telle qu''elle est. Falsifier la réalité dans votre esprit vous rend incapable de naviguer l''existence. Le menteur doit se souvenir de ses mensonges tandis que la réalité reste inchangée — une stratégie vouée à l''échec.", "wrong_explanations": {"a": "Mentir crée une fausse réalité dans votre esprit tandis que la vraie réalité continue inchangée — c''est autodestructeur.", "c": "Bien que l''honnêteté gagne la confiance, sa valeur première est épistémique : garder l''esprit clair.", "d": "L''éthique du commandement divin ne peut expliquer POURQUOI l''honnêteté est bonne — seulement que quelqu''un l''ordonne."}}}'::jsonb WHERE question = 'Why is honesty a selfish virtue (in the proper sense)?';

-- === SEED FILE 1: VIRTUES ===

-- Q28
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quais são as sete virtudes objetivas segundo a ética Objetivista?", "options": [{"id": "a", "text": "Fé, Esperança, Caridade, Prudência, Justiça, Fortaleza, Temperança"}, {"id": "b", "text": "Racionalidade, Independência, Integridade, Honestidade, Justiça, Produtividade, Orgulho"}, {"id": "c", "text": "Coragem, Sabedoria, Temperança, Justiça"}, {"id": "d", "text": "Humildade, Obediência, Castidade, Pobreza"}], "explanation": "As sete virtudes Objetivistas são: Racionalidade (pensar), Independência (autossuficiência no pensamento e ação), Integridade (lealdade a princípios racionais), Honestidade (nunca falsificar a realidade), Justiça (julgar pessoas objetivamente), Produtividade (criar valores) e Orgulho (ambição moral).", "wrong_explanations": {"a": "Estas são virtudes teológicas cristãs, misturando elementos baseados na fé e racionais.", "c": "Estas são as quatro virtudes cardeais de Platão — importantes mas incompletas.", "d": "Estas são ''virtudes'' monásticas que na verdade negam a vida e a felicidade humanas."}}, "es": {"question": "¿Cuáles son las siete virtudes objetivas según la ética Objetivista?", "options": [{"id": "a", "text": "Fe, Esperanza, Caridad, Prudencia, Justicia, Fortaleza, Templanza"}, {"id": "b", "text": "Racionalidad, Independencia, Integridad, Honestidad, Justicia, Productividad, Orgullo"}, {"id": "c", "text": "Coraje, Sabiduría, Templanza, Justicia"}, {"id": "d", "text": "Humildad, Obediencia, Castidad, Pobreza"}], "explanation": "Las siete virtudes Objetivistas son: Racionalidad (pensar), Independencia (autosuficiencia en pensamiento y acción), Integridad (lealtad a principios racionales), Honestidad (nunca falsificar la realidad), Justicia (juzgar personas objetivamente), Productividad (crear valores) y Orgullo (ambición moral).", "wrong_explanations": {"a": "Estas son virtudes teológicas cristianas, mezclando elementos basados en la fe y racionales.", "c": "Estas son las cuatro virtudes cardinales de Platón — importantes pero incompletas.", "d": "Estas son ''virtudes'' monásticas que en realidad niegan la vida y felicidad humanas."}}, "fr": {"question": "Quelles sont les sept vertus objectives selon l''éthique Objectiviste ?", "options": [{"id": "a", "text": "Foi, Espérance, Charité, Prudence, Justice, Force, Tempérance"}, {"id": "b", "text": "Rationalité, Indépendance, Intégrité, Honnêteté, Justice, Productivité, Fierté"}, {"id": "c", "text": "Courage, Sagesse, Tempérance, Justice"}, {"id": "d", "text": "Humilité, Obéissance, Chasteté, Pauvreté"}], "explanation": "Les sept vertus Objectivistes sont : Rationalité (penser), Indépendance (autonomie dans la pensée et l''action), Intégrité (fidélité aux principes rationnels), Honnêteté (ne jamais falsifier la réalité), Justice (juger les gens objectivement), Productivité (créer des valeurs) et Fierté (ambition morale).", "wrong_explanations": {"a": "Ce sont des vertus théologiques chrétiennes, mêlant éléments de foi et rationnels.", "c": "Ce sont les quatre vertus cardinales de Platon — importantes mais incomplètes.", "d": "Ce sont des ''vertus'' monastiques qui nient en réalité la vie et le bonheur humains."}}}'::jsonb WHERE question = 'What are the seven objective virtues according to Objectivist ethics?';

-- Q29
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a virtude da \"Independência\" em ética?", "options": [{"id": "a", "text": "Nunca cooperar com os outros"}, {"id": "b", "text": "Confiar no próprio julgamento e esforço como primários"}, {"id": "c", "text": "Rejeitar toda ajuda dos outros"}, {"id": "d", "text": "Estar fisicamente isolado"}], "explanation": "Independência significa aceitar a responsabilidade pelo próprio pensamento e por formar os seus próprios julgamentos. Não significa isolamento — pode-se aprender com os outros e cooperar. Mas a SUA mente deve ser o juiz final da verdade, e o SEU esforço deve ser a fonte primária dos seus valores.", "wrong_explanations": {"a": "Cooperação baseada em benefício mútuo é racional — independência refere-se ao julgamento, não ao isolamento.", "c": "Aceitar ajuda voluntariamente oferecida é aceitável; dependência é confiar nos outros como seu meio PRIMÁRIO.", "d": "O isolamento físico não é a questão — independência mental num contexto social é."}}, "es": {"question": "¿Qué es la virtud de la \"Independencia\" en ética?", "options": [{"id": "a", "text": "Nunca cooperar con otros"}, {"id": "b", "text": "Confiar en el propio juicio y esfuerzo como primarios"}, {"id": "c", "text": "Rechazar toda ayuda de otros"}, {"id": "d", "text": "Estar físicamente aislado"}], "explanation": "Independencia significa aceptar la responsabilidad por tu propio pensamiento y por formar tus propios juicios. No significa aislamiento — puedes aprender de otros y cooperar. Pero TU mente debe ser el juez final de la verdad, y TU esfuerzo debe ser la fuente primaria de tus valores.", "wrong_explanations": {"a": "La cooperación basada en beneficio mutuo es racional — independencia se refiere al juicio, no al aislamiento.", "c": "Aceptar ayuda voluntariamente ofrecida está bien; dependencia es confiar en otros como tu medio PRIMARIO.", "d": "El aislamiento físico no es el punto — independencia mental en un contexto social sí lo es."}}, "fr": {"question": "Qu''est-ce que la vertu de l''\"Indépendance\" en éthique ?", "options": [{"id": "a", "text": "Ne jamais coopérer avec les autres"}, {"id": "b", "text": "S''appuyer sur son propre jugement et effort comme prioritaires"}, {"id": "c", "text": "Rejeter toute aide des autres"}, {"id": "d", "text": "Être physiquement isolé"}], "explanation": "L''indépendance signifie accepter la responsabilité de sa propre pensée et de former ses propres jugements. Cela ne signifie pas l''isolement — on peut apprendre des autres et coopérer. Mais VOTRE esprit doit être le juge final de la vérité, et VOTRE effort doit être la source première de vos valeurs.", "wrong_explanations": {"a": "La coopération fondée sur le bénéfice mutuel est rationnelle — l''indépendance concerne le jugement, pas l''isolement.", "c": "Accepter l''aide volontairement offerte est acceptable ; la dépendance est compter sur les autres comme moyen PREMIER.", "d": "L''isolement physique n''est pas le sujet — l''indépendance mentale dans un contexte social l''est."}}}'::jsonb WHERE question = 'What is the virtue of "Independence" in ethics?';

-- Q30
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a virtude da \"Integridade\"?", "options": [{"id": "a", "text": "Seguir regras sem questionar"}, {"id": "b", "text": "Lealdade às suas convicções racionais em ação"}, {"id": "c", "text": "Concordar com a maioria"}, {"id": "d", "text": "Guardar segredos"}], "explanation": "Integridade é a recusa de permitir uma brecha entre o que se sabe e o que se faz. Significa praticar o que se prega, viver pelos princípios racionais mesmo quando é difícil. Uma pessoa com integridade não trai os seus valores por ganhos a curto prazo.", "wrong_explanations": {"a": "Seguir regras sem questionar é obediência, não integridade — deve-se compreender POR QUE as regras estão certas.", "c": "Concordar com a maioria é conformismo. A integridade frequentemente requer estar contra a multidão.", "d": "Guardar segredos pode ou não ser relevante para a integridade — depende do contexto."}}, "es": {"question": "¿Qué es la virtud de la \"Integridad\"?", "options": [{"id": "a", "text": "Seguir reglas sin cuestionar"}, {"id": "b", "text": "Lealtad a tus convicciones racionales en acción"}, {"id": "c", "text": "Estar de acuerdo con la mayoría"}, {"id": "d", "text": "Guardar secretos"}], "explanation": "La integridad es la negativa a permitir una brecha entre lo que sabes y lo que haces. Significa practicar lo que predicas, vivir según tus principios racionales incluso cuando es difícil. Una persona con integridad no traiciona sus valores por ganancias a corto plazo.", "wrong_explanations": {"a": "Seguir reglas sin cuestionar es obediencia, no integridad — debes entender POR QUÉ las reglas son correctas.", "c": "Estar de acuerdo con la mayoría es conformismo. La integridad frecuentemente requiere ir contra la corriente.", "d": "Guardar secretos puede o no ser relevante para la integridad — depende del contexto."}}, "fr": {"question": "Qu''est-ce que la vertu de l''\"Intégrité\" ?", "options": [{"id": "a", "text": "Suivre les règles sans questionner"}, {"id": "b", "text": "Fidélité à vos convictions rationnelles dans l''action"}, {"id": "c", "text": "Être d''accord avec la majorité"}, {"id": "d", "text": "Garder des secrets"}], "explanation": "L''intégrité est le refus de permettre un écart entre ce que l''on sait et ce que l''on fait. Cela signifie pratiquer ce que l''on prêche, vivre selon ses principes rationnels même quand c''est difficile. Une personne intègre ne trahit pas ses valeurs pour des gains à court terme.", "wrong_explanations": {"a": "Suivre les règles sans questionner est de l''obéissance, pas de l''intégrité — il faut comprendre POURQUOI les règles sont justes.", "c": "Être d''accord avec la majorité est du conformisme. L''intégrité exige souvent de s''opposer à la foule.", "d": "Garder des secrets peut ou non être pertinent pour l''intégrité — cela dépend du contexte."}}}'::jsonb WHERE question = 'What is the virtue of "Integrity"?';

-- Q31
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a virtude do \"Orgulho\" no seu sentido moral correto?", "options": [{"id": "a", "text": "Arrogância e ostentação"}, {"id": "b", "text": "Ambição moral — compromisso com alcançar o seu potencial máximo"}, {"id": "c", "text": "Pensar que é melhor que os outros"}, {"id": "d", "text": "Recusar-se a admitir erros"}], "explanation": "Orgulho é ambição moral: o compromisso de alcançar o seu potencial máximo em caráter e na vida. É autoestima merecida baseada em conquistas reais e ação virtuosa. O orgulho motiva-o a ser digno do seu próprio respeito.", "wrong_explanations": {"a": "Arrogância é autoimportância não merecida. O orgulho correto é conquistado através de realizações.", "c": "O orgulho é sobre os SEUS padrões para si mesmo, não comparação com os outros.", "d": "Recusar-se a admitir erros é negação, não orgulho. O orgulho real requer honestidade sobre erros para corrigi-los."}}, "es": {"question": "¿Qué es la virtud del \"Orgullo\" en su sentido moral correcto?", "options": [{"id": "a", "text": "Arrogancia y presunción"}, {"id": "b", "text": "Ambición moral — compromiso con alcanzar tu máximo potencial"}, {"id": "c", "text": "Pensar que eres mejor que los demás"}, {"id": "d", "text": "Negarse a admitir errores"}], "explanation": "El orgullo es ambición moral: el compromiso de alcanzar tu máximo potencial en carácter y en la vida. Es autoestima merecida basada en logros reales y acción virtuosa. El orgullo te motiva a ser digno de tu propio respeto.", "wrong_explanations": {"a": "La arrogancia es autoimportancia no merecida. El orgullo correcto se gana a través de logros.", "c": "El orgullo es sobre TUS estándares para ti mismo, no comparación con otros.", "d": "Negarse a admitir errores es negación, no orgullo. El orgullo real requiere honestidad sobre los errores para corregirlos."}}, "fr": {"question": "Qu''est-ce que la vertu de la \"Fierté\" dans son sens moral correct ?", "options": [{"id": "a", "text": "Arrogance et vantardise"}, {"id": "b", "text": "Ambition morale — engagement à atteindre son plus haut potentiel"}, {"id": "c", "text": "Penser qu''on est meilleur que les autres"}, {"id": "d", "text": "Refuser d''admettre ses erreurs"}], "explanation": "La fierté est l''ambition morale : l''engagement à atteindre son plus haut potentiel en caractère et dans la vie. C''est l''estime de soi méritée, fondée sur des réalisations réelles et une action vertueuse. La fierté vous motive à être digne de votre propre respect.", "wrong_explanations": {"a": "L''arrogance est une auto-importance non méritée. La vraie fierté se gagne par les réalisations.", "c": "La fierté concerne VOS standards pour vous-même, pas la comparaison avec les autres.", "d": "Refuser d''admettre ses erreurs est du déni, pas de la fierté. La vraie fierté exige l''honnêteté sur les erreurs pour les corriger."}}}'::jsonb WHERE question = 'What is the virtue of "Pride" in its proper moral sense?';

-- Q32
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que a \"Produtividade\" é uma virtude moral, não apenas uma atividade económica?", "options": [{"id": "a", "text": "Porque ganhar dinheiro é o objetivo mais elevado"}, {"id": "b", "text": "Porque criar valores sustenta a sua vida e dá-lhe significado"}, {"id": "c", "text": "Porque a sociedade precisa de trabalhadores"}, {"id": "d", "text": "Porque a ociosidade é pecado"}], "explanation": "A produtividade é o ato de criar os valores que a sua vida requer. Sustenta a existência física e dá à vida propósito e significado. O trabalho produtivo é o propósito central em torno do qual se organiza a vida — é como os humanos sobrevivem e prosperam.", "wrong_explanations": {"a": "O dinheiro é uma ferramenta, não o objetivo. O objetivo é criar valores reais — produtos, serviços, arte.", "c": "As necessidades da sociedade não determinam a SUA virtude. Produz-se para a SUA vida e valores.", "d": "''Pecado'' é um conceito religioso. A produtividade é boa porque serve a SUA vida."}}, "es": {"question": "¿Por qué la \"Productividad\" es una virtud moral, no solo una actividad económica?", "options": [{"id": "a", "text": "Porque ganar dinero es el objetivo más elevado"}, {"id": "b", "text": "Porque crear valores sustenta tu vida y le da significado"}, {"id": "c", "text": "Porque la sociedad necesita trabajadores"}, {"id": "d", "text": "Porque la ociosidad es pecado"}], "explanation": "La productividad es el acto de crear los valores que tu vida requiere. Sustenta la existencia física y da propósito y significado a la vida. El trabajo productivo es el propósito central alrededor del cual se organiza la vida — es como los humanos sobreviven y prosperan.", "wrong_explanations": {"a": "El dinero es una herramienta, no el objetivo. El objetivo es crear valores reales — productos, servicios, arte.", "c": "Las necesidades de la sociedad no determinan TU virtud. Produces para TU vida y valores.", "d": "''Pecado'' es un concepto religioso. La productividad es buena porque sirve a TU vida."}}, "fr": {"question": "Pourquoi la \"Productivité\" est-elle une vertu morale, et pas seulement une activité économique ?", "options": [{"id": "a", "text": "Parce que gagner de l''argent est l''objectif le plus élevé"}, {"id": "b", "text": "Parce que créer des valeurs soutient votre vie et lui donne un sens"}, {"id": "c", "text": "Parce que la société a besoin de travailleurs"}, {"id": "d", "text": "Parce que l''oisiveté est un péché"}], "explanation": "La productivité est l''acte de créer les valeurs que votre vie requiert. Elle soutient l''existence physique et donne un but et un sens à la vie. Le travail productif est le but central autour duquel on organise sa vie — c''est ainsi que les humains survivent et prospèrent.", "wrong_explanations": {"a": "L''argent est un outil, pas l''objectif. L''objectif est de créer des valeurs réelles — produits, services, art.", "c": "Les besoins de la société ne déterminent pas VOTRE vertu. On produit pour SA vie et ses valeurs.", "d": "Le ''péché'' est un concept religieux. La productivité est bonne parce qu''elle sert VOTRE vie."}}}'::jsonb WHERE question = 'Why is "Productiveness" a moral virtue, not just an economic activity?';

-- === SEED FILE 1: POLITICS ===

-- Q33
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Qual é a única função legítima do governo?", "options": [{"id": "a", "text": "Redistribuir riqueza"}, {"id": "b", "text": "Proteger os direitos individuais"}, {"id": "c", "text": "Promover o bem comum"}, {"id": "d", "text": "Orientar a economia"}], "explanation": "O governo existe unicamente para proteger os direitos individuais contra violação por força ou fraude. Isto significa polícia (proteger dos criminosos), militar (proteger de ameaças externas) e tribunais (resolver disputas). Qualquer outra função excede a autoridade legítima do governo.", "wrong_explanations": {"a": "A redistribuição viola os direitos de propriedade — tomar de uns para dar a outros pela força.", "c": "O ''bem comum'' não tem definição que não sacrifique indivíduos ao coletivo.", "d": "A orientação económica governamental é planeamento central, que viola direitos de propriedade e fracassa economicamente."}}, "es": {"question": "¿Cuál es la única función legítima del gobierno?", "options": [{"id": "a", "text": "Redistribuir la riqueza"}, {"id": "b", "text": "Proteger los derechos individuales"}, {"id": "c", "text": "Promover el bien común"}, {"id": "d", "text": "Guiar la economía"}], "explanation": "El gobierno existe únicamente para proteger los derechos individuales contra la violación por fuerza o fraude. Esto significa policía (proteger de criminales), ejército (proteger de amenazas externas) y tribunales (resolver disputas). Cualquier otra función excede la autoridad legítima del gobierno.", "wrong_explanations": {"a": "La redistribución viola los derechos de propiedad — tomar de unos para dar a otros por la fuerza.", "c": "El ''bien común'' no tiene definición que no sacrifique individuos al colectivo.", "d": "La guía económica gubernamental es planificación central, que viola derechos de propiedad y fracasa económicamente."}}, "fr": {"question": "Quelle est la seule fonction légitime du gouvernement ?", "options": [{"id": "a", "text": "Redistribuer la richesse"}, {"id": "b", "text": "Protéger les droits individuels"}, {"id": "c", "text": "Promouvoir le bien commun"}, {"id": "d", "text": "Guider l''économie"}], "explanation": "Le gouvernement existe uniquement pour protéger les droits individuels contre la violation par la force ou la fraude. Cela signifie la police (protéger des criminels), l''armée (protéger des menaces extérieures) et les tribunaux (résoudre les litiges). Toute autre fonction dépasse l''autorité légitime du gouvernement.", "wrong_explanations": {"a": "La redistribution viole les droits de propriété — prendre aux uns pour donner aux autres par la force.", "c": "Le ''bien commun'' n''a pas de définition qui ne sacrifie pas les individus au collectif.", "d": "La direction économique par le gouvernement est de la planification centrale, qui viole les droits de propriété et échoue économiquement."}}}'::jsonb WHERE question = 'What is the only proper function of government?';

-- Q34
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é um \"direito individual\"?", "options": [{"id": "a", "text": "Uma permissão concedida pelo governo"}, {"id": "b", "text": "Um princípio moral que define a liberdade de ação num contexto social"}, {"id": "c", "text": "Uma garantia de bens materiais"}, {"id": "d", "text": "O que a maioria decide"}], "explanation": "Direitos são princípios morais que sancionam a liberdade individual de ação num contexto social. Não são concedidos pelo governo — são inerentes à natureza humana (os requisitos da sobrevivência humana). A função do governo é reconhecer e proteger direitos preexistentes.", "wrong_explanations": {"a": "Se o governo concede direitos, pode revogá-los — tornando ''direitos'' meras permissões. Os verdadeiros direitos precedem o governo.", "c": "Direitos são à liberdade de AÇÃO, não a resultados garantidos. Ninguém lhe deve bens.", "d": "Direitos protegem indivíduos DA maioria. A democracia não pode votar para eliminar os seus direitos."}}, "es": {"question": "¿Qué es un \"derecho individual\"?", "options": [{"id": "a", "text": "Un permiso otorgado por el gobierno"}, {"id": "b", "text": "Un principio moral que define la libertad de acción en un contexto social"}, {"id": "c", "text": "Una garantía de bienes materiales"}, {"id": "d", "text": "Lo que la mayoría decide"}], "explanation": "Los derechos son principios morales que sancionan la libertad individual de acción en un contexto social. No son otorgados por el gobierno — son inherentes a la naturaleza humana (los requisitos de la supervivencia humana). La función del gobierno es reconocer y proteger derechos preexistentes.", "wrong_explanations": {"a": "Si el gobierno otorga derechos, puede revocarlos — haciendo que los ''derechos'' sean meros permisos. Los verdaderos derechos preceden al gobierno.", "c": "Los derechos son a la libertad de ACCIÓN, no a resultados garantizados. Nadie te debe bienes.", "d": "Los derechos protegen a los individuos DE la mayoría. La democracia no puede votar para eliminar tus derechos."}}, "fr": {"question": "Qu''est-ce qu''un \"droit individuel\" ?", "options": [{"id": "a", "text": "Une permission accordée par le gouvernement"}, {"id": "b", "text": "Un principe moral définissant la liberté d''action dans un contexte social"}, {"id": "c", "text": "Une garantie de biens matériels"}, {"id": "d", "text": "Ce que la majorité décide"}], "explanation": "Les droits sont des principes moraux sanctionnant la liberté individuelle d''action dans un contexte social. Ils ne sont pas accordés par le gouvernement — ils sont inhérents à la nature humaine (les exigences de la survie humaine). Le rôle du gouvernement est de reconnaître et protéger des droits préexistants.", "wrong_explanations": {"a": "Si le gouvernement accorde les droits, il peut les révoquer — ce qui fait des ''droits'' de simples permissions. Les vrais droits précèdent le gouvernement.", "c": "Les droits portent sur la liberté d''ACTION, pas sur des résultats garantis. Personne ne vous doit des biens.", "d": "Les droits protègent les individus DE la majorité. La démocratie ne peut pas voter pour supprimer vos droits."}}}'::jsonb WHERE question = 'What is an "individual right"?';

-- Q35
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é o princípio da \"não-iniciação de força\"?", "options": [{"id": "a", "text": "Nunca usar força em circunstância alguma"}, {"id": "b", "text": "Nunca iniciar a força; usá-la apenas em retaliação contra quem a inicia"}, {"id": "c", "text": "Deixar o governo lidar com toda a força"}, {"id": "d", "text": "A força é sempre justificada se precisar de algo"}], "explanation": "O princípio sustenta que iniciar força física contra outros é maligno. Contudo, a força retaliatória contra quem inicia a força é moralmente correta — é autodefesa. A distinção é crucial: iniciar a força viola direitos; retaliar protege-os.", "wrong_explanations": {"a": "O pacifismo é autodestrutivo. A autodefesa contra agressores é moral e necessária.", "c": "O governo deve ter o monopólio da força retaliatória, mas o princípio aplica-se a todos.", "d": "Necessidade não justifica força. Precisar de algo não dá o direito de tomá-lo pela força."}}, "es": {"question": "¿Qué es el principio de \"no-iniciación de la fuerza\"?", "options": [{"id": "a", "text": "Nunca usar la fuerza bajo ninguna circunstancia"}, {"id": "b", "text": "Nunca iniciar la fuerza; usarla solo en represalia contra quien la inicia"}, {"id": "c", "text": "Dejar que el gobierno maneje toda la fuerza"}, {"id": "d", "text": "La fuerza siempre se justifica si necesitas algo"}], "explanation": "El principio sostiene que iniciar fuerza física contra otros es maligno. Sin embargo, la fuerza de represalia contra quienes inician la fuerza es moralmente correcta — es autodefensa. La distinción es crucial: iniciar fuerza viola derechos; la represalia los protege.", "wrong_explanations": {"a": "El pacifismo es autodestructivo. La autodefensa contra agresores es moral y necesaria.", "c": "El gobierno debe tener el monopolio de la fuerza de represalia, pero el principio se aplica a todos.", "d": "La necesidad no justifica la fuerza. Necesitar algo no da derecho a tomarlo por la fuerza."}}, "fr": {"question": "Qu''est-ce que le principe de \"non-initiation de la force\" ?", "options": [{"id": "a", "text": "Ne jamais utiliser la force en aucune circonstance"}, {"id": "b", "text": "Ne jamais initier la force ; l''utiliser uniquement en représailles contre ceux qui l''initient"}, {"id": "c", "text": "Laisser le gouvernement gérer toute la force"}, {"id": "d", "text": "La force est toujours justifiée si on a besoin de quelque chose"}], "explanation": "Le principe soutient que l''initiation de la force physique contre autrui est mauvaise. Cependant, la force de représailles contre ceux qui initient la force est moralement juste — c''est de la légitime défense. La distinction est cruciale : initier la force viole les droits ; la représailles les protège.", "wrong_explanations": {"a": "Le pacifisme est autodestructeur. La légitime défense contre les agresseurs est morale et nécessaire.", "c": "Le gouvernement devrait avoir le monopole de la force de représailles, mais le principe s''applique à tous.", "d": "Le besoin ne justifie pas la force. Avoir besoin de quelque chose ne donne pas le droit de le prendre par la force."}}}'::jsonb WHERE question = 'What is the "non-initiation of force" principle?';

-- Q36
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que o capitalismo é o único sistema económico moral?", "options": [{"id": "a", "text": "Porque torna os ricos mais ricos"}, {"id": "b", "text": "Porque baseia-se em comércio voluntário e direitos individuais"}, {"id": "c", "text": "Porque o governo controla a economia sabiamente"}, {"id": "d", "text": "Porque prioriza o bem coletivo"}], "explanation": "O capitalismo é o único sistema onde todas as relações humanas são voluntárias, baseadas em comércio de benefício mútuo. Proíbe a iniciação da força, protegendo os direitos individuais incluindo direitos de propriedade. Qualquer outro sistema envolve forçar algumas pessoas a servir outras.", "wrong_explanations": {"a": "O capitalismo beneficia todos através da produção e comércio — não é um jogo de soma zero.", "c": "O controlo governamental é o oposto do capitalismo — isso é socialismo ou fascismo.", "d": "O capitalismo prioriza o INDIVÍDUO. O ''bem coletivo'' é uma justificação para o sacrifício."}}, "es": {"question": "¿Por qué el capitalismo es el único sistema económico moral?", "options": [{"id": "a", "text": "Porque hace a los ricos más ricos"}, {"id": "b", "text": "Porque se basa en comercio voluntario y derechos individuales"}, {"id": "c", "text": "Porque el gobierno controla la economía sabiamente"}, {"id": "d", "text": "Porque prioriza el bien colectivo"}], "explanation": "El capitalismo es el único sistema donde todas las relaciones humanas son voluntarias, basadas en comercio de beneficio mutuo. Prohíbe la iniciación de la fuerza, protegiendo los derechos individuales incluyendo los de propiedad. Cualquier otro sistema implica forzar a algunas personas a servir a otras.", "wrong_explanations": {"a": "El capitalismo beneficia a todos a través de la producción y el comercio — no es un juego de suma cero.", "c": "El control gubernamental es lo opuesto del capitalismo — eso es socialismo o fascismo.", "d": "El capitalismo prioriza al INDIVIDUO. El ''bien colectivo'' es una justificación para el sacrificio."}}, "fr": {"question": "Pourquoi le capitalisme est-il le seul système économique moral ?", "options": [{"id": "a", "text": "Parce qu''il rend les riches plus riches"}, {"id": "b", "text": "Parce qu''il repose sur le commerce volontaire et les droits individuels"}, {"id": "c", "text": "Parce que le gouvernement contrôle l''économie sagement"}, {"id": "d", "text": "Parce qu''il priorise le bien collectif"}], "explanation": "Le capitalisme est le seul système où toutes les relations humaines sont volontaires, fondées sur le commerce à bénéfice mutuel. Il interdit l''initiation de la force, protégeant les droits individuels y compris les droits de propriété. Tout autre système implique de forcer certaines personnes à en servir d''autres.", "wrong_explanations": {"a": "Le capitalisme profite à tous par la production et le commerce — ce n''est pas un jeu à somme nulle.", "c": "Le contrôle gouvernemental est l''opposé du capitalisme — c''est du socialisme ou du fascisme.", "d": "Le capitalisme priorise l''INDIVIDU. Le ''bien collectif'' est une justification du sacrifice."}}}'::jsonb WHERE question = 'Why is capitalism the only moral economic system?';

-- Q37
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Qual é a diferença entre \"direitos positivos\" e \"direitos negativos\"?", "options": [{"id": "a", "text": "Direitos positivos são bons; direitos negativos são maus"}, {"id": "b", "text": "Direitos positivos exigem que outros forneçam; direitos negativos exigem que outros se abstenham"}, {"id": "c", "text": "São a mesma coisa"}, {"id": "d", "text": "Direitos positivos são constitucionais; direitos negativos não são"}], "explanation": "Direitos negativos (os únicos verdadeiros) exigem que outros se ABSTENHAM de agir contra si — como o direito à vida (não me matem). ''Direitos positivos'' reivindicam direito a bens que outros devem fornecer (educação, saúde), o que viola os direitos dos fornecedores.", "wrong_explanations": {"a": "Direitos negativos são os únicos genuínos. ''Direitos positivos'' são na verdade reivindicações sobre o trabalho alheio.", "c": "São opostos: um exige ação DOS outros; outro exige não-interferência.", "d": "A Constituição originalmente protegia direitos negativos; ''direitos'' positivos foram adicionados depois por interpretação errónea."}}, "es": {"question": "¿Cuál es la diferencia entre \"derechos positivos\" y \"derechos negativos\"?", "options": [{"id": "a", "text": "Los derechos positivos son buenos; los negativos son malos"}, {"id": "b", "text": "Los derechos positivos requieren que otros provean; los negativos requieren que otros se abstengan"}, {"id": "c", "text": "Son lo mismo"}, {"id": "d", "text": "Los derechos positivos son constitucionales; los negativos no"}], "explanation": "Los derechos negativos (los únicos verdaderos) requieren que otros se ABSTENGAN de actuar contra ti — como el derecho a la vida (no me maten). Los ''derechos positivos'' reclaman derecho a bienes que otros deben proveer (educación, salud), lo que viola los derechos de los proveedores.", "wrong_explanations": {"a": "Los derechos negativos son los únicos genuinos. Los ''derechos positivos'' son en realidad reclamos sobre el trabajo ajeno.", "c": "Son opuestos: uno exige acción DE otros; otro exige no-interferencia.", "d": "La Constitución originalmente protegía derechos negativos; los ''derechos'' positivos se añadieron después por mala interpretación."}}, "fr": {"question": "Quelle est la différence entre les \"droits positifs\" et les \"droits négatifs\" ?", "options": [{"id": "a", "text": "Les droits positifs sont bons ; les négatifs sont mauvais"}, {"id": "b", "text": "Les droits positifs exigent que d''autres fournissent ; les négatifs exigent que d''autres s''abstiennent"}, {"id": "c", "text": "C''est la même chose"}, {"id": "d", "text": "Les droits positifs sont constitutionnels ; les négatifs non"}], "explanation": "Les droits négatifs (les seuls vrais droits) exigent que les autres S''ABSTIENNENT d''agir contre vous — comme le droit à la vie (ne me tuez pas). Les ''droits positifs'' revendiquent un droit à des biens que d''autres doivent fournir (éducation, santé), ce qui viole les droits des fournisseurs.", "wrong_explanations": {"a": "Les droits négatifs sont les seuls véritables. Les ''droits positifs'' sont en fait des revendications sur le travail d''autrui.", "c": "Ce sont des opposés : l''un exige une action DES autres ; l''autre exige la non-interférence.", "d": "La Constitution protégeait à l''origine les droits négatifs ; les ''droits'' positifs ont été ajoutés par mauvaise interprétation."}}}'::jsonb WHERE question = 'What is the difference between "positive rights" and "negative rights"?';

-- === SEED FILE 1: ECONOMICS ===

-- Q38
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a \"mão invisível\" em economia?", "options": [{"id": "a", "text": "O governo a controlar secretamente os mercados"}, {"id": "b", "text": "Os benefícios sociais não intencionais de indivíduos a perseguir o autointeresse"}, {"id": "c", "text": "Manipulação corporativa dos consumidores"}, {"id": "d", "text": "Intervenção divina no comércio"}], "explanation": "A ''mão invisível'' de Adam Smith descreve como indivíduos que perseguem o seu autointeresse em mercados livres beneficiam a sociedade involuntariamente. Ao buscar lucro, empreendedores criam produtos que as pessoas querem, empregam trabalhadores e alocam recursos eficientemente — sem planeamento central.", "wrong_explanations": {"a": "A mão invisível é a AUSÊNCIA de controlo governamental, não controlo secreto.", "c": "Em mercados livres, os consumidores controlam os produtores pelas suas escolhas — não o contrário.", "d": "É uma metáfora para a ordem emergente da troca voluntária, não intervenção sobrenatural."}}, "es": {"question": "¿Qué es la \"mano invisible\" en economía?", "options": [{"id": "a", "text": "El gobierno controlando secretamente los mercados"}, {"id": "b", "text": "Los beneficios sociales no intencionales de individuos persiguiendo su autointerés"}, {"id": "c", "text": "Manipulación corporativa de los consumidores"}, {"id": "d", "text": "Intervención divina en el comercio"}], "explanation": "La ''mano invisible'' de Adam Smith describe cómo los individuos que persiguen su autointerés en mercados libres benefician a la sociedad involuntariamente. Al buscar ganancias, los emprendedores crean productos deseados, emplean trabajadores y asignan recursos eficientemente — sin planificación central.", "wrong_explanations": {"a": "La mano invisible es la AUSENCIA de control gubernamental, no control secreto.", "c": "En mercados libres, los consumidores controlan a los productores con sus elecciones — no al revés.", "d": "Es una metáfora del orden emergente del intercambio voluntario, no intervención sobrenatural."}}, "fr": {"question": "Qu''est-ce que la \"main invisible\" en économie ?", "options": [{"id": "a", "text": "Le gouvernement contrôlant secrètement les marchés"}, {"id": "b", "text": "Les bénéfices sociaux non intentionnels d''individus poursuivant leur intérêt personnel"}, {"id": "c", "text": "La manipulation des consommateurs par les entreprises"}, {"id": "d", "text": "L''intervention divine dans le commerce"}], "explanation": "La ''main invisible'' d''Adam Smith décrit comment les individus poursuivant leur intérêt personnel dans les marchés libres bénéficient involontairement à la société. En cherchant le profit, les entrepreneurs créent des produits désirés, emploient des travailleurs et allouent les ressources efficacement — sans planification centrale.", "wrong_explanations": {"a": "La main invisible est l''ABSENCE de contrôle gouvernemental, pas un contrôle secret.", "c": "Dans les marchés libres, les consommateurs contrôlent les producteurs par leurs choix — pas l''inverse.", "d": "C''est une métaphore de l''ordre émergent de l''échange volontaire, pas une intervention surnaturelle."}}}'::jsonb WHERE question = 'What is the "invisible hand" in economics?';

-- Q39
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é uma transação \"ganha-ganha\"?", "options": [{"id": "a", "text": "Quando uma parte engana a outra fazendo-a pensar que ganhou"}, {"id": "b", "text": "Quando ambas as partes ganham valor através de troca voluntária"}, {"id": "c", "text": "Quando o governo garante justiça"}, {"id": "d", "text": "Quando os lucros são divididos igualmente"}], "explanation": "Na troca voluntária, ambas as partes ganham valor ou não trocariam. Se compra um livro por 20€, valoriza o livro mais do que 20€; o vendedor valoriza os 20€ mais do que o livro. Ambos ganham. Esta é a natureza do comércio em mercados livres — benefício mútuo.", "wrong_explanations": {"a": "A deceção é fraude, não comércio. O verdadeiro comércio é honesto e mutuamente benéfico.", "c": "A intervenção governamental frequentemente cria perdedores ao forçar trocas não voluntárias.", "d": "A divisão igual é irrelevante. Ambas as partes ganham segundo os seus PRÓPRIOS valores."}}, "es": {"question": "¿Qué es una transacción \"ganar-ganar\"?", "options": [{"id": "a", "text": "Cuando una parte engaña a la otra haciéndole creer que ganó"}, {"id": "b", "text": "Cuando ambas partes ganan valor mediante intercambio voluntario"}, {"id": "c", "text": "Cuando el gobierno asegura la justicia"}, {"id": "d", "text": "Cuando las ganancias se dividen por igual"}], "explanation": "En el intercambio voluntario, ambas partes ganan valor o no intercambiarían. Si compras un libro por $20, valoras el libro más que $20; el vendedor valora los $20 más que el libro. Ambos ganan. Esta es la naturaleza del comercio en mercados libres — beneficio mutuo.", "wrong_explanations": {"a": "El engaño es fraude, no comercio. El verdadero comercio es honesto y mutuamente beneficioso.", "c": "La intervención gubernamental frecuentemente crea perdedores al forzar intercambios no voluntarios.", "d": "La división igual es irrelevante. Ambas partes ganan según sus PROPIOS valores."}}, "fr": {"question": "Qu''est-ce qu''une transaction \"gagnant-gagnant\" ?", "options": [{"id": "a", "text": "Quand une partie trompe l''autre en lui faisant croire qu''elle a gagné"}, {"id": "b", "text": "Quand les deux parties gagnent de la valeur par un échange volontaire"}, {"id": "c", "text": "Quand le gouvernement assure l''équité"}, {"id": "d", "text": "Quand les profits sont partagés également"}], "explanation": "Dans l''échange volontaire, les deux parties gagnent de la valeur sinon elles n''échangeraient pas. Si vous achetez un livre à 20€, vous valorisez le livre plus que 20€ ; le vendeur valorise les 20€ plus que le livre. Les deux gagnent. C''est la nature du commerce dans les marchés libres — le bénéfice mutuel.", "wrong_explanations": {"a": "La tromperie est de la fraude, pas du commerce. Le vrai commerce est honnête et mutuellement bénéfique.", "c": "L''intervention gouvernementale crée souvent des perdants en forçant des échanges non volontaires.", "d": "Le partage égal est sans importance. Les deux parties gagnent selon leurs PROPRES valeurs."}}}'::jsonb WHERE question = 'What is a "win-win" transaction?';

-- Q40
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que os controlos de preços (como o controlo de rendas) falham?", "options": [{"id": "a", "text": "Não falham — ajudam os pobres"}, {"id": "b", "text": "Criam escassez ao eliminar o incentivo de lucro para oferta"}, {"id": "c", "text": "Só falham quando são definidos muito baixo"}, {"id": "d", "text": "Falham porque os senhorios gananciosos os evitam"}], "explanation": "Controlos de preço abaixo das taxas de mercado eliminam o motivo de lucro para produzir ou ofertar. Com o controlo de rendas, os senhorios deixam de manter os imóveis ou de construir novos. Resultado: escassez de habitação, deterioração da qualidade. A ''cura'' é pior que a doença.", "wrong_explanations": {"a": "O controlo de rendas prejudica as mesmas pessoas que alega ajudar ao reduzir a oferta de habitação.", "c": "QUALQUER preço abaixo do equilíbrio de mercado causa escassez; QUALQUER preço acima causa excedente.", "d": "Os senhorios respondem racionalmente a incentivos. Culpar a ''ganância'' ignora leis económicas."}}, "es": {"question": "¿Por qué los controles de precios (como el control de alquileres) fracasan?", "options": [{"id": "a", "text": "No fracasan — ayudan a los pobres"}, {"id": "b", "text": "Crean escasez al eliminar el incentivo de ganancia para la oferta"}, {"id": "c", "text": "Solo fracasan cuando se fijan muy bajos"}, {"id": "d", "text": "Fracasan porque los propietarios codiciosos los evaden"}], "explanation": "Los controles de precios por debajo de las tasas de mercado eliminan el incentivo de ganancia para producir u ofertar. Con el control de alquileres, los propietarios dejan de mantener sus propiedades o construir nuevas. Resultado: escasez de vivienda, deterioro de calidad. La ''cura'' es peor que la enfermedad.", "wrong_explanations": {"a": "El control de alquileres perjudica a las mismas personas que dice ayudar al reducir la oferta de vivienda.", "c": "CUALQUIER precio por debajo del equilibrio de mercado causa escasez; CUALQUIER precio por encima causa excedente.", "d": "Los propietarios responden racionalmente a incentivos. Culpar a la ''codicia'' ignora leyes económicas."}}, "fr": {"question": "Pourquoi les contrôles de prix (comme l''encadrement des loyers) échouent-ils ?", "options": [{"id": "a", "text": "Ils n''échouent pas — ils aident les pauvres"}, {"id": "b", "text": "Ils créent des pénuries en éliminant l''incitation au profit pour l''offre"}, {"id": "c", "text": "Ils n''échouent que lorsqu''ils sont fixés trop bas"}, {"id": "d", "text": "Ils échouent parce que les propriétaires cupides les contournent"}], "explanation": "Les contrôles de prix en dessous des taux du marché éliminent l''incitation au profit pour produire ou fournir. Avec l''encadrement des loyers, les propriétaires cessent d''entretenir leurs biens ou d''en construire de nouveaux. Résultat : pénurie de logements, détérioration de la qualité. Le ''remède'' est pire que le mal.", "wrong_explanations": {"a": "L''encadrement des loyers nuit aux personnes mêmes qu''il prétend aider en réduisant l''offre de logements.", "c": "TOUT prix en dessous de l''équilibre du marché cause une pénurie ; TOUT prix au-dessus cause un excédent.", "d": "Les propriétaires répondent rationnellement aux incitations. Blâmer la ''cupidité'' ignore les lois économiques."}}}'::jsonb WHERE question = 'Why do price controls (like rent control) fail?';

-- Q41
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a \"falácia da janela partida\"?", "options": [{"id": "a", "text": "Que janelas nunca devem ser partidas"}, {"id": "b", "text": "Que a destruição cria benefício económico ao criar trabalho"}, {"id": "c", "text": "Que as estatísticas de crime são enganosas"}, {"id": "d", "text": "Que as aparências importam mais que a substância"}], "explanation": "Frédéric Bastiat expôs esta falácia: as pessoas veem o vidraceiro empregado para consertar a janela partida (visível), mas não o que o comerciante teria comprado em vez disso (invisível). A destruição não cria riqueza — destrói-a. Os benefícios vistos escondem as perdas não vistas.", "wrong_explanations": {"a": "A falácia não é sobre se devemos partir janelas — é sobre a falsa alegação de que a destruição ajuda a economia.", "c": "Embora verdade, isso não está relacionado com a falácia económica de Bastiat.", "d": "A falácia é especificamente sobre raciocínio económico, não sobre aparências gerais."}}, "es": {"question": "¿Qué es la \"falacia de la ventana rota\"?", "options": [{"id": "a", "text": "Que las ventanas nunca deben romperse"}, {"id": "b", "text": "Que la destrucción crea beneficio económico al crear trabajo"}, {"id": "c", "text": "Que las estadísticas de crimen son engañosas"}, {"id": "d", "text": "Que las apariencias importan más que la sustancia"}], "explanation": "Frédéric Bastiat expuso esta falacia: la gente ve al vidriero empleado para reparar la ventana rota (visible), pero no lo que el comerciante habría comprado en su lugar (invisible). La destrucción no crea riqueza — la destruye. Los beneficios visibles ocultan las pérdidas invisibles.", "wrong_explanations": {"a": "La falacia no trata de si debemos romper ventanas — sino de la falsa afirmación de que la destrucción ayuda a la economía.", "c": "Aunque cierto, eso no está relacionado con la falacia económica de Bastiat.", "d": "La falacia es específicamente sobre razonamiento económico, no sobre apariencias generales."}}, "fr": {"question": "Qu''est-ce que la \"fable de la vitre cassée\" ?", "options": [{"id": "a", "text": "Que les vitres ne devraient jamais être cassées"}, {"id": "b", "text": "Que la destruction crée un bénéfice économique en créant du travail"}, {"id": "c", "text": "Que les statistiques criminelles sont trompeuses"}, {"id": "d", "text": "Que les apparences comptent plus que la substance"}], "explanation": "Frédéric Bastiat a exposé ce sophisme : on voit le vitrier employé pour réparer la vitre cassée (le visible), mais pas ce que le commerçant aurait acheté à la place (l''invisible). La destruction ne crée pas de richesse — elle la détruit. Les bénéfices visibles cachent les pertes invisibles.", "wrong_explanations": {"a": "Le sophisme ne porte pas sur le fait de casser des vitres — mais sur la fausse affirmation que la destruction aide l''économie.", "c": "Bien que vrai, cela n''a pas de rapport avec le sophisme économique de Bastiat.", "d": "Le sophisme porte spécifiquement sur le raisonnement économique, pas sur les apparences générales."}}}'::jsonb WHERE question = 'What is the "broken window fallacy"?';

-- === SEED FILE 1: HISTORY ===

-- Q42
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que a Revolução Americana foi filosoficamente significativa?", "options": [{"id": "a", "text": "Foi a primeira revolução"}, {"id": "b", "text": "Estabeleceu uma nação baseada em direitos individuais, não em direito de grupo ou divino"}, {"id": "c", "text": "Criou uma democracia"}, {"id": "d", "text": "Derrubou a monarquia pelo socialismo"}], "explanation": "A Revolução Americana foi a primeira nação da história fundada no princípio dos direitos individuais. A Declaração de Independência proclamou que os indivíduos têm direitos inalienáveis à vida, liberdade e busca da felicidade — e que o governo existe para proteger esses direitos.", "wrong_explanations": {"a": "Muitas revoluções a precederam. A sua singularidade foi a base filosófica.", "c": "A América é uma república constitucional que protege direitos DA democracia (governo da maioria).", "d": "Os Fundadores defenderam governo limitado e direitos de propriedade — o oposto do socialismo."}}, "es": {"question": "¿Por qué la Revolución Americana fue filosóficamente significativa?", "options": [{"id": "a", "text": "Fue la primera revolución"}, {"id": "b", "text": "Estableció una nación basada en derechos individuales, no en derecho grupal o divino"}, {"id": "c", "text": "Creó una democracia"}, {"id": "d", "text": "Derrocó la monarquía por el socialismo"}], "explanation": "La Revolución Americana fue la primera nación de la historia fundada en el principio de los derechos individuales. La Declaración de Independencia proclamó que los individuos tienen derechos inalienables a la vida, libertad y búsqueda de la felicidad — y que el gobierno existe para proteger esos derechos.", "wrong_explanations": {"a": "Muchas revoluciones la precedieron. Su singularidad fue la base filosófica.", "c": "América es una república constitucional que protege derechos DE la democracia (gobierno de la mayoría).", "d": "Los Fundadores defendieron gobierno limitado y derechos de propiedad — lo opuesto del socialismo."}}, "fr": {"question": "Pourquoi la Révolution américaine fut-elle philosophiquement significative ?", "options": [{"id": "a", "text": "Ce fut la première révolution"}, {"id": "b", "text": "Elle a établi une nation fondée sur les droits individuels, pas sur le droit de groupe ou divin"}, {"id": "c", "text": "Elle a créé une démocratie"}, {"id": "d", "text": "Elle a renversé la monarchie pour le socialisme"}], "explanation": "La Révolution américaine fut la première nation de l''histoire fondée sur le principe des droits individuels. La Déclaration d''Indépendance proclama que les individus ont des droits inaliénables à la vie, à la liberté et à la poursuite du bonheur — et que le gouvernement existe pour protéger ces droits.", "wrong_explanations": {"a": "Beaucoup de révolutions l''ont précédée. Son unicité résidait dans sa base philosophique.", "c": "L''Amérique est une république constitutionnelle qui protège les droits DE la démocratie (règle de la majorité).", "d": "Les Fondateurs défendaient le gouvernement limité et les droits de propriété — l''opposé du socialisme."}}}'::jsonb WHERE question = 'Why was the American Revolution philosophically significant?';

-- Q43
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Que erro filosófico levou ao Reinado de Terror da Revolução Francesa?", "options": [{"id": "a", "text": "Demasiada liberdade individual"}, {"id": "b", "text": "A ''vontade geral'' de Rousseau sacrificando indivíduos ao coletivo"}, {"id": "c", "text": "Proteção excessiva dos direitos de propriedade"}, {"id": "d", "text": "Seguir o modelo americano demasiado de perto"}], "explanation": "O conceito de ''vontade geral'' de Rousseau sustentava que a vontade do coletivo supera os direitos individuais. Isto justificou o assassinato de indivíduos que se opunham à Revolução. Ao contrário da América (direitos individuais), a França (direitos coletivos) desceu à tirania e ao assassinato em massa.", "wrong_explanations": {"a": "A liberdade individual era precisamente o que FALTAVA. O Terror sacrificou indivíduos à ''nação''.", "c": "A propriedade foi confiscada em massa. A proteção dos direitos de propriedade poderia ter prevenido o Terror.", "d": "Os franceses rejeitaram EXPLICITAMENTE o modelo americano de direitos individuais."}}, "es": {"question": "¿Qué error filosófico llevó al Reinado del Terror de la Revolución Francesa?", "options": [{"id": "a", "text": "Demasiada libertad individual"}, {"id": "b", "text": "La ''voluntad general'' de Rousseau sacrificando individuos al colectivo"}, {"id": "c", "text": "Protección excesiva de los derechos de propiedad"}, {"id": "d", "text": "Seguir el modelo americano muy de cerca"}], "explanation": "El concepto de ''voluntad general'' de Rousseau sostenía que la voluntad del colectivo supera los derechos individuales. Esto justificó el asesinato de individuos que se oponían a la Revolución. A diferencia de América (derechos individuales), Francia (derechos colectivos) descendió a la tiranía y el asesinato masivo.", "wrong_explanations": {"a": "La libertad individual era precisamente lo que FALTABA. El Terror sacrificó individuos a la ''nación''.", "c": "La propiedad fue confiscada masivamente. La protección de los derechos de propiedad podría haber prevenido el Terror.", "d": "Los franceses rechazaron EXPLÍCITAMENTE el modelo americano de derechos individuales."}}, "fr": {"question": "Quelle erreur philosophique a mené à la Terreur de la Révolution française ?", "options": [{"id": "a", "text": "Trop de liberté individuelle"}, {"id": "b", "text": "La ''volonté générale'' de Rousseau sacrifiant les individus au collectif"}, {"id": "c", "text": "Protection excessive des droits de propriété"}, {"id": "d", "text": "Suivre le modèle américain de trop près"}], "explanation": "Le concept de ''volonté générale'' de Rousseau soutenait que la volonté du collectif prime sur les droits individuels. Cela a justifié l''assassinat d''individus opposés à la Révolution. Contrairement à l''Amérique (droits individuels), la France (droits collectifs) a sombré dans la tyrannie et le meurtre de masse.", "wrong_explanations": {"a": "La liberté individuelle était précisément ce qui MANQUAIT. La Terreur a sacrifié les individus à la ''nation''.", "c": "La propriété fut confisquée en masse. La protection des droits de propriété aurait pu empêcher la Terreur.", "d": "Les Français ont EXPLICITEMENT rejeté le modèle américain des droits individuels."}}}'::jsonb WHERE question = 'What philosophical error led to the French Revolution''s Reign of Terror?';

-- Q44
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que o bombardeio atómico do Japão na verdade salvou vidas?", "options": [{"id": "a", "text": "Não salvou — foi puramente destrutivo"}, {"id": "b", "text": "A alternativa de invasão teria matado milhões de americanos e japoneses"}, {"id": "c", "text": "O Japão estava prestes a render-se de qualquer forma"}, {"id": "d", "text": "Impediu uma invasão soviética"}], "explanation": "A Operação Downfall (invasão planeada) projetava 500.000-1.000.000 de baixas americanas e milhões de japoneses. O exército japonês planeava armar civis com lanças de bambu. As bombas atómicas, embora devastadoras, terminaram a guerra imediatamente e salvaram muito mais vidas do que tiraram.", "wrong_explanations": {"a": "A guerra é destrutiva, mas a alternativa era MAIS destruição através de uma invasão prolongada.", "c": "O exército japonês rejeitou a rendição mesmo APÓS a primeira bomba. Planeavam lutar até ao último.", "d": "Embora um fator, o cálculo principal era as vidas americanas e japonesas salvas vs. invasão."}}, "es": {"question": "¿Por qué el bombardeo atómico de Japón realmente salvó vidas?", "options": [{"id": "a", "text": "No las salvó — fue puramente destructivo"}, {"id": "b", "text": "La alternativa de invasión habría matado a millones de americanos y japoneses"}, {"id": "c", "text": "Japón estaba a punto de rendirse de todas formas"}, {"id": "d", "text": "Impidió una invasión soviética"}], "explanation": "La Operación Downfall (invasión planificada) proyectaba 500.000-1.000.000 de bajas americanas y millones de japoneses. El ejército japonés planeaba armar civiles con lanzas de bambú. Las bombas atómicas, aunque devastadoras, terminaron la guerra inmediatamente y salvaron muchas más vidas de las que quitaron.", "wrong_explanations": {"a": "La guerra es destructiva, pero la alternativa era MÁS destrucción a través de una invasión prolongada.", "c": "El ejército japonés rechazó la rendición incluso DESPUÉS de la primera bomba. Planeaban luchar hasta el último.", "d": "Aunque fue un factor, el cálculo principal eran las vidas americanas y japonesas salvadas vs. invasión."}}, "fr": {"question": "Pourquoi le bombardement atomique du Japon a-t-il en fait sauvé des vies ?", "options": [{"id": "a", "text": "Il n''en a pas sauvé — c''était purement destructeur"}, {"id": "b", "text": "L''alternative d''invasion aurait tué des millions d''Américains et de Japonais"}, {"id": "c", "text": "Le Japon était sur le point de se rendre de toute façon"}, {"id": "d", "text": "Cela a empêché une invasion soviétique"}], "explanation": "L''Opération Downfall (invasion prévue) projetait 500 000 à 1 000 000 de pertes américaines et des millions de Japonais. L''armée japonaise prévoyait d''armer les civils avec des lances en bambou. Les bombes atomiques, bien que dévastatrices, ont mis fin à la guerre immédiatement et ont sauvé bien plus de vies qu''elles n''en ont pris.", "wrong_explanations": {"a": "La guerre est destructrice, mais l''alternative était PLUS de destruction par une invasion prolongée.", "c": "L''armée japonaise a rejeté la reddition même APRÈS la première bombe. Ils prévoyaient de se battre jusqu''au dernier.", "d": "Bien que ce soit un facteur, le calcul principal portait sur les vies américaines et japonaises sauvées vs. l''invasion."}}}'::jsonb WHERE question = 'Why did the atomic bombing of Japan actually save lives?';

-- Q45
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Qual foi a causa filosófica dos assassinatos em massa sem precedentes do século XX?", "options": [{"id": "a", "text": "Tecnologia — melhores armas permitiram mais mortes"}, {"id": "b", "text": "Coletivismo — ideologias que sacrificaram indivíduos a grupos"}, {"id": "c", "text": "Excessos do capitalismo"}, {"id": "d", "text": "Extremismo religioso"}], "explanation": "Os ~100 milhões de assassinatos por governos no século XX (URSS, China, Alemanha Nazi, Camboja) derivaram todos de ideologias coletivistas: comunismo, fascismo e socialismo. Cada uma sacrificou indivíduos ao ''bem coletivo'' — o estado, a raça ou a classe.", "wrong_explanations": {"a": "A tecnologia foi o meio, não a causa. A mesma tecnologia não causou assassinatos em massa em países livres.", "c": "As piores atrocidades ocorreram em regimes anticapitalistas (URSS, China, Camboja).", "d": "Embora tenha havido alguma violência religiosa, as mega-mortes vieram de ideologias coletivistas seculares."}}, "es": {"question": "¿Cuál fue la causa filosófica de los asesinatos en masa sin precedentes del siglo XX?", "options": [{"id": "a", "text": "Tecnología — mejores armas permitieron más muertes"}, {"id": "b", "text": "Colectivismo — ideologías que sacrificaron individuos a grupos"}, {"id": "c", "text": "Excesos del capitalismo"}, {"id": "d", "text": "Extremismo religioso"}], "explanation": "Los ~100 millones de asesinatos por gobiernos en el siglo XX (URSS, China, Alemania Nazi, Camboya) derivaron todos de ideologías colectivistas: comunismo, fascismo y socialismo. Cada una sacrificó individuos al ''bien colectivo'' — el estado, la raza o la clase.", "wrong_explanations": {"a": "La tecnología fue el medio, no la causa. La misma tecnología no causó asesinatos en masa en países libres.", "c": "Las peores atrocidades ocurrieron en regímenes anticapitalistas (URSS, China, Camboya).", "d": "Aunque hubo algo de violencia religiosa, las mega-muertes vinieron de ideologías colectivistas seculares."}}, "fr": {"question": "Quelle fut la cause philosophique des massacres sans précédent du XXe siècle ?", "options": [{"id": "a", "text": "La technologie — de meilleures armes ont permis plus de morts"}, {"id": "b", "text": "Le collectivisme — des idéologies qui ont sacrifié les individus aux groupes"}, {"id": "c", "text": "Les excès du capitalisme"}, {"id": "d", "text": "L''extrémisme religieux"}], "explanation": "Les ~100 millions d''assassinats par les gouvernements au XXe siècle (URSS, Chine, Allemagne nazie, Cambodge) découlaient tous d''idéologies collectivistes : communisme, fascisme et socialisme. Chacune a sacrifié les individus au ''bien collectif'' — l''État, la race ou la classe.", "wrong_explanations": {"a": "La technologie était le moyen, pas la cause. La même technologie n''a pas causé de massacres dans les pays libres.", "c": "Les pires atrocités se sont produites dans des régimes anticapitalistes (URSS, Chine, Cambodge).", "d": "Bien qu''il y ait eu de la violence religieuse, les méga-morts provenaient d''idéologies collectivistes séculières."}}}'::jsonb WHERE question = 'What was the philosophical cause of the 20th century''s unprecedented mass murders?';

-- Q46
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que demonstrou a queda da União Soviética em 1991?", "options": [{"id": "a", "text": "Que o socialismo pode funcionar se implementado corretamente"}, {"id": "b", "text": "Que o coletivismo e o planeamento central não podem sustentar uma economia ou sociedade"}, {"id": "c", "text": "Que a derrota militar acabou com o comunismo"}, {"id": "d", "text": "Que o comunismo só era mau por causa de Estaline"}], "explanation": "A URSS colapsou porque o socialismo não funciona. Sem propriedade privada e preços de mercado, os planeadores centrais não podem alocar recursos racionalmente. A economia soviética foi um desastre económico e humanitário. As ideias têm consequências — más ideias têm más consequências.", "wrong_explanations": {"a": "O argumento ''não era verdadeiro socialismo'' ignora que os fracassos do socialismo são inerentes, não acidentais.", "c": "A URSS não foi derrotada militarmente — colapsou internamente por fracasso económico.", "d": "Os problemas soviéticos persistiram com todos os líderes. O sistema em si era o problema."}}, "es": {"question": "¿Qué demostró la caída de la Unión Soviética en 1991?", "options": [{"id": "a", "text": "Que el socialismo puede funcionar si se implementa correctamente"}, {"id": "b", "text": "Que el colectivismo y la planificación central no pueden sostener una economía o sociedad"}, {"id": "c", "text": "Que la derrota militar acabó con el comunismo"}, {"id": "d", "text": "Que el comunismo solo era malo por culpa de Stalin"}], "explanation": "La URSS colapsó porque el socialismo no funciona. Sin propiedad privada y precios de mercado, los planificadores centrales no pueden asignar recursos racionalmente. La economía soviética fue un desastre económico y humanitario. Las ideas tienen consecuencias — malas ideas tienen malas consecuencias.", "wrong_explanations": {"a": "El argumento ''no era verdadero socialismo'' ignora que los fracasos del socialismo son inherentes, no accidentales.", "c": "La URSS no fue derrotada militarmente — colapsó internamente por fracaso económico.", "d": "Los problemas soviéticos persistieron con todos los líderes. El sistema en sí era el problema."}}, "fr": {"question": "Qu''a démontré la chute de l''Union soviétique en 1991 ?", "options": [{"id": "a", "text": "Que le socialisme peut fonctionner s''il est correctement mis en œuvre"}, {"id": "b", "text": "Que le collectivisme et la planification centrale ne peuvent soutenir une économie ou une société"}, {"id": "c", "text": "Que la défaite militaire a mis fin au communisme"}, {"id": "d", "text": "Que le communisme n''était mauvais qu''à cause de Staline"}], "explanation": "L''URSS s''est effondrée parce que le socialisme ne fonctionne pas. Sans propriété privée et prix de marché, les planificateurs centraux ne peuvent allouer les ressources rationnellement. L''économie soviétique fut un désastre économique et humanitaire. Les idées ont des conséquences — les mauvaises idées ont de mauvaises conséquences.", "wrong_explanations": {"a": "L''argument ''ce n''était pas du vrai socialisme'' ignore que les échecs du socialisme sont inhérents, pas accidentels.", "c": "L''URSS n''a pas été vaincue militairement — elle s''est effondrée de l''intérieur par échec économique.", "d": "Les problèmes soviétiques ont persisté sous tous les dirigeants. Le système lui-même était le problème."}}}'::jsonb WHERE question = 'What did the fall of the Soviet Union in 1991 demonstrate?';

-- === SEED FILE 1: AMERICAN EXCEPTIONALISM ===

-- Q47
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que torna a América filosoficamente única entre as nações?", "options": [{"id": "a", "text": "O seu poder militar"}, {"id": "b", "text": "Foi fundada no princípio de que os indivíduos têm direitos que o governo não pode violar"}, {"id": "c", "text": "O seu tamanho e recursos naturais"}, {"id": "d", "text": "A sua diversidade cultural"}], "explanation": "A América foi a primeira nação fundada numa ideia filosófica: que os indivíduos possuem direitos inerentes à vida, liberdade e busca da felicidade, e que o governo existe para proteger — não conceder — esses direitos. Nenhuma outra nação foi fundada neste princípio explícito.", "wrong_explanations": {"a": "O poder militar é consequência da produtividade americana, não o seu fundamento filosófico.", "c": "Muitas nações têm recursos. As ideias é que tornaram a América capaz de usá-los produtivamente.", "d": "A diversidade existe noutros lugares. A IDEIA unificadora de direitos individuais é que é única."}}, "es": {"question": "¿Qué hace a América filosóficamente única entre las naciones?", "options": [{"id": "a", "text": "Su poder militar"}, {"id": "b", "text": "Fue fundada en el principio de que los individuos tienen derechos que el gobierno no puede violar"}, {"id": "c", "text": "Su tamaño y recursos naturales"}, {"id": "d", "text": "Su diversidad cultural"}], "explanation": "América fue la primera nación fundada en una idea filosófica: que los individuos poseen derechos inherentes a la vida, libertad y búsqueda de la felicidad, y que el gobierno existe para proteger — no otorgar — esos derechos. Ninguna otra nación fue fundada en este principio explícito.", "wrong_explanations": {"a": "El poder militar es consecuencia de la productividad americana, no su fundamento filosófico.", "c": "Muchas naciones tienen recursos. Las ideas hicieron a América capaz de usarlos productivamente.", "d": "La diversidad existe en otros lugares. La IDEA unificadora de derechos individuales es lo único."}}, "fr": {"question": "Qu''est-ce qui rend l''Amérique philosophiquement unique parmi les nations ?", "options": [{"id": "a", "text": "Sa puissance militaire"}, {"id": "b", "text": "Elle a été fondée sur le principe que les individus ont des droits que le gouvernement ne peut violer"}, {"id": "c", "text": "Sa taille et ses ressources naturelles"}, {"id": "d", "text": "Sa diversité culturelle"}], "explanation": "L''Amérique fut la première nation fondée sur une idée philosophique : que les individus possèdent des droits inhérents à la vie, à la liberté et à la poursuite du bonheur, et que le gouvernement existe pour protéger — et non accorder — ces droits. Aucune autre nation n''a été fondée sur ce principe explicite.", "wrong_explanations": {"a": "La puissance militaire est une conséquence de la productivité américaine, pas son fondement philosophique.", "c": "Beaucoup de nations ont des ressources. Les idées ont rendu l''Amérique capable de les utiliser productivement.", "d": "La diversité existe ailleurs. L''IDÉE unificatrice des droits individuels est ce qui est unique."}}}'::jsonb WHERE question = 'What makes America philosophically unique among nations?';

-- Q48
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que significa \"direitos inalienáveis\" na Declaração de Independência?", "options": [{"id": "a", "text": "Direitos que podem ser retirados por lei"}, {"id": "b", "text": "Direitos inerentes à natureza humana que não podem ser legitimamente removidos"}, {"id": "c", "text": "Direitos dados pelo governo"}, {"id": "d", "text": "Direitos apenas para cidadãos"}], "explanation": "\"Inalienáveis\" significa que estes direitos não podem ser legitimamente tirados, transferidos ou cedidos. São inerentes à natureza humana — não concedidos pelo governo ou sociedade. Mesmo que o governo os viole, permanecem moralmente seus. Isto limita absolutamente o poder governamental.", "wrong_explanations": {"a": "Se os direitos pudessem ser retirados por lei, não seriam ''inalienáveis'' — seriam privilégios.", "c": "O governo não cria direitos — só pode reconhecer ou violar direitos preexistentes.", "d": "Os direitos naturais aplicam-se a todos os humanos em virtude da sua humanidade, não da cidadania."}}, "es": {"question": "¿Qué significa \"derechos inalienables\" en la Declaración de Independencia?", "options": [{"id": "a", "text": "Derechos que pueden ser quitados por ley"}, {"id": "b", "text": "Derechos inherentes a la naturaleza humana que no pueden ser legítimamente removidos"}, {"id": "c", "text": "Derechos otorgados por el gobierno"}, {"id": "d", "text": "Derechos solo para ciudadanos"}], "explanation": "\"Inalienables\" significa que estos derechos no pueden ser legítimamente quitados, transferidos o cedidos. Son inherentes a la naturaleza humana — no otorgados por el gobierno o la sociedad. Incluso si el gobierno los viola, siguen siendo moralmente tuyos. Esto limita absolutamente el poder gubernamental.", "wrong_explanations": {"a": "Si los derechos pudieran ser quitados por ley, no serían ''inalienables'' — serían privilegios.", "c": "El gobierno no crea derechos — solo puede reconocer o violar derechos preexistentes.", "d": "Los derechos naturales se aplican a todos los humanos en virtud de su humanidad, no de la ciudadanía."}}, "fr": {"question": "Que signifie \"droits inaliénables\" dans la Déclaration d''Indépendance ?", "options": [{"id": "a", "text": "Des droits qui peuvent être retirés par la loi"}, {"id": "b", "text": "Des droits inhérents à la nature humaine qui ne peuvent être légitimement supprimés"}, {"id": "c", "text": "Des droits accordés par le gouvernement"}, {"id": "d", "text": "Des droits réservés aux citoyens"}], "explanation": "\"Inaliénables\" signifie que ces droits ne peuvent être légitimement retirés, transférés ou abandonnés. Ils sont inhérents à la nature humaine — pas accordés par le gouvernement ou la société. Même si le gouvernement les viole, ils restent moralement vôtres. Cela limite absolument le pouvoir gouvernemental.", "wrong_explanations": {"a": "Si les droits pouvaient être retirés par la loi, ils ne seraient pas ''inaliénables'' — ce seraient des privilèges.", "c": "Le gouvernement ne crée pas les droits — il ne peut que reconnaître ou violer des droits préexistants.", "d": "Les droits naturels s''appliquent à tous les êtres humains en vertu de leur humanité, pas de leur citoyenneté."}}}'::jsonb WHERE question = 'What does "unalienable rights" mean in the Declaration of Independence?';

-- Q49
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que os Fundadores criaram uma república em vez de uma democracia pura?", "options": [{"id": "a", "text": "Não confiavam no povo comum"}, {"id": "b", "text": "Para proteger os direitos individuais da tirania da maioria"}, {"id": "c", "text": "A democracia ainda não tinha sido inventada"}, {"id": "d", "text": "Para beneficiar os ricos"}], "explanation": "Os Fundadores entendiam que a democracia pura — governo ilimitado da maioria — poderia votar para eliminar os direitos das minorias. Uma república limita o poder governamental através de uma constituição que protege os direitos individuais independentemente da opinião da maioria. Direitos não estão sujeitos a voto.", "wrong_explanations": {"a": "A questão não era desconfiança do povo, mas proteção CONTRA qualquer grupo — maioria ou minoria — que violasse direitos.", "c": "A democracia remonta à Atenas antiga. Os Fundadores deliberadamente a rejeitaram.", "d": "Os limites constitucionais protegem os direitos de todos, não apenas dos ricos."}}, "es": {"question": "¿Por qué los Fundadores crearon una república en vez de una democracia pura?", "options": [{"id": "a", "text": "No confiaban en el pueblo común"}, {"id": "b", "text": "Para proteger los derechos individuales de la tiranía de la mayoría"}, {"id": "c", "text": "La democracia aún no había sido inventada"}, {"id": "d", "text": "Para beneficiar a los ricos"}], "explanation": "Los Fundadores entendían que la democracia pura — gobierno ilimitado de la mayoría — podría votar para eliminar los derechos de las minorías. Una república limita el poder gubernamental a través de una constitución que protege los derechos individuales sin importar la opinión de la mayoría. Los derechos no están sujetos a votación.", "wrong_explanations": {"a": "La cuestión no era desconfianza del pueblo, sino protección CONTRA cualquier grupo — mayoría o minoría — que violara derechos.", "c": "La democracia se remonta a la Atenas antigua. Los Fundadores deliberadamente la rechazaron.", "d": "Los límites constitucionales protegen los derechos de todos, no solo de los ricos."}}, "fr": {"question": "Pourquoi les Fondateurs ont-ils créé une république plutôt qu''une démocratie pure ?", "options": [{"id": "a", "text": "Ils ne faisaient pas confiance au peuple"}, {"id": "b", "text": "Pour protéger les droits individuels de la tyrannie de la majorité"}, {"id": "c", "text": "La démocratie n''avait pas encore été inventée"}, {"id": "d", "text": "Pour bénéficier aux riches"}], "explanation": "Les Fondateurs comprenaient que la démocratie pure — règle illimitée de la majorité — pouvait voter pour supprimer les droits des minorités. Une république limite le pouvoir gouvernemental par une constitution qui protège les droits individuels indépendamment de l''opinion de la majorité. Les droits ne sont pas soumis au vote.", "wrong_explanations": {"a": "La question n''était pas la méfiance envers le peuple mais la protection CONTRE tout groupe — majorité ou minorité — qui violerait les droits.", "c": "La démocratie remonte à l''Athènes antique. Les Fondateurs l''ont délibérément rejetée.", "d": "Les limites constitutionnelles protègent les droits de tous, pas seulement des riches."}}}'::jsonb WHERE question = 'Why did the Founders create a republic rather than a pure democracy?';

-- === SEED FILE 1: LAW ===

-- Q50
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é \"lei objetiva\"?", "options": [{"id": "a", "text": "Lei que os juízes podem interpretar flexivelmente"}, {"id": "b", "text": "Lei claramente definida, conhecível antecipadamente e que se aplica igualmente a todos"}, {"id": "c", "text": "Lei baseada na vontade do governante"}, {"id": "d", "text": "Lei que muda com as condições sociais"}], "explanation": "A lei objetiva é claramente definida para que os cidadãos saibam antecipadamente o que é proibido, previsível na aplicação e aplica-se igualmente a todos — incluindo funcionários do governo. Os homens podem viver e planear porque conhecem as regras. A lei subjetiva é tirania pela incerteza.", "wrong_explanations": {"a": "A interpretação flexível torna a lei subjetiva — não se pode saber se se está em conformidade.", "c": "O governo pela vontade do governante é o oposto: poder arbitrário, não padrões objetivos.", "d": "A lei que muda constantemente não pode ser conhecida antecipadamente — tornando a conformidade impossível."}}, "es": {"question": "¿Qué es la \"ley objetiva\"?", "options": [{"id": "a", "text": "Ley que los jueces pueden interpretar flexiblemente"}, {"id": "b", "text": "Ley claramente definida, conocible de antemano y que se aplica igualmente a todos"}, {"id": "c", "text": "Ley basada en la voluntad del gobernante"}, {"id": "d", "text": "Ley que cambia con las condiciones sociales"}], "explanation": "La ley objetiva está claramente definida para que los ciudadanos sepan de antemano lo que está prohibido, es predecible en su aplicación y se aplica igualmente a todos — incluidos los funcionarios del gobierno. Los hombres pueden vivir y planificar porque conocen las reglas. La ley subjetiva es tiranía por incertidumbre.", "wrong_explanations": {"a": "La interpretación flexible hace la ley subjetiva — no se puede saber si se está cumpliendo.", "c": "El gobierno por voluntad del gobernante es lo opuesto: poder arbitrario, no estándares objetivos.", "d": "La ley que cambia constantemente no puede conocerse de antemano — haciendo el cumplimiento imposible."}}, "fr": {"question": "Qu''est-ce que la \"loi objective\" ?", "options": [{"id": "a", "text": "Une loi que les juges peuvent interpréter de manière flexible"}, {"id": "b", "text": "Une loi clairement définie, connaissable à l''avance et qui s''applique également à tous"}, {"id": "c", "text": "Une loi basée sur la volonté du dirigeant"}, {"id": "d", "text": "Une loi qui change avec les conditions sociales"}], "explanation": "La loi objective est clairement définie pour que les citoyens sachent à l''avance ce qui est interdit, prévisible dans son application et s''applique également à tous — y compris les fonctionnaires du gouvernement. Les hommes peuvent vivre et planifier car ils connaissent les règles. La loi subjective est la tyrannie par l''incertitude.", "wrong_explanations": {"a": "L''interprétation flexible rend la loi subjective — on ne peut savoir si on s''y conforme.", "c": "Le gouvernement par la volonté du dirigeant est l''opposé : un pouvoir arbitraire, pas des standards objectifs.", "d": "La loi qui change constamment ne peut être connue à l''avance — rendant la conformité impossible."}}}'::jsonb WHERE question = 'What is "objective law"?';

-- Q51
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é o \"estado de direito\" em oposição ao \"governo dos homens\"?", "options": [{"id": "a", "text": "Mais leis são melhores que menos"}, {"id": "b", "text": "Mesmo os governantes estão vinculados pela lei; ninguém está acima dela"}, {"id": "c", "text": "A aplicação da lei deve ser rigorosa"}, {"id": "d", "text": "Advogados devem governar o país"}], "explanation": "O estado de direito significa que princípios legais objetivos — não a vontade arbitrária dos governantes — governam a sociedade. Todos, incluindo o rei, presidente ou maioria, são vinculados pelas mesmas leis. O governo dos homens significa que o capricho de alguém determina os resultados — poder arbitrário.", "wrong_explanations": {"a": "O número de leis é irrelevante. O que importa é a sua objetividade e limites ao poder.", "c": "A aplicação rigorosa de leis arbitrárias ainda é tirania.", "d": "O estado de direito é um princípio, não sobre quem ocupa o cargo."}}, "es": {"question": "¿Qué es el \"estado de derecho\" en oposición al \"gobierno de los hombres\"?", "options": [{"id": "a", "text": "Más leyes son mejores que menos"}, {"id": "b", "text": "Incluso los gobernantes están sujetos a la ley; nadie está por encima de ella"}, {"id": "c", "text": "La aplicación de la ley debe ser estricta"}, {"id": "d", "text": "Los abogados deben gobernar el país"}], "explanation": "El estado de derecho significa que principios legales objetivos — no la voluntad arbitraria de los gobernantes — gobiernan la sociedad. Todos, incluidos el rey, presidente o mayoría, están sujetos a las mismas leyes. El gobierno de los hombres significa que el capricho de alguien determina los resultados — poder arbitrario.", "wrong_explanations": {"a": "El número de leyes es irrelevante. Lo que importa es su objetividad y los límites al poder.", "c": "La aplicación estricta de leyes arbitrarias sigue siendo tiranía.", "d": "El estado de derecho es un principio, no se trata de quién ocupa el cargo."}}, "fr": {"question": "Qu''est-ce que l''\"état de droit\" par opposition au \"gouvernement des hommes\" ?", "options": [{"id": "a", "text": "Plus de lois valent mieux que moins"}, {"id": "b", "text": "Même les dirigeants sont liés par la loi ; personne n''est au-dessus"}, {"id": "c", "text": "L''application de la loi doit être stricte"}, {"id": "d", "text": "Les avocats devraient diriger le gouvernement"}], "explanation": "L''état de droit signifie que des principes juridiques objectifs — et non la volonté arbitraire des dirigeants — gouvernent la société. Tout le monde, y compris le roi, le président ou la majorité, est lié par les mêmes lois. Le gouvernement des hommes signifie que le caprice de quelqu''un détermine les résultats — un pouvoir arbitraire.", "wrong_explanations": {"a": "Le nombre de lois est sans importance. Ce qui compte, c''est leur objectivité et les limites au pouvoir.", "c": "L''application stricte de lois arbitraires reste de la tyrannie.", "d": "L''état de droit est un principe, pas une question de qui occupe les fonctions."}}}'::jsonb WHERE question = 'What is the "rule of law" as opposed to "rule of men"?';

-- Q52
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que a lei deve basear-se na proteção dos direitos individuais em vez de promover o \"bem social\"?", "options": [{"id": "a", "text": "Os direitos individuais são egoístas"}, {"id": "b", "text": "O ''bem social'' é indefinido e pode justificar qualquer violação de direitos"}, {"id": "c", "text": "Não existe tal coisa como sociedade"}, {"id": "d", "text": "O bem social é mais importante que os direitos"}], "explanation": "O ''bem social'' não tem definição objetiva — significa o que quer que os detentores do poder digam que significa. Justificou escravatura, genocídio e totalitarismo. Os direitos individuais fornecem um limite objetivo e principiado ao que o governo (ou maiorias) pode fazer aos indivíduos.", "wrong_explanations": {"a": "Os direitos individuais são a precondição para qualquer ''bem'' genuíno — para indivíduos ou sociedade.", "c": "A sociedade existe como coleção de indivíduos — mas não tem direitos para além dos direitos individuais.", "d": "Sacrificar indivíduos ao ''bem social'' É o crime definidor do coletivismo."}}, "es": {"question": "¿Por qué la ley debe basarse en proteger los derechos individuales en vez de promover el \"bien social\"?", "options": [{"id": "a", "text": "Los derechos individuales son egoístas"}, {"id": "b", "text": "El ''bien social'' es indefinido y puede justificar cualquier violación de derechos"}, {"id": "c", "text": "No existe tal cosa como la sociedad"}, {"id": "d", "text": "El bien social es más importante que los derechos"}], "explanation": "El ''bien social'' no tiene definición objetiva — significa lo que los que están en el poder digan que significa. Ha justificado esclavitud, genocidio y totalitarismo. Los derechos individuales proporcionan un límite objetivo y basado en principios a lo que el gobierno (o mayorías) puede hacer a los individuos.", "wrong_explanations": {"a": "Los derechos individuales son la precondición para cualquier ''bien'' genuino — para individuos o sociedad.", "c": "La sociedad existe como colección de individuos — pero no tiene derechos aparte de los derechos individuales.", "d": "Sacrificar individuos al ''bien social'' ES el crimen definitorio del colectivismo."}}, "fr": {"question": "Pourquoi la loi doit-elle se fonder sur la protection des droits individuels plutôt que sur la promotion du \"bien social\" ?", "options": [{"id": "a", "text": "Les droits individuels sont égoïstes"}, {"id": "b", "text": "Le ''bien social'' est indéfini et peut justifier n''importe quelle violation des droits"}, {"id": "c", "text": "La société n''existe pas"}, {"id": "d", "text": "Le bien social est plus important que les droits"}], "explanation": "Le ''bien social'' n''a pas de définition objective — il signifie ce que les détenteurs du pouvoir disent qu''il signifie. Il a justifié l''esclavage, le génocide et le totalitarisme. Les droits individuels fournissent une limite objective et fondée sur des principes à ce que le gouvernement (ou les majorités) peut faire aux individus.", "wrong_explanations": {"a": "Les droits individuels sont la condition préalable à tout ''bien'' véritable — pour les individus ou la société.", "c": "La société existe en tant que collection d''individus — mais elle n''a pas de droits en dehors des droits individuels.", "d": "Sacrifier les individus au ''bien social'' EST le crime caractéristique du collectivisme."}}}'::jsonb WHERE question = 'Why must law be based on protecting individual rights rather than promoting "social good"?';

-- === SEED FILE 1: AESTHETICS ===

-- Q53
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Qual é o propósito da arte segundo a estética racional?", "options": [{"id": "a", "text": "Confundir e desafiar o espetador"}, {"id": "b", "text": "Concretizar valores abstratos e torná-los percetíveis"}, {"id": "c", "text": "Refletir as falhas da sociedade"}, {"id": "d", "text": "Expressar emoções aleatórias"}], "explanation": "A arte concretiza abstrações — dá forma percetível a valores e ideias abstratos. Uma escultura heroica mostra como é a coragem; uma bela pintura mostra um ideal. A arte torna a filosofia visível, fornecendo combustível emocional para viver.", "wrong_explanations": {"a": "A confusão não é um valor. A arte deve iluminar, não obscurecer.", "c": "A arte PODE criticar, mas o seu propósito mais elevado é apresentar ideais — o que DEVERIA ser.", "d": "Emoções aleatórias produzem resultados aleatórios. A grande arte incorpora valores coerentes."}}, "es": {"question": "¿Cuál es el propósito del arte según la estética racional?", "options": [{"id": "a", "text": "Confundir y desafiar al espectador"}, {"id": "b", "text": "Concretizar valores abstractos y hacerlos perceptibles"}, {"id": "c", "text": "Reflejar las fallas de la sociedad"}, {"id": "d", "text": "Expresar emociones aleatorias"}], "explanation": "El arte concretiza abstracciones — da forma perceptible a valores e ideas abstractos. Una escultura heroica muestra cómo luce el coraje; una bella pintura muestra un ideal. El arte hace visible la filosofía, proporcionando combustible emocional para vivir.", "wrong_explanations": {"a": "La confusión no es un valor. El arte debe iluminar, no oscurecer.", "c": "El arte PUEDE criticar, pero su propósito más elevado es presentar ideales — lo que DEBERÍA ser.", "d": "Las emociones aleatorias producen resultados aleatorios. El gran arte incorpora valores coherentes."}}, "fr": {"question": "Quel est le but de l''art selon l''esthétique rationnelle ?", "options": [{"id": "a", "text": "Confondre et défier le spectateur"}, {"id": "b", "text": "Concrétiser des valeurs abstraites et les rendre perceptibles"}, {"id": "c", "text": "Refléter les défauts de la société"}, {"id": "d", "text": "Exprimer des émotions aléatoires"}], "explanation": "L''art concrétise les abstractions — il donne une forme perceptible aux valeurs et idées abstraites. Une sculpture héroïque montre à quoi ressemble le courage ; un beau tableau montre un idéal. L''art rend la philosophie visible, fournissant un carburant émotionnel pour vivre.", "wrong_explanations": {"a": "La confusion n''est pas une valeur. L''art doit éclairer, pas obscurcir.", "c": "L''art PEUT critiquer, mais son but le plus élevé est de présenter des idéaux — ce qui DEVRAIT être.", "d": "Des émotions aléatoires produisent des résultats aléatoires. Le grand art incarne des valeurs cohérentes."}}}'::jsonb WHERE question = 'What is the purpose of art according to rational aesthetics?';

-- Q54
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que torna a música \"bela\" em termos objetivos?", "options": [{"id": "a", "text": "O que as pessoas gostarem é belo"}, {"id": "b", "text": "Estrutura harmónica, coerência melódica e integração de elementos"}, {"id": "c", "text": "Novidade e quebra de regras"}, {"id": "d", "text": "Sucesso comercial"}], "explanation": "A beleza musical envolve elementos objetivos: relações harmónicas, desenvolvimento melódico, coerência rítmica e integração num todo unificado. Embora a resposta tenha um componente subjetivo, os critérios para avaliar música são objetivos e ensináveis.", "wrong_explanations": {"a": "Popularidade não é igual a qualidade. Muita gente gosta de comida rápida, mas não é nutritiva.", "c": "Quebrar regras pode ser inovador OU apenas ruído. A inovação deve ainda criar valor.", "d": "O sucesso comercial mede popularidade, não mérito estético."}}, "es": {"question": "¿Qué hace que la música sea \"bella\" en términos objetivos?", "options": [{"id": "a", "text": "Lo que la gente guste es bello"}, {"id": "b", "text": "Estructura armónica, coherencia melódica e integración de elementos"}, {"id": "c", "text": "Novedad y ruptura de reglas"}, {"id": "d", "text": "Éxito comercial"}], "explanation": "La belleza musical involucra elementos objetivos: relaciones armónicas, desarrollo melódico, coherencia rítmica e integración en un todo unificado. Aunque la respuesta tiene un componente subjetivo, los criterios para evaluar música son objetivos y enseñables.", "wrong_explanations": {"a": "La popularidad no equivale a calidad. Mucha gente gusta de la comida chatarra, pero no es nutritiva.", "c": "Romper reglas puede ser innovador O simplemente ruido. La innovación debe aún crear valor.", "d": "El éxito comercial mide popularidad, no mérito estético."}}, "fr": {"question": "Qu''est-ce qui rend la musique \"belle\" en termes objectifs ?", "options": [{"id": "a", "text": "Ce que les gens aiment est beau"}, {"id": "b", "text": "La structure harmonique, la cohérence mélodique et l''intégration des éléments"}, {"id": "c", "text": "La nouveauté et la transgression des règles"}, {"id": "d", "text": "Le succès commercial"}], "explanation": "La beauté musicale implique des éléments objectifs : relations harmoniques, développement mélodique, cohérence rythmique et intégration en un tout unifié. Bien que la réponse ait une composante subjective, les critères d''évaluation de la musique sont objectifs et enseignables.", "wrong_explanations": {"a": "La popularité n''est pas la qualité. Beaucoup aiment la malbouffe, mais ce n''est pas nutritif.", "c": "Transgresser les règles peut être innovant OU du bruit. L''innovation doit encore créer de la valeur.", "d": "Le succès commercial mesure la popularité, pas le mérite esthétique."}}}'::jsonb WHERE question = 'What makes music "beautiful" in objective terms?';

-- Q55
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é o \"Realismo Romântico\" na arte?", "options": [{"id": "a", "text": "Arte sobre relações amorosas"}, {"id": "b", "text": "Arte que retrata o mundo como poderia e deveria ser, segundo os seus valores"}, {"id": "c", "text": "Arte de fantasia sem regras"}, {"id": "d", "text": "Cópia estrita da natureza"}], "explanation": "O Realismo Romântico retrata o mundo como poderia e deveria ser — mostrando o potencial humano e ideais, ao mesmo tempo fundamentado no real. Combina o compromisso do Realismo com retratar a realidade com o foco do Romantismo nos valores e na realização humana.", "wrong_explanations": {"a": "O ''Romântico'' refere-se ao movimento artístico que enfatiza valores, não romances.", "c": "O Realismo Romântico é fundamentado na realidade e racionalidade, não fantasia arbitrária.", "d": "A mera cópia (Naturalismo) omite o elemento seletivo e carregado de valores essencial à arte."}}, "es": {"question": "¿Qué es el \"Realismo Romántico\" en el arte?", "options": [{"id": "a", "text": "Arte sobre relaciones amorosas"}, {"id": "b", "text": "Arte que retrata el mundo como podría y debería ser, según los valores de uno"}, {"id": "c", "text": "Arte de fantasía sin reglas"}, {"id": "d", "text": "Copia estricta de la naturaleza"}], "explanation": "El Realismo Romántico retrata el mundo como podría y debería ser — mostrando el potencial humano e ideales mientras está fundamentado en lo real. Combina el compromiso del Realismo con retratar la realidad con el enfoque del Romanticismo en los valores y el logro humano.", "wrong_explanations": {"a": "Lo ''Romántico'' se refiere al movimiento artístico que enfatiza valores, no novelas románticas.", "c": "El Realismo Romántico está fundamentado en la realidad y la racionalidad, no en fantasía arbitraria.", "d": "La mera copia (Naturalismo) omite el elemento selectivo y cargado de valores esencial al arte."}}, "fr": {"question": "Qu''est-ce que le \"Réalisme Romantique\" en art ?", "options": [{"id": "a", "text": "L''art des relations amoureuses"}, {"id": "b", "text": "L''art dépeignant le monde tel qu''il pourrait et devrait être, selon ses valeurs"}, {"id": "c", "text": "L''art fantaisiste sans règles"}, {"id": "d", "text": "La copie stricte de la nature"}], "explanation": "Le Réalisme Romantique dépeint le monde tel qu''il pourrait et devrait être — montrant le potentiel humain et les idéaux tout en restant ancré dans le réel. Il combine l''engagement du Réalisme à dépeindre la réalité avec l''accent du Romantisme sur les valeurs et l''accomplissement humain.", "wrong_explanations": {"a": "Le ''Romantique'' fait référence au mouvement artistique mettant l''accent sur les valeurs, pas aux romans d''amour.", "c": "Le Réalisme Romantique est ancré dans la réalité et la rationalité, pas dans la fantaisie arbitraire.", "d": "La simple copie (Naturalisme) omet l''élément sélectif et chargé de valeurs essentiel à l''art."}}}'::jsonb WHERE question = 'What is "Romantic Realism" in art?';

-- === SEED FILE 1: MUSIC ===

-- Q56
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que \"My Way\" de Frank Sinatra encarna a ética individualista?", "options": [{"id": "a", "text": "Porque é uma canção popular"}, {"id": "b", "text": "Celebra viver pelo próprio julgamento e assumir responsabilidade pelas escolhas"}, {"id": "c", "text": "Promove o isolamento dos outros"}, {"id": "d", "text": "Rejeita toda autoridade"}], "explanation": "\"My Way\" é um hino ao individualismo: ''I did it my way'' celebra viver autenticamente pelos próprios valores e julgamento, aceitando tanto triunfos como arrependimentos como seus. É sobre a autoria da própria vida, não isolamento ou rebelião.", "wrong_explanations": {"a": "A popularidade não determina o conteúdo filosófico.", "c": "A canção não defende o isolamento — defende a autenticidade em como se vive.", "d": "Não é sobre rejeitar autoridade mas sobre assumir a responsabilidade das suas escolhas de vida."}}, "es": {"question": "¿Por qué \"My Way\" de Frank Sinatra encarna la ética individualista?", "options": [{"id": "a", "text": "Porque es una canción popular"}, {"id": "b", "text": "Celebra vivir por el propio juicio y asumir responsabilidad por las elecciones"}, {"id": "c", "text": "Promueve el aislamiento de los demás"}, {"id": "d", "text": "Rechaza toda autoridad"}], "explanation": "\"My Way\" es un himno al individualismo: ''I did it my way'' celebra vivir auténticamente por los propios valores y juicio, aceptando tanto triunfos como arrepentimientos como propios. Se trata de la autoría de la propia vida, no del aislamiento o la rebelión.", "wrong_explanations": {"a": "La popularidad no determina el contenido filosófico.", "c": "La canción no defiende el aislamiento — defiende la autenticidad en cómo se vive.", "d": "No se trata de rechazar la autoridad sino de asumir la responsabilidad de tus elecciones de vida."}}, "fr": {"question": "Pourquoi \"My Way\" de Frank Sinatra incarne-t-il l''éthique individualiste ?", "options": [{"id": "a", "text": "Parce que c''est une chanson populaire"}, {"id": "b", "text": "Elle célèbre le fait de vivre selon son propre jugement et d''assumer ses choix"}, {"id": "c", "text": "Elle promeut l''isolement des autres"}, {"id": "d", "text": "Elle rejette toute autorité"}], "explanation": "\"My Way\" est un hymne à l''individualisme : ''I did it my way'' célèbre le fait de vivre authentiquement selon ses propres valeurs et jugement, acceptant triomphes et regrets comme les siens. C''est l''auto-création de sa vie, pas l''isolement ou la rébellion.", "wrong_explanations": {"a": "La popularité ne détermine pas le contenu philosophique.", "c": "La chanson ne prône pas l''isolement — elle prône l''authenticité dans la façon dont on vit.", "d": "Il ne s''agit pas de rejeter l''autorité mais d''assumer la responsabilité de ses choix de vie."}}}'::jsonb WHERE question = 'Why does "My Way" by Frank Sinatra embody individualist ethics?';

-- Q57
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Que erro filosófico promove \"Imagine\" de John Lennon?", "options": [{"id": "a", "text": "Nenhum — é uma filosofia perfeita"}, {"id": "b", "text": "Coletivismo e a eliminação da propriedade privada"}, {"id": "c", "text": "Extremismo religioso"}, {"id": "d", "text": "Individualismo excessivo"}], "explanation": "\"Imagine no possessions\" promove a eliminação da propriedade privada — um ideal comunista que leva à pobreza e tirania. \"No countries\" elimina as entidades políticas que protegem direitos. Embora a melodia seja bela, as ideias são destrutivas.", "wrong_explanations": {"a": "A canção promove ideias que causaram sofrimento em massa quando implementadas.", "c": "A canção explicitamente imagina ''no religion'' — é antirreligiosa, não religiosamente extrema.", "d": "A canção promove o oposto: dissolver a identidade individual numa ''fraternidade'' coletiva."}}, "es": {"question": "¿Qué error filosófico promueve \"Imagine\" de John Lennon?", "options": [{"id": "a", "text": "Ninguno — es una filosofía perfecta"}, {"id": "b", "text": "Colectivismo y la eliminación de la propiedad privada"}, {"id": "c", "text": "Extremismo religioso"}, {"id": "d", "text": "Individualismo excesivo"}], "explanation": "\"Imagine no possessions\" promueve la eliminación de la propiedad privada — un ideal comunista que lleva a la pobreza y la tiranía. \"No countries\" elimina las entidades políticas que protegen derechos. Aunque la melodía es bella, las ideas son destructivas.", "wrong_explanations": {"a": "La canción promueve ideas que causaron sufrimiento masivo cuando se implementaron.", "c": "La canción explícitamente imagina ''no religion'' — es antirreligiosa, no religiosamente extrema.", "d": "La canción promueve lo opuesto: disolver la identidad individual en una ''hermandad'' colectiva."}}, "fr": {"question": "Quelle erreur philosophique promeut \"Imagine\" de John Lennon ?", "options": [{"id": "a", "text": "Aucune — c''est une philosophie parfaite"}, {"id": "b", "text": "Le collectivisme et l''élimination de la propriété privée"}, {"id": "c", "text": "L''extrémisme religieux"}, {"id": "d", "text": "L''individualisme excessif"}], "explanation": "\"Imagine no possessions\" promeut l''élimination de la propriété privée — un idéal communiste qui mène à la pauvreté et à la tyrannie. \"No countries\" élimine les entités politiques qui protègent les droits. Bien que la mélodie soit belle, les idées sont destructrices.", "wrong_explanations": {"a": "La chanson promeut des idées qui ont causé des souffrances massives une fois mises en œuvre.", "c": "La chanson imagine explicitement ''no religion'' — elle est antireligieuse, pas extrémiste religieuse.", "d": "La chanson promeut l''opposé : dissoudre l''identité individuelle dans une ''fraternité'' collective."}}}'::jsonb WHERE question = 'What philosophical error does "Imagine" by John Lennon promote?';

-- Q58
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que muitas \"canções de protesto\" contra o capitalismo se autorrefutam filosoficamente?", "options": [{"id": "a", "text": "Não se autorrefutam — fazem pontos válidos"}, {"id": "b", "text": "Os artistas lucram vendendo música no sistema capitalista que condenam"}, {"id": "c", "text": "Canções de protesto são sempre fracassos artísticos"}, {"id": "d", "text": "A indústria musical censura mensagens anticapitalistas"}], "explanation": "Artistas que escrevem canções anticapitalistas, depois vendem-nas com lucro, gozam de proteção de direitos de autor e enriquecem, são contradições vivas. Condenam o sistema que permite o seu sucesso. As suas ações (trocar valor por valor) contradizem as suas crenças declaradas.", "wrong_explanations": {"a": "A contradição filosófica existe independentemente de quaisquer outros pontos feitos.", "c": "Algumas canções de protesto são artisticamente excelentes — a questão é a inconsistência filosófica.", "d": "O oposto é verdade — o ''anti-establishment'' vende bem, provando que o capitalismo serve até os seus críticos."}}, "es": {"question": "¿Por qué muchas \"canciones de protesta\" contra el capitalismo se autorrefutan filosóficamente?", "options": [{"id": "a", "text": "No se autorrefutan — hacen puntos válidos"}, {"id": "b", "text": "Los artistas lucran vendiendo música en el sistema capitalista que condenan"}, {"id": "c", "text": "Las canciones de protesta siempre son fracasos artísticos"}, {"id": "d", "text": "La industria musical censura mensajes anticapitalistas"}], "explanation": "Artistas que escriben canciones anticapitalistas, luego las venden con ganancia, gozan de protección de derechos de autor y se enriquecen, son contradicciones vivientes. Condenan el sistema que permite su éxito. Sus acciones (intercambiar valor por valor) contradicen sus creencias declaradas.", "wrong_explanations": {"a": "La contradicción filosófica existe independientemente de cualquier otro punto hecho.", "c": "Algunas canciones de protesta son artísticamente excelentes — la cuestión es la inconsistencia filosófica.", "d": "Lo opuesto es verdad — lo ''anti-establishment'' vende bien, probando que el capitalismo sirve hasta a sus críticos."}}, "fr": {"question": "Pourquoi beaucoup de \"chansons de protestation\" contre le capitalisme s''auto-réfutent-elles philosophiquement ?", "options": [{"id": "a", "text": "Elles ne s''auto-réfutent pas — elles font des points valides"}, {"id": "b", "text": "Les artistes profitent de la vente de musique dans le système capitaliste qu''ils condamnent"}, {"id": "c", "text": "Les chansons de protestation sont toujours des échecs artistiques"}, {"id": "d", "text": "L''industrie musicale censure les messages anticapitalistes"}], "explanation": "Les artistes qui écrivent des chansons anticapitalistes, puis les vendent avec profit, bénéficient de la protection des droits d''auteur et s''enrichissent, sont des contradictions vivantes. Ils condamnent le système qui permet leur succès. Leurs actions (échanger valeur contre valeur) contredisent leurs croyances déclarées.", "wrong_explanations": {"a": "La contradiction philosophique existe indépendamment de tout autre point avancé.", "c": "Certaines chansons de protestation sont artistiquement excellentes — le problème est l''incohérence philosophique.", "d": "C''est l''inverse — l''anti-establishment se vend bien, prouvant que le capitalisme sert même ses critiques."}}}'::jsonb WHERE question = 'Why do many "protest songs" against capitalism philosophically self-refute?';

-- === SEED FILE 1: CINEMA ===

-- Q59
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que \"The Fountainhead\" (1949) é filosoficamente significativo?", "options": [{"id": "a", "text": "Foi um sucesso de bilheteira"}, {"id": "b", "text": "Dramatiza o conflito entre individualismo e coletivismo"}, {"id": "c", "text": "Tem efeitos especiais impressionantes"}, {"id": "d", "text": "Critica o capitalismo"}], "explanation": "\"The Fountainhead\" dramatiza a filosofia de Ayn Rand através do arquiteto Howard Roark: integridade vs. conformismo, criação vs. parasitismo, o indivíduo vs. o coletivo. Roark recusa comprometer a sua visão por aprovação, encarnando o homem independente heroico.", "wrong_explanations": {"a": "O sucesso de bilheteira não determina o significado filosófico.", "c": "É um drama de personagens, não um filme de efeitos especiais.", "d": "O filme DEFENDE o individualismo e implicitamente o capitalismo — não os critica."}}, "es": {"question": "¿Por qué \"The Fountainhead\" (1949) es filosóficamente significativo?", "options": [{"id": "a", "text": "Fue un éxito de taquilla"}, {"id": "b", "text": "Dramatiza el conflicto entre individualismo y colectivismo"}, {"id": "c", "text": "Tiene efectos especiales impresionantes"}, {"id": "d", "text": "Critica el capitalismo"}], "explanation": "\"The Fountainhead\" dramatiza la filosofía de Ayn Rand a través del arquitecto Howard Roark: integridad vs. conformismo, creación vs. parasitismo, el individuo vs. el colectivo. Roark se niega a comprometer su visión por aprobación, encarnando al hombre independiente heroico.", "wrong_explanations": {"a": "El éxito de taquilla no determina el significado filosófico.", "c": "Es un drama de personajes, no una película de efectos especiales.", "d": "La película DEFIENDE el individualismo e implícitamente el capitalismo — no los critica."}}, "fr": {"question": "Pourquoi \"The Fountainhead\" (1949) est-il philosophiquement significatif ?", "options": [{"id": "a", "text": "Ce fut un succès au box-office"}, {"id": "b", "text": "Il dramatise le conflit entre individualisme et collectivisme"}, {"id": "c", "text": "Il a des effets spéciaux impressionnants"}, {"id": "d", "text": "Il critique le capitalisme"}], "explanation": "\"The Fountainhead\" dramatise la philosophie d''Ayn Rand à travers l''architecte Howard Roark : intégrité vs. conformisme, création vs. parasitisme, l''individu vs. le collectif. Roark refuse de compromettre sa vision pour obtenir l''approbation, incarnant l''homme indépendant héroïque.", "wrong_explanations": {"a": "Le succès au box-office ne détermine pas la signification philosophique.", "c": "C''est un drame de personnages, pas un film d''effets spéciaux.", "d": "Le film DÉFEND l''individualisme et implicitement le capitalisme — il ne les critique pas."}}}'::jsonb WHERE question = 'Why is "The Fountainhead" (1949) philosophically significant?';

-- Q60
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que argumenta o filme \"Gattaca\" (1997) sobre a natureza humana e o determinismo?", "options": [{"id": "a", "text": "A genética determina completamente o destino"}, {"id": "b", "text": "A vontade e o espírito humano podem superar limitações genéticas"}, {"id": "c", "text": "A engenharia genética é totalmente benéfica"}, {"id": "d", "text": "A natureza é mais importante que a educação"}], "explanation": "\"Gattaca\" mostra Vincent, geneticamente ''inferior'', a alcançar os seus sonhos através de vontade, esforço e determinação — enquanto o seu irmão geneticamente ''superior'' fracassa. O filme afirma a agência e espírito humano sobre o determinismo genético. As suas escolhas importam mais que os seus genes.", "wrong_explanations": {"a": "Todo o enredo refuta o determinismo genético — Vincent tem sucesso apesar dos genes ''inferiores''.", "c": "O filme critica uma sociedade que depende excessivamente da engenharia genética.", "d": "O filme argumenta o oposto: a educação (vontade, escolhas) transcende a natureza (genética)."}}, "es": {"question": "¿Qué argumenta la película \"Gattaca\" (1997) sobre la naturaleza humana y el determinismo?", "options": [{"id": "a", "text": "La genética determina completamente el destino"}, {"id": "b", "text": "La voluntad y el espíritu humano pueden superar las limitaciones genéticas"}, {"id": "c", "text": "La ingeniería genética es totalmente beneficiosa"}, {"id": "d", "text": "La naturaleza es más importante que la crianza"}], "explanation": "\"Gattaca\" muestra a Vincent, genéticamente ''inferior'', alcanzando sus sueños a través de voluntad, esfuerzo y determinación — mientras su hermano genéticamente ''superior'' fracasa. La película afirma la agencia y el espíritu humano sobre el determinismo genético. Tus elecciones importan más que tus genes.", "wrong_explanations": {"a": "Toda la trama refuta el determinismo genético — Vincent triunfa a pesar de genes ''inferiores''.", "c": "La película critica una sociedad que depende excesivamente de la ingeniería genética.", "d": "La película argumenta lo opuesto: la crianza (voluntad, elecciones) trasciende la naturaleza (genética)."}}, "fr": {"question": "Que défend le film \"Bienvenue à Gattaca\" (1997) sur la nature humaine et le déterminisme ?", "options": [{"id": "a", "text": "La génétique détermine complètement le destin"}, {"id": "b", "text": "La volonté et l''esprit humain peuvent surmonter les limitations génétiques"}, {"id": "c", "text": "L''ingénierie génétique est entièrement bénéfique"}, {"id": "d", "text": "La nature est plus importante que l''éducation"}], "explanation": "\"Gattaca\" montre Vincent, génétiquement ''inférieur'', réalisant ses rêves par la volonté, l''effort et la détermination — tandis que son frère génétiquement ''supérieur'' échoue. Le film affirme l''agence et l''esprit humain face au déterminisme génétique. Vos choix comptent plus que vos gènes.", "wrong_explanations": {"a": "Toute l''intrigue réfute le déterminisme génétique — Vincent réussit malgré des gènes ''inférieurs''.", "c": "Le film critique une société qui dépend excessivement de l''ingénierie génétique.", "d": "Le film argumente l''inverse : l''acquis (volonté, choix) transcende l''inné (génétique)."}}}'::jsonb WHERE question = 'What does the film "Gattaca" (1997) argue about human nature and determinism?';

-- Q61
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que \"Atlas Shrugged\" (os filmes) tem dificuldade em captar as ideias do romance?", "options": [{"id": "a", "text": "As ideias estão erradas"}, {"id": "b", "text": "A filosofia requer diálogos extensos e introspeção difícil de filmar"}, {"id": "c", "text": "Hollywood deliberadamente os sabotou"}, {"id": "d", "text": "O romance não é interessante"}], "explanation": "Os romances filosóficos de Rand funcionam através de extensos monólogos internos, longos discursos (o discurso de Galt tem 60 páginas) e desenvolvimento gradual de ideias complexas. O cinema é um meio visual adequado à ação, não à exposição filosófica prolongada. O meio não se adequa ao conteúdo.", "wrong_explanations": {"a": "Se as ideias estão certas ou erradas não explica a dificuldade de adaptação.", "c": "Os filmes foram produzidos independentemente por apoiantes do romance.", "d": "O romance tem milhões de leitores apaixonados — claramente é interessante para muitos."}}, "es": {"question": "¿Por qué \"La Rebelión de Atlas\" (las películas) tiene dificultades para captar las ideas de la novela?", "options": [{"id": "a", "text": "Las ideas están equivocadas"}, {"id": "b", "text": "La filosofía requiere diálogos extensos e introspección difícil de filmar"}, {"id": "c", "text": "Hollywood deliberadamente las saboteó"}, {"id": "d", "text": "La novela no es interesante"}], "explanation": "Las novelas filosóficas de Rand funcionan a través de extensos monólogos internos, largos discursos (el discurso de Galt tiene 60 páginas) y desarrollo gradual de ideas complejas. El cine es un medio visual adecuado para la acción, no para la exposición filosófica prolongada. El medio no se adecua al contenido.", "wrong_explanations": {"a": "Si las ideas son correctas o no, no explica la dificultad de adaptación.", "c": "Las películas fueron producidas independientemente por simpatizantes de la novela.", "d": "La novela tiene millones de lectores apasionados — claramente es interesante para muchos."}}, "fr": {"question": "Pourquoi les films \"La Grève\" peinent-ils à capturer les idées du roman ?", "options": [{"id": "a", "text": "Les idées sont fausses"}, {"id": "b", "text": "La philosophie nécessite des dialogues étendus et une introspection difficiles à filmer"}, {"id": "c", "text": "Hollywood les a délibérément sabotés"}, {"id": "d", "text": "Le roman n''est pas intéressant"}], "explanation": "Les romans philosophiques de Rand fonctionnent par de longs monologues intérieurs, de longs discours (le discours de Galt fait 60 pages) et le développement progressif d''idées complexes. Le cinéma est un média visuel adapté à l''action, pas à l''exposition philosophique prolongée. Le média ne convient pas au contenu.", "wrong_explanations": {"a": "Que les idées soient justes ou non n''explique pas la difficulté d''adaptation.", "c": "Les films ont été produits indépendamment par des partisans du roman.", "d": "Le roman a des millions de lecteurs passionnés — il est clairement intéressant pour beaucoup."}}}'::jsonb WHERE question = 'Why does "Atlas Shrugged" (the films) struggle to capture the novel''s ideas?';

-- === SEED FILE 1: APPLIED ===

-- Q62
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Como a \"tragédia dos comuns\" ilustra a importância dos direitos de propriedade?", "options": [{"id": "a", "text": "Os comuns sempre funcionam bem"}, {"id": "b", "text": "Sem propriedade privada, recursos partilhados são sobreusados e destruídos"}, {"id": "c", "text": "A propriedade privada causa tragédias"}, {"id": "d", "text": "O governo deve possuir todos os recursos"}], "explanation": "Quando ninguém possui um recurso (terrenos de pastagem comuns, pesca), todos têm incentivo para tirar o máximo possível antes que os outros o façam — esgotando o recurso. A propriedade privada cria incentivo para preservar e melhorar recursos para benefício a longo prazo.", "wrong_explanations": {"a": "Os comuns falham sistematicamente porque os incentivos individuais desalinham com a sustentabilidade coletiva.", "c": "A propriedade privada RESOLVE a tragédia ao alinhar os interesses individuais e dos recursos.", "d": "A propriedade governamental é apenas outra forma de comuns, com os mesmos incentivos perversos."}}, "es": {"question": "¿Cómo ilustra la \"tragedia de los comunes\" la importancia de los derechos de propiedad?", "options": [{"id": "a", "text": "Los comunes siempre funcionan bien"}, {"id": "b", "text": "Sin propiedad privada, los recursos compartidos son sobreexplotados y destruidos"}, {"id": "c", "text": "La propiedad privada causa tragedias"}, {"id": "d", "text": "El gobierno debe poseer todos los recursos"}], "explanation": "Cuando nadie posee un recurso (tierras de pastoreo comunes, pesca), todos tienen incentivo para tomar lo máximo posible antes que los demás — agotando el recurso. La propiedad privada crea incentivo para preservar y mejorar recursos para beneficio a largo plazo.", "wrong_explanations": {"a": "Los comunes fracasan sistemáticamente porque los incentivos individuales se desalinean con la sostenibilidad colectiva.", "c": "La propiedad privada RESUELVE la tragedia al alinear los intereses individuales y de los recursos.", "d": "La propiedad gubernamental es solo otra forma de comunes, con los mismos incentivos perversos."}}, "fr": {"question": "Comment la \"tragédie des communs\" illustre-t-elle l''importance des droits de propriété ?", "options": [{"id": "a", "text": "Les communs fonctionnent toujours bien"}, {"id": "b", "text": "Sans propriété privée, les ressources partagées sont surexploitées et détruites"}, {"id": "c", "text": "La propriété privée cause des tragédies"}, {"id": "d", "text": "Le gouvernement devrait posséder toutes les ressources"}], "explanation": "Quand personne ne possède une ressource (pâturages communs, pêcheries), chacun a intérêt à prendre le maximum avant les autres — épuisant la ressource. La propriété privée crée l''incitation à préserver et améliorer les ressources pour un bénéfice à long terme.", "wrong_explanations": {"a": "Les communs échouent systématiquement car les incitations individuelles sont désalignées avec la durabilité collective.", "c": "La propriété privée RÉSOUT la tragédie en alignant les intérêts individuels et ceux des ressources.", "d": "La propriété gouvernementale n''est qu''une autre forme de communs, avec les mêmes incitations perverses."}}}'::jsonb WHERE question = 'How does the "tragedy of the commons" illustrate the importance of property rights?';

-- Q63
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que as políticas de controlo de rendas falham em ajudar aqueles que pretendem ajudar?", "options": [{"id": "a", "text": "Não falham — proporcionam habitação acessível"}, {"id": "b", "text": "Reduzem a oferta de habitação ao eliminar o incentivo para construir ou manter"}, {"id": "c", "text": "Os senhorios são gananciosos demais para cumprir"}, {"id": "d", "text": "Os controlos não são rigorosos o suficiente"}], "explanation": "O controlo de rendas limita os preços abaixo das taxas de mercado, eliminando o incentivo de lucro para construir novas habitações ou manter as existentes. Resultado: escassez de habitação, edifícios em deterioração e mercado negro. A política prejudica os inquilinos ao reduzir a habitação disponível.", "wrong_explanations": {"a": "Todos os grandes estudos mostram que o controlo de rendas reduz a oferta e qualidade de habitação.", "c": "Os senhorios respondem racionalmente a incentivos — se se retira o lucro, deixam de investir.", "d": "Controlos mais rigorosos agravam o problema ao eliminar ainda mais os incentivos."}}, "es": {"question": "¿Por qué las políticas de control de alquileres fracasan en ayudar a quienes pretenden ayudar?", "options": [{"id": "a", "text": "No fracasan — proporcionan vivienda asequible"}, {"id": "b", "text": "Reducen la oferta de vivienda al eliminar el incentivo para construir o mantener"}, {"id": "c", "text": "Los propietarios son demasiado codiciosos para cumplir"}, {"id": "d", "text": "Los controles no son suficientemente estrictos"}], "explanation": "El control de alquileres limita los precios por debajo de las tasas de mercado, eliminando el incentivo de ganancia para construir nueva vivienda o mantener la existente. Resultado: escasez de vivienda, edificios deteriorados y mercado negro. La política perjudica a los inquilinos al reducir la vivienda disponible.", "wrong_explanations": {"a": "Todos los grandes estudios muestran que el control de alquileres reduce la oferta y calidad de vivienda.", "c": "Los propietarios responden racionalmente a incentivos — si se quita la ganancia, dejan de invertir.", "d": "Controles más estrictos empeoran el problema al eliminar aún más los incentivos."}}, "fr": {"question": "Pourquoi les politiques d''encadrement des loyers échouent-elles à aider ceux qu''elles prétendent aider ?", "options": [{"id": "a", "text": "Elles n''échouent pas — elles fournissent des logements abordables"}, {"id": "b", "text": "Elles réduisent l''offre de logements en éliminant l''incitation à construire ou entretenir"}, {"id": "c", "text": "Les propriétaires sont trop cupides pour se conformer"}, {"id": "d", "text": "Les contrôles ne sont pas assez stricts"}], "explanation": "L''encadrement des loyers plafonne les prix en dessous des taux du marché, éliminant l''incitation au profit pour construire de nouveaux logements ou entretenir les existants. Résultat : pénurie de logements, bâtiments se détériorant et marché noir. La politique nuit aux locataires en réduisant les logements disponibles.", "wrong_explanations": {"a": "Toutes les grandes études montrent que l''encadrement des loyers réduit l''offre et la qualité des logements.", "c": "Les propriétaires répondent rationnellement aux incitations — si on supprime le profit, ils cessent d''investir.", "d": "Des contrôles plus stricts aggravent le problème en éliminant davantage les incitations."}}}'::jsonb WHERE question = 'Why do rent control policies fail to help those they intend to help?';

-- Q64
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é o \"capitalismo de compadrio\" e por que difere do capitalismo?", "options": [{"id": "a", "text": "Capitalismo de compadrio é apenas outro nome para capitalismo"}, {"id": "b", "text": "Capitalismo de compadrio é empresas a usar a força governamental; capitalismo proíbe iniciar a força"}, {"id": "c", "text": "Capitalismo de compadrio ajuda pequenas empresas"}, {"id": "d", "text": "O capitalismo leva sempre ao capitalismo de compadrio"}], "explanation": "O capitalismo de compadrio é empresas a usar o governo para obter vantagens injustas — subsídios, regulações que prejudicam concorrentes, resgates. O verdadeiro capitalismo proíbe o favoritismo governamental: todas as empresas competem pelo mérito em mercados livres. O capitalismo de compadrio é anticapitalista.", "wrong_explanations": {"a": "O capitalismo de compadrio requer intervenção governamental; o capitalismo requer NÃO-intervenção governamental.", "c": "O capitalismo de compadrio ajuda empresas com conexões à custa de concorrentes menores.", "d": "O capitalismo com governo estritamente limitado previne o capitalismo de compadrio ao remover os favores governamentais para vender."}}, "es": {"question": "¿Qué es el \"capitalismo de amiguetes\" y por qué difiere del capitalismo?", "options": [{"id": "a", "text": "El capitalismo de amiguetes es solo otro nombre para capitalismo"}, {"id": "b", "text": "El capitalismo de amiguetes son empresas usando la fuerza gubernamental; el capitalismo prohíbe iniciar la fuerza"}, {"id": "c", "text": "El capitalismo de amiguetes ayuda a las pequeñas empresas"}, {"id": "d", "text": "El capitalismo siempre lleva al capitalismo de amiguetes"}], "explanation": "El capitalismo de amiguetes son empresas que usan al gobierno para obtener ventajas injustas — subsidios, regulaciones que perjudican a competidores, rescates. El verdadero capitalismo prohíbe el favoritismo gubernamental: todas las empresas compiten por mérito en mercados libres. El capitalismo de amiguetes es anticapitalista.", "wrong_explanations": {"a": "El capitalismo de amiguetes requiere intervención gubernamental; el capitalismo requiere NO-intervención gubernamental.", "c": "El capitalismo de amiguetes ayuda a empresas con conexiones a costa de competidores menores.", "d": "El capitalismo con gobierno estrictamente limitado previene el capitalismo de amiguetes al eliminar los favores gubernamentales."}}, "fr": {"question": "Qu''est-ce que le \"capitalisme de copinage\" et pourquoi diffère-t-il du capitalisme ?", "options": [{"id": "a", "text": "Le capitalisme de copinage n''est qu''un autre nom pour le capitalisme"}, {"id": "b", "text": "Le capitalisme de copinage, c''est des entreprises utilisant la force gouvernementale ; le capitalisme interdit l''initiation de la force"}, {"id": "c", "text": "Le capitalisme de copinage aide les petites entreprises"}, {"id": "d", "text": "Le capitalisme mène toujours au capitalisme de copinage"}], "explanation": "Le capitalisme de copinage, c''est des entreprises utilisant le gouvernement pour obtenir des avantages injustes — subventions, réglementations nuisant aux concurrents, sauvetages. Le vrai capitalisme interdit le favoritisme gouvernemental : toutes les entreprises rivalisent au mérite dans des marchés libres. Le copinage est anticapitaliste.", "wrong_explanations": {"a": "Le capitalisme de copinage nécessite l''intervention gouvernementale ; le capitalisme nécessite la NON-intervention.", "c": "Le capitalisme de copinage aide les entreprises connectées aux dépens des petits concurrents.", "d": "Le capitalisme avec un gouvernement strictement limité empêche le copinage en supprimant les faveurs gouvernementales."}}}'::jsonb WHERE question = 'What is "cronyism" and why does it differ from capitalism?';

-- Q65
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que a inflação é um imposto oculto?", "options": [{"id": "a", "text": "Não é — a inflação é natural"}, {"id": "b", "text": "O governo a imprimir dinheiro reduz o poder de compra, transferindo riqueza para o governo"}, {"id": "c", "text": "A inflação ajuda os poupadores"}, {"id": "d", "text": "Apenas a deflação é prejudicial"}], "explanation": "Quando o governo imprime dinheiro, cada nota vale menos. As suas poupanças compram menos; o seu salário compra menos. O governo gasta o novo dinheiro ao valor total enquanto você suporta o custo. É tributação sem legislação — e prejudica mais os mais pobres.", "wrong_explanations": {"a": "A inflação é causada pelo governo a aumentar a oferta monetária — é uma escolha política, não da natureza.", "c": "A inflação destrói os poupadores ao reduzir o valor das suas poupanças.", "d": "Tanto inflação como deflação podem ser prejudiciais, mas a inflação é o problema mais comum causado pelo governo."}}, "es": {"question": "¿Por qué la inflación es un impuesto oculto?", "options": [{"id": "a", "text": "No lo es — la inflación es natural"}, {"id": "b", "text": "El gobierno imprimiendo dinero reduce el poder adquisitivo, transfiriendo riqueza al gobierno"}, {"id": "c", "text": "La inflación ayuda a los ahorradores"}, {"id": "d", "text": "Solo la deflación es perjudicial"}], "explanation": "Cuando el gobierno imprime dinero, cada billete vale menos. Tus ahorros compran menos; tu salario compra menos. El gobierno gasta el nuevo dinero a valor completo mientras tú soportas el costo. Es tributación sin legislación — y perjudica más a los más pobres.", "wrong_explanations": {"a": "La inflación es causada por el gobierno aumentando la oferta monetaria — es una elección política, no de la naturaleza.", "c": "La inflación destruye a los ahorradores al reducir el valor de sus ahorros.", "d": "Tanto inflación como deflación pueden ser perjudiciales, pero la inflación es el problema más común causado por el gobierno."}}, "fr": {"question": "Pourquoi l''inflation est-elle un impôt caché ?", "options": [{"id": "a", "text": "Ce n''en est pas un — l''inflation est naturelle"}, {"id": "b", "text": "Le gouvernement imprimant de l''argent réduit le pouvoir d''achat, transférant la richesse au gouvernement"}, {"id": "c", "text": "L''inflation aide les épargnants"}, {"id": "d", "text": "Seule la déflation est nuisible"}], "explanation": "Quand le gouvernement imprime de l''argent, chaque billet vaut moins. Vos économies achètent moins ; votre salaire achète moins. Le gouvernement dépense le nouvel argent à sa pleine valeur tandis que vous supportez le coût. C''est une taxation sans législation — et elle nuit le plus aux plus pauvres.", "wrong_explanations": {"a": "L''inflation est causée par le gouvernement augmentant la masse monétaire — c''est un choix politique, pas naturel.", "c": "L''inflation détruit les épargnants en réduisant la valeur de leurs économies.", "d": "L''inflation comme la déflation peuvent être nuisibles, mais l''inflation est le problème le plus courant causé par le gouvernement."}}}'::jsonb WHERE question = 'Why is inflation a hidden tax?';

-- Q66
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que significa filosoficamente \"não existe almoço grátis\"?", "options": [{"id": "a", "text": "Os restaurantes devem cobrar por tudo"}, {"id": "b", "text": "Todo benefício tem um custo — alguém sempre paga"}, {"id": "c", "text": "A generosidade é errada"}, {"id": "d", "text": "Os pobres não merecem ajuda"}], "explanation": "Este princípio reconhece que os recursos são escassos e cada uso tem um custo de oportunidade. Programas governamentais ''gratuitos'' são pagos com impostos. Benefícios ''gratuitos'' para um grupo são custos para outro. Compreender isto previne o pensamento fantasioso por trás de más políticas.", "wrong_explanations": {"a": "É uma metáfora sobre economia e política, não conselho literal sobre restaurantes.", "c": "A generosidade voluntária é aceitável — o ponto é que ALGUÉM paga, mesmo pelos presentes.", "d": "O princípio não diz nada sobre quem merece o quê — apenas que os custos existem."}}, "es": {"question": "¿Qué significa filosóficamente \"no existe el almuerzo gratis\"?", "options": [{"id": "a", "text": "Los restaurantes deben cobrar por todo"}, {"id": "b", "text": "Todo beneficio tiene un costo — alguien siempre paga"}, {"id": "c", "text": "La generosidad es incorrecta"}, {"id": "d", "text": "Los pobres no merecen ayuda"}], "explanation": "Este principio reconoce que los recursos son escasos y cada uso tiene un costo de oportunidad. Los programas gubernamentales ''gratuitos'' se pagan con impuestos. Los beneficios ''gratuitos'' para un grupo son costos para otro. Entender esto previene el pensamiento fantasioso detrás de malas políticas.", "wrong_explanations": {"a": "Es una metáfora sobre economía y política, no consejo literal sobre restaurantes.", "c": "La generosidad voluntaria está bien — el punto es que ALGUIEN paga, incluso por los regalos.", "d": "El principio no dice nada sobre quién merece qué — solo que los costos existen."}}, "fr": {"question": "Que signifie philosophiquement \"il n''y a pas de repas gratuit\" ?", "options": [{"id": "a", "text": "Les restaurants devraient tout facturer"}, {"id": "b", "text": "Tout avantage a un coût — quelqu''un paie toujours"}, {"id": "c", "text": "La générosité est mauvaise"}, {"id": "d", "text": "Les pauvres ne méritent pas d''aide"}], "explanation": "Ce principe reconnaît que les ressources sont rares et que chaque utilisation a un coût d''opportunité. Les programmes gouvernementaux ''gratuits'' sont payés par les impôts. Les avantages ''gratuits'' pour un groupe sont des coûts pour un autre. Comprendre cela empêche la pensée magique derrière les mauvaises politiques.", "wrong_explanations": {"a": "C''est une métaphore sur l''économie et la politique, pas un conseil littéral sur les restaurants.", "c": "La générosité volontaire est acceptable — le point est que QUELQU''UN paie, même pour les cadeaux.", "d": "Le principe ne dit rien sur qui mérite quoi — seulement que les coûts existent."}}}'::jsonb WHERE question = 'What does "there''s no such thing as a free lunch" mean philosophically?';

-- === SEED FILE 1: DIFFICULTY 8-10 ===

-- Q67
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a falácia do \"conceito roubado\"?", "options": [{"id": "a", "text": "Usar palavras sem as definir"}, {"id": "b", "text": "Usar um conceito enquanto se nega os conceitos dos quais depende"}, {"id": "c", "text": "Copiar as ideias de outra pessoa"}, {"id": "d", "text": "Usar jargão técnico para confundir"}], "explanation": "A falácia do conceito roubado usa um conceito enquanto nega os seus fundamentos. Exemplo: ''Não existe verdade'' rouba ''verdade'' enquanto a nega. ''Os direitos não existem'' usa ''direitos'' ao fazer a afirmação. A negação pressupõe o que nega.", "wrong_explanations": {"a": "A vagueza é um problema diferente. O conceito roubado é mais específico.", "c": "Isso seria plágio, não uma falácia lógica.", "d": "A ofuscação é uma tática retórica, não esta falácia específica."}}, "es": {"question": "¿Qué es la falacia del \"concepto robado\"?", "options": [{"id": "a", "text": "Usar palabras sin definirlas"}, {"id": "b", "text": "Usar un concepto mientras se niegan los conceptos de los que depende"}, {"id": "c", "text": "Copiar las ideas de otra persona"}, {"id": "d", "text": "Usar jerga técnica para confundir"}], "explanation": "La falacia del concepto robado usa un concepto mientras niega sus fundamentos. Ejemplo: ''No existe la verdad'' roba ''verdad'' mientras la niega. ''Los derechos no existen'' usa ''derechos'' al hacer la afirmación. La negación presupone lo que niega.", "wrong_explanations": {"a": "La vaguedad es un problema diferente. El concepto robado es más específico.", "c": "Eso sería plagio, no una falacia lógica.", "d": "La ofuscación es una táctica retórica, no esta falacia específica."}}, "fr": {"question": "Qu''est-ce que le sophisme du \"concept volé\" ?", "options": [{"id": "a", "text": "Utiliser des mots sans les définir"}, {"id": "b", "text": "Utiliser un concept tout en niant les concepts dont il dépend"}, {"id": "c", "text": "Copier les idées de quelqu''un d''autre"}, {"id": "d", "text": "Utiliser du jargon technique pour confondre"}], "explanation": "Le sophisme du concept volé utilise un concept tout en niant ses fondements. Exemple : ''Il n''y a pas de vérité'' vole ''vérité'' tout en la niant. ''Les droits n''existent pas'' utilise ''droits'' en faisant l''affirmation. La négation présuppose ce qu''elle nie.", "wrong_explanations": {"a": "Le flou est un problème différent. Le concept volé est plus spécifique.", "c": "Ce serait du plagiat, pas un sophisme logique.", "d": "L''obscurcissement est une tactique rhétorique, pas ce sophisme spécifique."}}}'::jsonb WHERE question = 'What is the "stolen concept" fallacy?';

-- Q68
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a \"falácia da reificação\" (ou hipostatização)?", "options": [{"id": "a", "text": "Tratar coisas concretas como abstratas"}, {"id": "b", "text": "Tratar uma abstração como se fosse uma entidade concreta com poderes causais"}, {"id": "c", "text": "Usar demasiados conceitos abstratos"}, {"id": "d", "text": "Falhar em abstrair dos concretos"}], "explanation": "A reificação trata abstrações como se fossem coisas concretas que podem agir. ''A sociedade exige'' ou ''A história mostra'' tratam sociedade e história como agentes. Mas apenas indivíduos agem. Abstrações são ferramentas mentais, não entidades com poder causal.", "wrong_explanations": {"a": "Isso seria o erro oposto.", "c": "Usar abstrações é correto; tratá-las como entidades concretas é o erro.", "d": "A falha em abstrair é uma fraqueza epistemológica, não esta falácia específica."}}, "es": {"question": "¿Qué es la \"falacia de reificación\" (o hipostatización)?", "options": [{"id": "a", "text": "Tratar cosas concretas como abstractas"}, {"id": "b", "text": "Tratar una abstracción como si fuera una entidad concreta con poderes causales"}, {"id": "c", "text": "Usar demasiados conceptos abstractos"}, {"id": "d", "text": "Fallar en abstraer de los concretos"}], "explanation": "La reificación trata las abstracciones como si fueran cosas concretas que pueden actuar. ''La sociedad exige'' o ''La historia muestra'' tratan a la sociedad y la historia como agentes. Pero solo los individuos actúan. Las abstracciones son herramientas mentales, no entidades con poder causal.", "wrong_explanations": {"a": "Eso sería el error opuesto.", "c": "Usar abstracciones es correcto; tratarlas como entidades concretas es el error.", "d": "La falla en abstraer es una debilidad epistemológica, no esta falacia específica."}}, "fr": {"question": "Qu''est-ce que le \"sophisme de réification\" (ou hypostasie) ?", "options": [{"id": "a", "text": "Traiter des choses concrètes comme abstraites"}, {"id": "b", "text": "Traiter une abstraction comme si c''était une entité concrète avec des pouvoirs causaux"}, {"id": "c", "text": "Utiliser trop de concepts abstraits"}, {"id": "d", "text": "Échouer à abstraire des concrets"}], "explanation": "La réification traite les abstractions comme si elles étaient des choses concrètes pouvant agir. ''La société exige'' ou ''L''histoire montre'' traitent la société et l''histoire comme des agents. Mais seuls les individus agissent. Les abstractions sont des outils mentaux, pas des entités avec un pouvoir causal.", "wrong_explanations": {"a": "Ce serait l''erreur opposée.", "c": "Utiliser des abstractions est correct ; les traiter comme des entités concrètes est l''erreur.", "d": "L''échec à abstraire est une faiblesse épistémologique, pas ce sophisme spécifique."}}}'::jsonb WHERE question = 'What is the "fallacy of reification" (or hypostatization)?';

-- Q69
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é o \"egoísmo psicológico\" e por que é falso?", "options": [{"id": "a", "text": "A visão de que as pessoas devem ser egoístas"}, {"id": "b", "text": "A afirmação de que as pessoas agem sempre egoisticamente, que é infalsificável"}, {"id": "c", "text": "Uma descrição correta da natureza humana"}, {"id": "d", "text": "O oposto do egoísmo ético"}], "explanation": "O egoísmo psicológico afirma que as pessoas SEMPRE agem egoisticamente — mesmo o altruísmo aparente é ''realmente'' egoísta. Isto é infalsificável: qualquer contra-exemplo é reinterpretado como egoísmo secreto. Esvazia ''egoísta'' de significado. O egoísmo ético (as pessoas DEVEM perseguir o autointeresse) é diferente.", "wrong_explanations": {"a": "Isso é o egoísmo ético (uma afirmação normativa), não o egoísmo psicológico (uma afirmação descritiva).", "c": "Ser infalsificável significa que não é uma afirmação científica testável.", "d": "São relacionados mas diferentes: um descreve, o outro prescreve."}}, "es": {"question": "¿Qué es el \"egoísmo psicológico\" y por qué es falso?", "options": [{"id": "a", "text": "La opinión de que la gente debería ser egoísta"}, {"id": "b", "text": "La afirmación de que la gente siempre actúa egoístamente, que es infalsificable"}, {"id": "c", "text": "Una descripción correcta de la naturaleza humana"}, {"id": "d", "text": "Lo opuesto del egoísmo ético"}], "explanation": "El egoísmo psicológico afirma que la gente SIEMPRE actúa egoístamente — incluso el altruismo aparente es ''realmente'' egoísta. Esto es infalsificable: cualquier contraejemplo se reinterpreta como egoísmo secreto. Vacía de significado ''egoísta''. El egoísmo ético (la gente DEBERÍA perseguir su autointerés) es diferente.", "wrong_explanations": {"a": "Eso es el egoísmo ético (una afirmación normativa), no el egoísmo psicológico (una afirmación descriptiva).", "c": "Ser infalsificable significa que no es una afirmación científica comprobable.", "d": "Están relacionados pero son diferentes: uno describe, el otro prescribe."}}, "fr": {"question": "Qu''est-ce que l''\"égoïsme psychologique\" et pourquoi est-il faux ?", "options": [{"id": "a", "text": "L''idée que les gens devraient être égoïstes"}, {"id": "b", "text": "L''affirmation que les gens agissent toujours égoïstement, qui est infalsifiable"}, {"id": "c", "text": "Une description correcte de la nature humaine"}, {"id": "d", "text": "L''opposé de l''égoïsme éthique"}], "explanation": "L''égoïsme psychologique affirme que les gens agissent TOUJOURS égoïstement — même l''altruisme apparent est ''vraiment'' égoïste. C''est infalsifiable : tout contre-exemple est réinterprété comme égoïsme secret. Cela vide ''égoïste'' de sens. L''égoïsme éthique (les gens DEVRAIENT poursuivre leur intérêt personnel) est différent.", "wrong_explanations": {"a": "C''est l''égoïsme éthique (affirmation normative), pas l''égoïsme psychologique (affirmation descriptive).", "c": "Être infalsifiable signifie que ce n''est pas une affirmation scientifique testable.", "d": "Ils sont liés mais différents : l''un décrit, l''autre prescrit."}}}'::jsonb WHERE question = 'What is "psychological egoism" and why is it false?';

-- Q70
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a \"presunção fatal\" segundo F.A. Hayek?", "options": [{"id": "a", "text": "Acreditar nos direitos individuais"}, {"id": "b", "text": "Presumir que os planeadores centrais podem possuir o conhecimento disperso necessário para gerir uma economia"}, {"id": "c", "text": "Apoiar mercados livres"}, {"id": "d", "text": "Confiar nos processos democráticos"}], "explanation": "A ''presunção fatal'' de Hayek é a crença de que uma autoridade central pode possuir o conhecimento disperso entre milhões de indivíduos e coordenar a atividade económica melhor que os mercados. Este conhecimento é local, tácito e em constante mudança — nenhum planeador pode acedê-lo.", "wrong_explanations": {"a": "Hayek defendia os direitos individuais — isso não é a presunção.", "c": "Hayek defendia os mercados livres contra a presunção fatal do planeamento.", "d": "A democracia é separada do planeamento económico."}}, "es": {"question": "¿Qué es la \"fatal arrogancia\" según F.A. Hayek?", "options": [{"id": "a", "text": "Creer en los derechos individuales"}, {"id": "b", "text": "Suponer que los planificadores centrales pueden poseer el conocimiento disperso necesario para gestionar una economía"}, {"id": "c", "text": "Apoyar los mercados libres"}, {"id": "d", "text": "Confiar en los procesos democráticos"}], "explanation": "La ''fatal arrogancia'' de Hayek es la creencia de que una autoridad central puede poseer el conocimiento disperso entre millones de individuos y coordinar la actividad económica mejor que los mercados. Este conocimiento es local, tácito y cambiante — ningún planificador puede acceder a él.", "wrong_explanations": {"a": "Hayek defendía los derechos individuales — eso no es la arrogancia.", "c": "Hayek defendía los mercados libres contra la fatal arrogancia de la planificación.", "d": "La democracia es separada de la planificación económica."}}, "fr": {"question": "Qu''est-ce que la \"présomption fatale\" selon F.A. Hayek ?", "options": [{"id": "a", "text": "Croire aux droits individuels"}, {"id": "b", "text": "Supposer que les planificateurs centraux peuvent détenir la connaissance dispersée nécessaire pour gérer une économie"}, {"id": "c", "text": "Soutenir les marchés libres"}, {"id": "d", "text": "Faire confiance aux processus démocratiques"}], "explanation": "La ''présomption fatale'' de Hayek est la croyance qu''une autorité centrale peut posséder la connaissance dispersée parmi des millions d''individus et coordonner l''activité économique mieux que les marchés. Cette connaissance est locale, tacite et en changement constant — aucun planificateur ne peut y accéder.", "wrong_explanations": {"a": "Hayek défendait les droits individuels — ce n''est pas la présomption.", "c": "Hayek défendait les marchés libres contre la présomption fatale de la planification.", "d": "La démocratie est distincte de la planification économique."}}}'::jsonb WHERE question = 'What is the "fatal conceit" according to F.A. Hayek?';

-- Q71
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Que erro filosófico cometeu a constituição da República de Weimar que permitiu Hitler?", "options": [{"id": "a", "text": "Demasiada proteção dos direitos individuais"}, {"id": "b", "text": "O Artigo 48 permitia a suspensão de emergência dos direitos, possibilitando a ditadura"}, {"id": "c", "text": "Participação democrática insuficiente"}, {"id": "d", "text": "Capitalismo excessivo"}], "explanation": "O Artigo 48 permitia ao presidente suspender as liberdades civis em emergências. Hitler usou este ''poder de emergência'' para abolir legalmente os direitos após o incêndio do Reichstag. Direitos constitucionais que podem ser suspensos não são direitos — são permissões.", "wrong_explanations": {"a": "O problema era que os direitos PODIAM ser suspensos, não que estavam demasiado protegidos.", "c": "A Alemanha tinha democracia extensiva — o problema eram limites constitucionais inadequados.", "d": "A Alemanha de Weimar tinha extensiva intervenção governamental, não capitalismo laissez-faire."}}, "es": {"question": "¿Qué error filosófico cometió la constitución de la República de Weimar que permitió a Hitler?", "options": [{"id": "a", "text": "Demasiada protección de los derechos individuales"}, {"id": "b", "text": "El Artículo 48 permitía la suspensión de emergencia de derechos, posibilitando la dictadura"}, {"id": "c", "text": "Participación democrática insuficiente"}, {"id": "d", "text": "Capitalismo excesivo"}], "explanation": "El Artículo 48 permitía al presidente suspender las libertades civiles en emergencias. Hitler usó este ''poder de emergencia'' para abolir legalmente los derechos después del incendio del Reichstag. Los derechos constitucionales que pueden suspenderse no son derechos — son permisos.", "wrong_explanations": {"a": "El problema era que los derechos PODÍAN ser suspendidos, no que estaban demasiado protegidos.", "c": "Alemania tenía amplia democracia — el problema eran límites constitucionales inadecuados.", "d": "La Alemania de Weimar tenía amplia intervención gubernamental, no capitalismo laissez-faire."}}, "fr": {"question": "Quelle erreur philosophique de la constitution de la République de Weimar a permis Hitler ?", "options": [{"id": "a", "text": "Trop de protection des droits individuels"}, {"id": "b", "text": "L''Article 48 permettait la suspension d''urgence des droits, rendant la dictature possible"}, {"id": "c", "text": "Participation démocratique insuffisante"}, {"id": "d", "text": "Capitalisme excessif"}], "explanation": "L''Article 48 permettait au président de suspendre les libertés civiles en cas d''urgence. Hitler a utilisé ce ''pouvoir d''urgence'' pour abolir légalement les droits après l''incendie du Reichstag. Des droits constitutionnels pouvant être suspendus ne sont pas des droits — ce sont des permissions.", "wrong_explanations": {"a": "Le problème était que les droits POUVAIENT être suspendus, pas qu''ils étaient trop protégés.", "c": "L''Allemagne avait une démocratie étendue — le problème était des limites constitutionnelles inadéquates.", "d": "L''Allemagne de Weimar avait une intervention gouvernementale étendue, pas un capitalisme laissez-faire."}}}'::jsonb WHERE question = 'What philosophical error did the Weimar Republic''s constitution make that enabled Hitler?';

-- Q72
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a \"captura regulatória\"?", "options": [{"id": "a", "text": "Quando as regulações se tornam demasiado rigorosas"}, {"id": "b", "text": "Quando as indústrias reguladas controlam as agências que deveriam regulá-las"}, {"id": "c", "text": "Quando o governo captura empresas privadas"}, {"id": "d", "text": "Quando as regulações são devidamente aplicadas"}], "explanation": "A captura regulatória ocorre quando as agências reguladoras passam a servir os interesses das indústrias que regulam em vez do público. As indústrias influenciam as regulações para prejudicar concorrentes e beneficiar-se — transformando a regulação numa ferramenta de capitalismo de compadrio.", "wrong_explanations": {"a": "O rigor não é a questão — é QUEM beneficia das regulações.", "c": "A captura é mais subtil: a indústria controla o regulador sem propriedade formal.", "d": "As regulações capturadas são aplicadas para beneficiar a indústria, não o público."}}, "es": {"question": "¿Qué es la \"captura regulatoria\"?", "options": [{"id": "a", "text": "Cuando las regulaciones se vuelven demasiado estrictas"}, {"id": "b", "text": "Cuando las industrias reguladas controlan las agencias que deberían regularlas"}, {"id": "c", "text": "Cuando el gobierno captura empresas privadas"}, {"id": "d", "text": "Cuando las regulaciones se aplican correctamente"}], "explanation": "La captura regulatoria ocurre cuando las agencias reguladoras pasan a servir los intereses de las industrias que regulan en vez del público. Las industrias influyen en las regulaciones para perjudicar a competidores y beneficiarse — convirtiendo la regulación en una herramienta de capitalismo de amiguetes.", "wrong_explanations": {"a": "La rigurosidad no es la cuestión — es QUIÉN se beneficia de las regulaciones.", "c": "La captura es más sutil: la industria controla al regulador sin propiedad formal.", "d": "Las regulaciones capturadas se aplican para beneficiar a la industria, no al público."}}, "fr": {"question": "Qu''est-ce que la \"capture réglementaire\" ?", "options": [{"id": "a", "text": "Quand les réglementations deviennent trop strictes"}, {"id": "b", "text": "Quand les industries régulées contrôlent les agences censées les réguler"}, {"id": "c", "text": "Quand le gouvernement capture des entreprises privées"}, {"id": "d", "text": "Quand les réglementations sont correctement appliquées"}], "explanation": "La capture réglementaire survient quand les agences de régulation en viennent à servir les intérêts des industries qu''elles régulent plutôt que le public. Les industries influencent les réglementations pour nuire aux concurrents et se favoriser — transformant la régulation en outil de copinage.", "wrong_explanations": {"a": "La rigueur n''est pas le problème — c''est QUI bénéficie des réglementations.", "c": "La capture est plus subtile : l''industrie contrôle le régulateur sans propriété formelle.", "d": "Les réglementations capturées sont appliquées au bénéfice de l''industrie, pas du public."}}}'::jsonb WHERE question = 'What is "regulatory capture"?';

-- Q73
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem escreveu: \"A longo prazo estaremos todos mortos\"?", "options": [{"id": "a", "text": "Adam Smith"}, {"id": "b", "text": "John Maynard Keynes"}, {"id": "c", "text": "Milton Friedman"}, {"id": "d", "text": "Karl Marx"}], "explanation": "Keynes escreveu isto descartando preocupações com as consequências a longo prazo das suas políticas. Isto capta o pensamento a curto prazo da economia keynesiana — gastar agora, preocupar-se depois. O comentário revela uma filosofia que desvaloriza as consequências futuras, permitindo políticas destrutivas.", "wrong_explanations": {"a": "Smith preocupava-se com a criação de riqueza a longo prazo, não com descartar o futuro.", "c": "Friedman criticou esta atitude e a economia keynesiana em geral.", "d": "Marx focava-se na inevitabilidade histórica, não em descartar o longo prazo."}}, "es": {"question": "¿Quién escribió: \"A largo plazo todos estaremos muertos\"?", "options": [{"id": "a", "text": "Adam Smith"}, {"id": "b", "text": "John Maynard Keynes"}, {"id": "c", "text": "Milton Friedman"}, {"id": "d", "text": "Karl Marx"}], "explanation": "Keynes escribió esto descartando preocupaciones por las consecuencias a largo plazo de sus políticas. Esto capta el pensamiento a corto plazo de la economía keynesiana — gastar ahora, preocuparse después. El comentario revela una filosofía que descuenta las consecuencias futuras, habilitando políticas destructivas.", "wrong_explanations": {"a": "Smith se preocupaba por la creación de riqueza a largo plazo, no por descartar el futuro.", "c": "Friedman criticó esta actitud y la economía keynesiana en general.", "d": "Marx se enfocaba en la inevitabilidad histórica, no en descartar el largo plazo."}}, "fr": {"question": "Qui a écrit : \"À long terme, nous serons tous morts\" ?", "options": [{"id": "a", "text": "Adam Smith"}, {"id": "b", "text": "John Maynard Keynes"}, {"id": "c", "text": "Milton Friedman"}, {"id": "d", "text": "Karl Marx"}], "explanation": "Keynes a écrit cela en écartant les préoccupations sur les conséquences à long terme de ses politiques. Cela capture la pensée à court terme de l''économie keynésienne — dépenser maintenant, s''inquiéter plus tard. La remarque révèle une philosophie qui dévalorise les conséquences futures, permettant des politiques destructrices.", "wrong_explanations": {"a": "Smith se préoccupait de la création de richesse à long terme, pas d''écarter l''avenir.", "c": "Friedman a critiqué cette attitude et l''économie keynésienne en général.", "d": "Marx se concentrait sur l''inévitabilité historique, pas sur écarter le long terme."}}}'::jsonb WHERE question = 'Who wrote: "In the long run we are all dead"?';

-- Q74
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que as leis de salário mínimo causam desemprego entre os menos qualificados?", "options": [{"id": "a", "text": "Não causam — o salário mínimo só ajuda os trabalhadores"}, {"id": "b", "text": "Se um trabalhador produz menos valor do que o salário mínimo, contratá-lo é uma perda"}, {"id": "c", "text": "Os empregadores são gananciosos demais para pagar salários justos"}, {"id": "d", "text": "O salário mínimo é sempre definido demasiado alto"}], "explanation": "Se o salário mínimo é 15€/hora mas a produtividade de um trabalhador vale 10€/hora, contratá-lo significa perder 5€/hora. Os empregadores não aceitam essa perda — e esse trabalhador fica desempregado. As leis de salário mínimo não aumentam salários; proíbem o emprego abaixo de certa produtividade.", "wrong_explanations": {"a": "A economia básica e estudos empíricos mostram que aumentos do salário mínimo aumentam o desemprego entre os menos qualificados.", "c": "A ''ganância'' não explica economia. As empresas não conseguem pagar sustentavelmente mais do que os trabalhadores produzem.", "d": "QUALQUER salário mínimo acima do equilíbrio de mercado causa algum desemprego — é o princípio."}}, "es": {"question": "¿Por qué las leyes de salario mínimo causan desempleo entre los menos cualificados?", "options": [{"id": "a", "text": "No lo causan — el salario mínimo solo ayuda a los trabajadores"}, {"id": "b", "text": "Si un trabajador produce menos valor que el salario mínimo, contratarlo es una pérdida"}, {"id": "c", "text": "Los empleadores son demasiado codiciosos para pagar salarios justos"}, {"id": "d", "text": "El salario mínimo siempre se fija demasiado alto"}], "explanation": "Si el salario mínimo es $15/hora pero la productividad de un trabajador vale $10/hora, contratarlo significa perder $5/hora. Los empleadores no aceptarán esa pérdida — y ese trabajador quedará desempleado. Las leyes de salario mínimo no elevan salarios; prohíben el empleo por debajo de cierta productividad.", "wrong_explanations": {"a": "La economía básica y estudios empíricos muestran que los aumentos del salario mínimo incrementan el desempleo entre los menos cualificados.", "c": "La ''codicia'' no explica economía. Las empresas no pueden pagar sustentablemente más de lo que los trabajadores producen.", "d": "CUALQUIER salario mínimo por encima del equilibrio de mercado causa algo de desempleo — es el principio."}}, "fr": {"question": "Pourquoi les lois sur le salaire minimum causent-elles du chômage parmi les moins qualifiés ?", "options": [{"id": "a", "text": "Elles n''en causent pas — le salaire minimum ne fait qu''aider les travailleurs"}, {"id": "b", "text": "Si un travailleur produit moins de valeur que le salaire minimum, l''embaucher est une perte"}, {"id": "c", "text": "Les employeurs sont trop cupides pour payer des salaires justes"}, {"id": "d", "text": "Le salaire minimum est toujours fixé trop haut"}], "explanation": "Si le salaire minimum est de 15€/heure mais que la productivité d''un travailleur vaut 10€/heure, l''embaucher signifie perdre 5€/heure. Les employeurs n''accepteront pas cette perte — et ce travailleur restera au chômage. Les lois sur le salaire minimum n''augmentent pas les salaires ; elles interdisent l''emploi en dessous d''un certain niveau de productivité.", "wrong_explanations": {"a": "L''économie fondamentale et les études empiriques montrent que les hausses du salaire minimum augmentent le chômage parmi les moins qualifiés.", "c": "La ''cupidité'' n''explique pas l''économie. Les entreprises ne peuvent pas payer durablement plus que ce que les travailleurs produisent.", "d": "TOUT salaire minimum au-dessus de l''équilibre du marché cause du chômage — c''est le principe."}}}'::jsonb WHERE question = 'Why do minimum wage laws cause unemployment among the least skilled?';

-- Q75
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que a \"justiça\" é uma virtude egoísta?", "options": [{"id": "a", "text": "Justiça significa obter mais que os outros"}, {"id": "b", "text": "Julgar os outros objetivamente protege-o de fraudes e ajuda-o a encontrar valor"}, {"id": "c", "text": "Justiça é sobre punir inimigos"}, {"id": "d", "text": "Justiça é na verdade altruísta, não egoísta"}], "explanation": "Justiça — julgar objetivamente o caráter e conceder a cada um o que merece — serve o seu autointeresse. Ajuda-o a identificar comerciantes honestos (para seu benefício) e fraudes (evitando danos). Recusar-se a julgar deixa-o vulnerável à exploração.", "wrong_explanations": {"a": "Justiça é sobre avaliação precisa, não obter vantagem através do julgamento.", "c": "Justiça inclui recompensar o bom, não apenas punir o mau.", "d": "Todas as virtudes genuínas são egoístas no sentido correto — servem a sua vida."}}, "es": {"question": "¿Por qué la \"justicia\" es una virtud egoísta?", "options": [{"id": "a", "text": "Justicia significa obtener más que los demás"}, {"id": "b", "text": "Juzgar a los demás objetivamente te protege de fraudes y te ayuda a encontrar valor"}, {"id": "c", "text": "La justicia es castigar enemigos"}, {"id": "d", "text": "La justicia es en realidad altruista, no egoísta"}], "explanation": "La justicia — juzgar objetivamente el carácter y dar a cada uno lo que merece — sirve a tu autointerés. Te ayuda a identificar comerciantes honestos (para tu beneficio) y fraudes (evitando daños). Negarse a juzgar te deja vulnerable a la explotación.", "wrong_explanations": {"a": "La justicia es sobre evaluación precisa, no obtener ventaja a través del juicio.", "c": "La justicia incluye recompensar al bueno, no solo castigar al malo.", "d": "Todas las virtudes genuinas son egoístas en el sentido correcto — sirven a tu vida."}}, "fr": {"question": "Pourquoi la \"justice\" est-elle une vertu égoïste ?", "options": [{"id": "a", "text": "La justice signifie obtenir plus que les autres"}, {"id": "b", "text": "Juger objectivement les autres vous protège des fraudeurs et vous aide à trouver de la valeur"}, {"id": "c", "text": "La justice consiste à punir les ennemis"}, {"id": "d", "text": "La justice est en réalité altruiste, pas égoïste"}], "explanation": "La justice — juger objectivement le caractère et accorder à chacun ce qu''il mérite — sert votre intérêt personnel. Elle vous aide à identifier les commerçants honnêtes (à votre avantage) et les fraudeurs (en évitant les dommages). Refuser de juger vous rend vulnérable à l''exploitation.", "wrong_explanations": {"a": "La justice porte sur l''évaluation précise, pas sur l''obtention d''un avantage par le jugement.", "c": "La justice inclut de récompenser le bien, pas seulement de punir le mal.", "d": "Toutes les véritables vertus sont égoïstes au sens correct — elles servent votre vie."}}}'::jsonb WHERE question = 'Why is "justice" a selfish virtue?';

-- Q76
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é o \"problema é-deve\" e como se resolve?", "options": [{"id": "a", "text": "Nunca se pode derivar ''deve'' de ''é''"}, {"id": "b", "text": "Reconhecer que ''deve'' depende de ''é'' — especificamente, do que a vida humana requer"}, {"id": "c", "text": "Factos e valores são completamente separados"}, {"id": "d", "text": "O problema não tem solução"}], "explanation": "Hume notou que não se pode derivar ''deve'' de ''é'' sem uma premissa de valor. A solução: a premissa de valor é a VIDA. Dado que a vida requer certas ações, e os humanos escolhem viver, factos sobre o que sustenta a vida geram ''deveres'' vinculantes. Os valores são objetivos.", "wrong_explanations": {"a": "PODE-SE derivar ''deve'' de ''é'' uma vez identificada a vida como padrão de valor.", "c": "Factos sobre os requisitos da vida determinam valores — não são separados.", "d": "Identificar a vida como padrão resolve o problema."}}, "es": {"question": "¿Qué es el \"problema ser-deber\" y cómo se resuelve?", "options": [{"id": "a", "text": "Nunca se puede derivar ''deber'' de ''ser''"}, {"id": "b", "text": "Reconocer que ''deber'' depende de ''ser'' — específicamente, de lo que la vida humana requiere"}, {"id": "c", "text": "Hechos y valores están completamente separados"}, {"id": "d", "text": "El problema no tiene solución"}], "explanation": "Hume notó que no se puede derivar ''deber'' de ''ser'' sin una premisa de valor. La solución: la premisa de valor es la VIDA. Dado que la vida requiere ciertas acciones, y los humanos eligen vivir, hechos sobre lo que sustenta la vida generan ''deberes'' vinculantes. Los valores son objetivos.", "wrong_explanations": {"a": "SE PUEDE derivar ''deber'' de ''ser'' una vez identificada la vida como estándar de valor.", "c": "Los hechos sobre los requisitos de la vida determinan valores — no están separados.", "d": "Identificar la vida como estándar resuelve el problema."}}, "fr": {"question": "Qu''est-ce que le \"problème être-devoir\" et comment le résoudre ?", "options": [{"id": "a", "text": "On ne peut jamais dériver le ''devoir'' de l''être''"}, {"id": "b", "text": "Reconnaître que le ''devoir'' dépend de l''être — spécifiquement, de ce que la vie humaine nécessite"}, {"id": "c", "text": "Les faits et les valeurs sont complètement séparés"}, {"id": "d", "text": "Le problème n''a pas de solution"}], "explanation": "Hume a noté qu''on ne peut dériver le ''devoir'' de l''être sans une prémisse de valeur. La solution : la prémisse de valeur est la VIE. Étant donné que la vie nécessite certaines actions et que les humains choisissent de vivre, les faits sur ce qui soutient la vie génèrent des ''devoirs'' contraignants. Les valeurs sont objectives.", "wrong_explanations": {"a": "ON PEUT dériver le ''devoir'' de l''être une fois la vie identifiée comme critère de valeur.", "c": "Les faits sur les exigences de la vie déterminent les valeurs — ils ne sont pas séparés.", "d": "Identifier la vie comme critère résout le problème."}}}'::jsonb WHERE question = 'What is the "is-ought problem" and how is it resolved?';

-- Q77
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é o \"trilema de Münchhausen\" e como o Objetivismo o aborda?", "options": [{"id": "a", "text": "Prova que o conhecimento é impossível"}, {"id": "b", "text": "Mostra que os fundamentos do conhecimento devem ser axiomáticos, não derivados"}, {"id": "c", "text": "Apoia a regressão infinita de justificação"}, {"id": "d", "text": "Prova que o raciocínio circular é válido"}], "explanation": "O trilema: justificar o conhecimento leva a regressão infinita, raciocínio circular ou parar em axiomas. O Objetivismo abraça axiomas — verdades autoevidentes (existência, identidade, consciência) que não podem ser negadas sem as usar. São o fundamento adequado.", "wrong_explanations": {"a": "O trilema não prova impossibilidade — identifica a necessidade de axiomas.", "c": "A regressão infinita é um dos cornos do trilema, não uma solução.", "d": "O raciocínio circular é outro corno — também não é uma solução. Os axiomas são a resposta."}}, "es": {"question": "¿Qué es el \"trilema de Münchhausen\" y cómo lo aborda el Objetivismo?", "options": [{"id": "a", "text": "Prueba que el conocimiento es imposible"}, {"id": "b", "text": "Muestra que los fundamentos del conocimiento deben ser axiomáticos, no derivados"}, {"id": "c", "text": "Apoya la regresión infinita de justificación"}, {"id": "d", "text": "Prueba que el razonamiento circular es válido"}], "explanation": "El trilema: justificar el conocimiento lleva a regresión infinita, razonamiento circular o detenerse en axiomas. El Objetivismo abraza axiomas — verdades autoevidentes (existencia, identidad, conciencia) que no pueden negarse sin usarlas. Son el fundamento adecuado.", "wrong_explanations": {"a": "El trilema no prueba imposibilidad — identifica la necesidad de axiomas.", "c": "La regresión infinita es uno de los cuernos del trilema, no una solución.", "d": "El razonamiento circular es otro cuerno — tampoco es una solución. Los axiomas son la respuesta."}}, "fr": {"question": "Qu''est-ce que le \"trilemme de Münchhausen\" et comment l''Objectivisme y répond-il ?", "options": [{"id": "a", "text": "Il prouve que la connaissance est impossible"}, {"id": "b", "text": "Il montre que les fondements de la connaissance doivent être axiomatiques, pas dérivés"}, {"id": "c", "text": "Il soutient la régression infinie de la justification"}, {"id": "d", "text": "Il prouve que le raisonnement circulaire est valide"}], "explanation": "Le trilemme : justifier la connaissance mène à la régression infinie, au raisonnement circulaire ou à l''arrêt sur des axiomes. L''Objectivisme embrasse les axiomes — des vérités évidentes par elles-mêmes (existence, identité, conscience) qui ne peuvent être niées sans les utiliser. Ce sont le fondement approprié.", "wrong_explanations": {"a": "Le trilemme ne prouve pas l''impossibilité — il identifie le besoin d''axiomes.", "c": "La régression infinie est une branche du trilemme, pas une solution.", "d": "Le raisonnement circulaire est une autre branche — pas non plus une solution. Les axiomes sont la réponse."}}}'::jsonb WHERE question = 'What is the "Münchhausen trilemma" and how does Objectivism address it?';

-- Q78
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é o \"anarco-capitalismo\" e por que os Objetivistas o rejeitam?", "options": [{"id": "a", "text": "É o mesmo que o Objetivismo"}, {"id": "b", "text": "Propõe agências de defesa privadas concorrentes, mas isto permite a iniciação de força sem resolução objetiva"}, {"id": "c", "text": "Tem demasiado governo"}, {"id": "d", "text": "Os Objetivistas apoiam o anarco-capitalismo"}], "explanation": "O anarco-capitalismo propõe agências de defesa privadas em competição sem governo. Os Objetivistas rejeitam isto: sem uma autoridade única sobre a força retaliatória, conflitos entre agências não têm resolução objetiva — levando a guerra de gangues, não proteção de direitos.", "wrong_explanations": {"a": "O Objetivismo apoia governo limitado, não nenhum governo.", "c": "O anarco-capitalismo NÃO tem governo — esse é o problema.", "d": "Rand criticou explicitamente o anarquismo como ''ingénuo'' e ''abstração flutuante''."}}, "es": {"question": "¿Qué es el \"anarcocapitalismo\" y por qué los Objetivistas lo rechazan?", "options": [{"id": "a", "text": "Es lo mismo que el Objetivismo"}, {"id": "b", "text": "Propone agencias de defensa privadas competidoras, pero esto permite la iniciación de fuerza sin resolución objetiva"}, {"id": "c", "text": "Tiene demasiado gobierno"}, {"id": "d", "text": "Los Objetivistas apoyan el anarcocapitalismo"}], "explanation": "El anarcocapitalismo propone agencias de defensa privadas en competencia sin gobierno. Los Objetivistas lo rechazan: sin una autoridad única sobre la fuerza de represalia, los conflictos entre agencias no tienen resolución objetiva — llevando a guerra de pandillas, no protección de derechos.", "wrong_explanations": {"a": "El Objetivismo apoya gobierno limitado, no ningún gobierno.", "c": "El anarcocapitalismo NO tiene gobierno — ese es el problema.", "d": "Rand criticó explícitamente el anarquismo como ''ingenuo'' y ''abstracción flotante''."}}, "fr": {"question": "Qu''est-ce que l''\"anarcho-capitalisme\" et pourquoi les Objectivistes le rejettent-ils ?", "options": [{"id": "a", "text": "C''est la même chose que l''Objectivisme"}, {"id": "b", "text": "Il propose des agences de défense privées concurrentes, mais cela permet l''initiation de la force sans résolution objective"}, {"id": "c", "text": "Il a trop de gouvernement"}, {"id": "d", "text": "Les Objectivistes soutiennent l''anarcho-capitalisme"}], "explanation": "L''anarcho-capitalisme propose des agences de défense privées concurrentes sans gouvernement. Les Objectivistes le rejettent : sans une autorité unique sur la force de représailles, les conflits entre agences n''ont pas de résolution objective — menant à la guerre des gangs, pas à la protection des droits.", "wrong_explanations": {"a": "L''Objectivisme soutient un gouvernement limité, pas l''absence de gouvernement.", "c": "L''anarcho-capitalisme n''a PAS de gouvernement — c''est le problème.", "d": "Rand a explicitement critiqué l''anarchisme comme ''naïf'' et ''abstraction flottante''."}}}'::jsonb WHERE question = 'What is "anarcho-capitalism" and why do Objectivists reject it?';

-- Q79
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que os Fundadores Americanos incluíram a Segunda Emenda?", "options": [{"id": "a", "text": "Para direitos de caça"}, {"id": "b", "text": "Para garantir que o povo pudesse resistir a um governo tirânico"}, {"id": "c", "text": "Para tiro desportivo"}, {"id": "d", "text": "Para apoiar o exército"}], "explanation": "A Segunda Emenda existe para preservar a capacidade do povo de resistir à tirania — seja do seu próprio governo ou de invasão estrangeira. Um povo armado é o último controlo sobre o poder governamental. Os Fundadores tinham acabado de lutar uma guerra contra a tirania e queriam garantir que pudesse ser feito novamente se necessário.", "wrong_explanations": {"a": "Os direitos de caça eram tão óbvios que não precisavam de emenda. O propósito era político.", "c": "O tiro desportivo não era a preocupação dos Fundadores ao criar proteções constitucionais.", "d": "A cláusula da milícia refere-se a soldados cidadãos, não ao exército profissional."}}, "es": {"question": "¿Por qué los Fundadores Americanos incluyeron la Segunda Enmienda?", "options": [{"id": "a", "text": "Para derechos de caza"}, {"id": "b", "text": "Para asegurar que el pueblo pudiera resistir a un gobierno tiránico"}, {"id": "c", "text": "Para tiro deportivo"}, {"id": "d", "text": "Para apoyar al ejército"}], "explanation": "La Segunda Enmienda existe para preservar la capacidad del pueblo de resistir la tiranía — ya sea de su propio gobierno o de invasión extranjera. Un pueblo armado es el último control sobre el poder gubernamental. Los Fundadores acababan de luchar una guerra contra la tiranía y querían asegurar que pudiera hacerse de nuevo si fuera necesario.", "wrong_explanations": {"a": "Los derechos de caza eran tan obvios que no necesitaban enmienda. El propósito era político.", "c": "El tiro deportivo no era la preocupación de los Fundadores al crear protecciones constitucionales.", "d": "La cláusula de la milicia se refiere a soldados ciudadanos, no al ejército profesional."}}, "fr": {"question": "Pourquoi les Fondateurs américains ont-ils inclus le Deuxième Amendement ?", "options": [{"id": "a", "text": "Pour les droits de chasse"}, {"id": "b", "text": "Pour garantir que le peuple puisse résister à un gouvernement tyrannique"}, {"id": "c", "text": "Pour le tir sportif"}, {"id": "d", "text": "Pour soutenir l''armée"}], "explanation": "Le Deuxième Amendement existe pour préserver la capacité du peuple à résister à la tyrannie — qu''elle vienne de son propre gouvernement ou d''une invasion étrangère. Un peuple armé est le dernier contrôle sur le pouvoir gouvernemental. Les Fondateurs venaient de mener une guerre contre la tyrannie et voulaient s''assurer que cela puisse être fait à nouveau si nécessaire.", "wrong_explanations": {"a": "Les droits de chasse étaient si évidents qu''ils n''avaient pas besoin d''amendement. Le but était politique.", "c": "Le tir sportif n''était pas la préoccupation des Fondateurs en créant des protections constitutionnelles.", "d": "La clause de la milice fait référence aux soldats citoyens, pas à l''armée professionnelle."}}}'::jsonb WHERE question = 'Why did the American Founders include the Second Amendment?';

-- Q80
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Qual é a diferença entre \"sentido de vida\" e filosofia explícita na arte?", "options": [{"id": "a", "text": "São a mesma coisa"}, {"id": "b", "text": "O sentido de vida é uma soma emocional de respostas subconscientes a valores; a filosofia são crenças concetuais explícitas"}, {"id": "c", "text": "O sentido de vida é mais importante"}, {"id": "d", "text": "A filosofia explícita é irrelevante para a arte"}], "explanation": "O sentido de vida é uma soma pré-concetual, emocional que reflete a visão implícita da existência — otimista ou pessimista, benevolente ou malevolente. Molda as preferências artísticas antes da filosofia explícita. A arte pode projetar um sentido de vida que contradiz as opiniões declaradas do artista.", "wrong_explanations": {"a": "Frequentemente alinham-se mas podem entrar em conflito — alguém pode professar pessimismo mas responder à arte heroica.", "c": "Ambos importam: o sentido de vida molda a resposta; a filosofia permite a avaliação.", "d": "A filosofia explícita é essencial para avaliar a arte, mesmo que o sentido de vida molde a resposta inicial."}}, "es": {"question": "¿Cuál es la diferencia entre el \"sentido de vida\" y la filosofía explícita en el arte?", "options": [{"id": "a", "text": "Son lo mismo"}, {"id": "b", "text": "El sentido de vida es una suma emocional de respuestas subconscientes a valores; la filosofía son creencias conceptuales explícitas"}, {"id": "c", "text": "El sentido de vida es más importante"}, {"id": "d", "text": "La filosofía explícita es irrelevante para el arte"}], "explanation": "El sentido de vida es una suma preconceptual, emocional que refleja la visión implícita de la existencia — optimista o pesimista, benevolente o malevolente. Moldea las preferencias artísticas antes de la filosofía explícita. El arte puede proyectar un sentido de vida que contradice las opiniones declaradas del artista.", "wrong_explanations": {"a": "A menudo se alinean pero pueden entrar en conflicto — alguien puede profesar pesimismo pero responder al arte heroico.", "c": "Ambos importan: el sentido de vida moldea la respuesta; la filosofía permite la evaluación.", "d": "La filosofía explícita es esencial para evaluar el arte, incluso si el sentido de vida moldea la respuesta inicial."}}, "fr": {"question": "Quelle est la différence entre le \"sens de la vie\" et la philosophie explicite dans l''art ?", "options": [{"id": "a", "text": "C''est la même chose"}, {"id": "b", "text": "Le sens de la vie est une somme émotionnelle de réponses subconscientes aux valeurs ; la philosophie, ce sont des croyances conceptuelles explicites"}, {"id": "c", "text": "Le sens de la vie est plus important"}, {"id": "d", "text": "La philosophie explicite est sans rapport avec l''art"}], "explanation": "Le sens de la vie est une somme pré-conceptuelle, émotionnelle reflétant la vision implicite de l''existence — optimiste ou pessimiste, bienveillante ou malveillante. Il façonne les préférences artistiques avant la philosophie explicite. L''art peut projeter un sens de la vie qui contredit les opinions déclarées de l''artiste.", "wrong_explanations": {"a": "Ils s''alignent souvent mais peuvent entrer en conflit — quelqu''un peut professer le pessimisme tout en répondant à l''art héroïque.", "c": "Les deux comptent : le sens de la vie façonne la réponse ; la philosophie permet l''évaluation.", "d": "La philosophie explicite est essentielle pour évaluer l''art, même si le sens de la vie façonne la réponse initiale."}}}'::jsonb WHERE question = 'What is the difference between "sense of life" and explicit philosophy in art?';

