-- Q81
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem disse: \"Aquele governo é melhor que governa menos\"?", "options": [{"id": "a", "text": "Henry David Thoreau"}, {"id": "b", "text": "Thomas Jefferson"}, {"id": "c", "text": "John Adams"}, {"id": "d", "text": "Abraham Lincoln"}], "explanation": "Henry David Thoreau escreveu isto em \"Desobediência Civil\" (1849), defendendo a mínima interferência governamental na vida individual. Levou o princípio mais longe: \"Aquele governo é melhor que não governa de todo.\"", "wrong_explanations": {"b": "Jefferson tinha opiniões semelhantes, mas não escreveu esta citação específica.", "c": "Adams era mais favorável a um governo federal forte.", "d": "Lincoln expandiu o poder federal durante a Guerra Civil."}}, "es": {"question": "¿Quién dijo: \"El mejor gobierno es el que menos gobierna\"?", "options": [{"id": "a", "text": "Henry David Thoreau"}, {"id": "b", "text": "Thomas Jefferson"}, {"id": "c", "text": "John Adams"}, {"id": "d", "text": "Abraham Lincoln"}], "explanation": "Henry David Thoreau escribió esto en \"Desobediencia civil\" (1849), abogando por la mínima interferencia gubernamental en la vida individual. Llevó el principio más lejos: \"El mejor gobierno es el que no gobierna en absoluto.\"", "wrong_explanations": {"b": "Jefferson tenía opiniones similares, pero no escribió esta cita específica.", "c": "Adams era más favorable a un gobierno federal fuerte.", "d": "Lincoln expandió el poder federal durante la Guerra Civil."}}, "fr": {"question": "Qui a dit : \"Le meilleur gouvernement est celui qui gouverne le moins\" ?", "options": [{"id": "a", "text": "Henry David Thoreau"}, {"id": "b", "text": "Thomas Jefferson"}, {"id": "c", "text": "John Adams"}, {"id": "d", "text": "Abraham Lincoln"}], "explanation": "Henry David Thoreau a écrit ceci dans \"La Désobéissance civile\" (1849), plaidant pour une interférence gouvernementale minimale dans la vie individuelle. Il a poussé le principe plus loin : \"Le meilleur gouvernement est celui qui ne gouverne pas du tout.\"", "wrong_explanations": {"b": "Jefferson avait des opinions similaires, mais n''a pas écrit cette citation spécifique.", "c": "Adams était plus favorable à un gouvernement fédéral fort.", "d": "Lincoln a étendu le pouvoir fédéral pendant la Guerre civile."}}}'::jsonb WHERE question = 'Who said: "That government is best which governs least"?';

-- Q82
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem escreveu: \"Uma vida não examinada não vale a pena ser vivida\"?", "options": [{"id": "a", "text": "Platão"}, {"id": "b", "text": "Aristóteles"}, {"id": "c", "text": "Sócrates"}, {"id": "d", "text": "Epicuro"}], "explanation": "Sócrates disse isto no seu julgamento, conforme registado na \"Apologia\" de Platão. Argumentou que questionar, raciocinar e o autoexame são essenciais para uma vida humana significativa. Escolheu a morte em vez de abandonar a filosofia.", "wrong_explanations": {"a": "Platão registou-o, mas Sócrates proferiu estas palavras.", "b": "Aristóteles foi aluno de Platão, vindo depois de Sócrates.", "d": "Epicuro focava-se no prazer e em evitar a dor."}}, "es": {"question": "¿Quién escribió: \"Una vida no examinada no vale la pena ser vivida\"?", "options": [{"id": "a", "text": "Platón"}, {"id": "b", "text": "Aristóteles"}, {"id": "c", "text": "Sócrates"}, {"id": "d", "text": "Epicuro"}], "explanation": "Sócrates dijo esto en su juicio, según registró Platón en la \"Apología\". Argumentó que cuestionar, razonar y el autoexamen son esenciales para una vida humana significativa. Eligió la muerte antes que abandonar la filosofía.", "wrong_explanations": {"a": "Platón lo registró, pero Sócrates pronunció estas palabras.", "b": "Aristóteles fue alumno de Platón, viniendo después de Sócrates.", "d": "Epicuro se enfocaba en el placer y en evitar el dolor."}}, "fr": {"question": "Qui a écrit : \"Une vie sans examen ne vaut pas la peine d''être vécue\" ?", "options": [{"id": "a", "text": "Platon"}, {"id": "b", "text": "Aristote"}, {"id": "c", "text": "Socrate"}, {"id": "d", "text": "Épicure"}], "explanation": "Socrate a dit cela lors de son procès, tel que rapporté dans l''\"Apologie\" de Platon. Il a soutenu que questionner, raisonner et l''examen de soi sont essentiels à une vie humaine significative. Il a choisi la mort plutôt que d''abandonner la philosophie.", "wrong_explanations": {"a": "Platon l''a rapporté, mais Socrate a prononcé ces mots.", "b": "Aristote était l''élève de Platon, venant après Socrate.", "d": "Épicure se concentrait sur le plaisir et l''évitement de la douleur."}}}'::jsonb WHERE question = 'Who wrote: "The unexamined life is not worth living"?';

-- Q83
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem disse: \"O poder tende a corromper, e o poder absoluto corrompe absolutamente\"?", "options": [{"id": "a", "text": "Thomas Jefferson"}, {"id": "b", "text": "Lord Acton"}, {"id": "c", "text": "Edmund Burke"}, {"id": "d", "text": "John Stuart Mill"}], "explanation": "Lord Acton escreveu isto numa carta de 1887 ao Bispo Mandell Creighton. Adverte que o poder concentrado leva à corrupção moral — um argumento chave para governo limitado e separação de poderes.", "wrong_explanations": {"a": "Jefferson alertou sobre o poder, mas não cunhou esta frase.", "c": "Burke preocupava-se com tradição e ordem.", "d": "Mill focava-se na liberdade e no utilitarismo."}}, "es": {"question": "¿Quién dijo: \"El poder tiende a corromper, y el poder absoluto corrompe absolutamente\"?", "options": [{"id": "a", "text": "Thomas Jefferson"}, {"id": "b", "text": "Lord Acton"}, {"id": "c", "text": "Edmund Burke"}, {"id": "d", "text": "John Stuart Mill"}], "explanation": "Lord Acton escribió esto en una carta de 1887 al Obispo Mandell Creighton. Advierte que el poder concentrado lleva a la corrupción moral — un argumento clave para el gobierno limitado y la separación de poderes.", "wrong_explanations": {"a": "Jefferson advirtió sobre el poder, pero no acuñó esta frase.", "c": "Burke se preocupaba por la tradición y el orden.", "d": "Mill se enfocaba en la libertad y el utilitarismo."}}, "fr": {"question": "Qui a dit : \"Le pouvoir tend à corrompre, et le pouvoir absolu corrompt absolument\" ?", "options": [{"id": "a", "text": "Thomas Jefferson"}, {"id": "b", "text": "Lord Acton"}, {"id": "c", "text": "Edmund Burke"}, {"id": "d", "text": "John Stuart Mill"}], "explanation": "Lord Acton a écrit ceci dans une lettre de 1887 à l''évêque Mandell Creighton. Cela avertit que le pouvoir concentré mène à la corruption morale — un argument clé pour un gouvernement limité et la séparation des pouvoirs.", "wrong_explanations": {"a": "Jefferson a mis en garde contre le pouvoir, mais n''a pas inventé cette phrase.", "c": "Burke se préoccupait de la tradition et de l''ordre.", "d": "Mill se concentrait sur la liberté et l''utilitarisme."}}}'::jsonb WHERE question = 'Who said: "Power tends to corrupt, and absolute power corrupts absolutely"?';

-- Q84
UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem escreveu: \"O amor ao dinheiro é a raiz de todo o mal\"?", "options": [{"id": "a", "text": "Karl Marx"}, {"id": "b", "text": "A Bíblia (1 Timóteo)"}, {"id": "c", "text": "Adam Smith"}, {"id": "d", "text": "Aristóteles"}], "explanation": "Isto é da Bíblia (1 Timóteo 6:10). Note que diz ''amor ao dinheiro'', não ''o dinheiro em si''. A distinção importa: o dinheiro é uma ferramenta; a obsessão com ele excluindo valores é o problema. Ayn Rand reinterpretou como ''o amor ao dinheiro é a raiz de todo o bem'' quando o dinheiro representa conquista produtiva.", "wrong_explanations": {"a": "Marx criticou o capitalismo, mas esta citação precede-o em milénios.", "c": "Smith analisou o papel do dinheiro na economia positivamente.", "d": "Aristóteles escreveu sobre dinheiro, mas não esta frase específica."}}, "es": {"question": "¿Quién escribió: \"El amor al dinero es la raíz de todo mal\"?", "options": [{"id": "a", "text": "Karl Marx"}, {"id": "b", "text": "La Biblia (1 Timoteo)"}, {"id": "c", "text": "Adam Smith"}, {"id": "d", "text": "Aristóteles"}], "explanation": "Esto viene de la Biblia (1 Timoteo 6:10). Note que dice ''amor al dinero'', no ''el dinero en sí''. La distinción importa: el dinero es una herramienta; la obsesión con él excluyendo valores es el problema. Ayn Rand lo reinterpretó como ''el amor al dinero es la raíz de todo bien'' cuando el dinero representa logro productivo.", "wrong_explanations": {"a": "Marx criticó el capitalismo, pero esta cita lo precede por milenios.", "c": "Smith analizó el papel del dinero en la economía positivamente.", "d": "Aristóteles escribió sobre dinero, pero no esta frase específica."}}, "fr": {"question": "Qui a écrit : \"L''amour de l''argent est la racine de tous les maux\" ?", "options": [{"id": "a", "text": "Karl Marx"}, {"id": "b", "text": "La Bible (1 Timothée)"}, {"id": "c", "text": "Adam Smith"}, {"id": "d", "text": "Aristote"}], "explanation": "Ceci vient de la Bible (1 Timothée 6:10). Notez que c''est ''l''amour de l''argent'', pas ''l''argent en soi''. La distinction compte : l''argent est un outil ; l''obsession qui exclut les valeurs est le problème. Ayn Rand l''a réinterprété comme ''l''amour de l''argent est la racine de tout bien'' quand l''argent représente l''accomplissement productif.", "wrong_explanations": {"a": "Marx a critiqué le capitalisme, mais cette citation le précède de millénaires.", "c": "Smith a analysé le rôle de l''argent dans l''économie positivement.", "d": "Aristote a écrit sur l''argent, mais pas cette phrase spécifique."}}}'::jsonb WHERE question = 'Who wrote: "The love of money is the root of all evil"?';

