UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem disse: \"Proletários de todos os países, uni-vos! Nada tendes a perder a não ser as vossas correntes\"?", "options": [{"id": "a", "text": "Vladimir Lenine"}, {"id": "b", "text": "Friedrich Engels"}, {"id": "c", "text": "Karl Marx"}, {"id": "d", "text": "Leon Trotsky"}], "explanation": "Marx e Engels escreveram isto no \"Manifesto Comunista\" (1848). O apelo à revolução levou a regimes que puseram trabalhadores em correntes reais — a URSS, China, Camboja — matando mais de 100 milhões de pessoas no século XX.", "wrong_explanations": {"a": "Lenine implementou as ideias de Marx, mas não escreveu o Manifesto.", "b": "Engels co-escreveu-o, mas Marx é creditado como autor principal.", "d": "Trotsky veio depois, durante a Revolução Russa."}}, "es": {"question": "¿Quién dijo: \"¡Proletarios de todos los países, uníos! No tenéis nada que perder salvo vuestras cadenas\"?", "options": [{"id": "a", "text": "Vladimir Lenin"}, {"id": "b", "text": "Friedrich Engels"}, {"id": "c", "text": "Karl Marx"}, {"id": "d", "text": "León Trotsky"}], "explanation": "Marx y Engels escribieron esto en el \"Manifiesto Comunista\" (1848). El llamado a la revolución llevó a regímenes que pusieron a los trabajadores en cadenas reales — la URSS, China, Camboya — matando a más de 100 millones de personas en el siglo XX.", "wrong_explanations": {"a": "Lenin implementó las ideas de Marx, pero no escribió el Manifiesto.", "b": "Engels lo coescribió, pero Marx es acreditado como autor principal.", "d": "Trotsky vino después, durante la Revolución Rusa."}}, "fr": {"question": "Qui a dit : \"Prolétaires de tous les pays, unissez-vous ! Vous n''avez rien à perdre que vos chaînes\" ?", "options": [{"id": "a", "text": "Vladimir Lénine"}, {"id": "b", "text": "Friedrich Engels"}, {"id": "c", "text": "Karl Marx"}, {"id": "d", "text": "Léon Trotski"}], "explanation": "Marx et Engels ont écrit cela dans le \"Manifeste du Parti communiste\" (1848). L''appel à la révolution a mené à des régimes qui ont mis les travailleurs dans de vraies chaînes — l''URSS, la Chine, le Cambodge — tuant plus de 100 millions de personnes au XXe siècle.", "wrong_explanations": {"a": "Lénine a mis en œuvre les idées de Marx, mais n''a pas écrit le Manifeste.", "b": "Engels l''a coécrit, mais Marx en est le principal auteur.", "d": "Trotski est venu plus tard, pendant la Révolution russe."}}}'::jsonb WHERE question = 'Who said: "Workers of the world, unite! You have nothing to lose but your chains"?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem escreveu: \"O homem está condenado a ser livre\"?", "options": [{"id": "a", "text": "Albert Camus"}, {"id": "b", "text": "Jean-Paul Sartre"}, {"id": "c", "text": "Simone de Beauvoir"}, {"id": "d", "text": "Martin Heidegger"}], "explanation": "Sartre escreveu isto em \"O Existencialismo é um Humanismo\" (1946). Embora tenha identificado corretamente que os humanos têm livre-arbítrio e devem escolher, chamar a liberdade de ''condenação'' revela a sua visão da existência como fardo em vez de oportunidade.", "wrong_explanations": {"a": "Camus era existencialista, mas focava-se no absurdo.", "c": "De Beauvoir era parceira de Sartre e existencialista também.", "d": "Heidegger influenciou o existencialismo, mas não usou esta frase."}}, "es": {"question": "¿Quién escribió: \"El hombre está condenado a ser libre\"?", "options": [{"id": "a", "text": "Albert Camus"}, {"id": "b", "text": "Jean-Paul Sartre"}, {"id": "c", "text": "Simone de Beauvoir"}, {"id": "d", "text": "Martin Heidegger"}], "explanation": "Sartre escribió esto en \"El existencialismo es un humanismo\" (1946). Aunque identificó correctamente que los humanos tienen libre albedrío y deben elegir, llamar a la libertad ''condena'' revela su visión de la existencia como carga en vez de oportunidad.", "wrong_explanations": {"a": "Camus era existencialista, pero se enfocaba en el absurdo.", "c": "De Beauvoir era compañera de Sartre y existencialista también.", "d": "Heidegger influyó en el existencialismo, pero no usó esta frase."}}, "fr": {"question": "Qui a écrit : \"L''homme est condamné à être libre\" ?", "options": [{"id": "a", "text": "Albert Camus"}, {"id": "b", "text": "Jean-Paul Sartre"}, {"id": "c", "text": "Simone de Beauvoir"}, {"id": "d", "text": "Martin Heidegger"}], "explanation": "Sartre a écrit ceci dans \"L''existentialisme est un humanisme\" (1946). Bien qu''il ait correctement identifié que les humains ont le libre arbitre et doivent choisir, qualifier la liberté de ''condamnation'' révèle sa vision de l''existence comme fardeau plutôt qu''opportunité.", "wrong_explanations": {"a": "Camus était existentialiste, mais se concentrait sur l''absurde.", "c": "De Beauvoir était la compagne de Sartre et existentialiste aussi.", "d": "Heidegger a influencé l''existentialisme, mais n''a pas utilisé cette phrase."}}}'::jsonb WHERE question = 'Who wrote: "Man is condemned to be free"?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem escreveu: \"Deus está morto\"?", "options": [{"id": "a", "text": "Charles Darwin"}, {"id": "b", "text": "Friedrich Nietzsche"}, {"id": "c", "text": "Sigmund Freud"}, {"id": "d", "text": "Richard Dawkins"}], "explanation": "Nietzsche escreveu isto em \"A Gaia Ciência\" (1882). Não estava a celebrar, mas a avisar: a morte da crença religiosa deixou um vazio que poderia ser preenchido por ideologias perigosas. O século XX provou-o com o comunismo e o fascismo.", "wrong_explanations": {"a": "A evolução de Darwin desafiou os relatos da criação, mas ele não fez esta declaração filosófica.", "c": "Freud analisou a religião psicologicamente, mas não usou esta frase.", "d": "Dawkins é um ateu moderno que veio muito depois."}}, "es": {"question": "¿Quién escribió: \"Dios ha muerto\"?", "options": [{"id": "a", "text": "Charles Darwin"}, {"id": "b", "text": "Friedrich Nietzsche"}, {"id": "c", "text": "Sigmund Freud"}, {"id": "d", "text": "Richard Dawkins"}], "explanation": "Nietzsche escribió esto en \"La gaya ciencia\" (1882). No estaba celebrando, sino advirtiendo: la muerte de la creencia religiosa dejó un vacío que podría ser llenado por ideologías peligrosas. El siglo XX lo demostró con el comunismo y el fascismo.", "wrong_explanations": {"a": "La evolución de Darwin desafió los relatos de la creación, pero no hizo esta declaración filosófica.", "c": "Freud analizó la religión psicológicamente, pero no usó esta frase.", "d": "Dawkins es un ateo moderno que vino mucho después."}}, "fr": {"question": "Qui a écrit : \"Dieu est mort\" ?", "options": [{"id": "a", "text": "Charles Darwin"}, {"id": "b", "text": "Friedrich Nietzsche"}, {"id": "c", "text": "Sigmund Freud"}, {"id": "d", "text": "Richard Dawkins"}], "explanation": "Nietzsche a écrit ceci dans \"Le Gai Savoir\" (1882). Il ne célébrait pas, mais avertissait : la mort de la croyance religieuse a laissé un vide qui pourrait être comblé par des idéologies dangereuses. Le XXe siècle l''a prouvé avec le communisme et le fascisme.", "wrong_explanations": {"a": "L''évolution de Darwin a défié les récits de la création, mais il n''a pas fait cette déclaration philosophique.", "c": "Freud a analysé la religion psychologiquement, mais n''a pas utilisé cette phrase.", "d": "Dawkins est un athée moderne qui est venu bien plus tard."}}}'::jsonb WHERE question = 'Who wrote: "God is dead"?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem disse: \"O único bem é o conhecimento e o único mal é a ignorância\"?", "options": [{"id": "a", "text": "Platão"}, {"id": "b", "text": "Sócrates"}, {"id": "c", "text": "Aristóteles"}, {"id": "d", "text": "Confúcio"}], "explanation": "Sócrates sustentava que o conhecimento é a chave para a virtude — que as pessoas erram por ignorância, não por malícia. Embora incompleta (a evasão deliberada existe), enfatiza o papel central da razão na ética.", "wrong_explanations": {"a": "Platão desenvolveu a teoria das Formas, mas isto é socrático.", "c": "Aristóteles equilibrou virtudes intelectuais e morais de forma diferente.", "d": "Confúcio focava-se na harmonia social e nos rituais."}}, "es": {"question": "¿Quién dijo: \"El único bien es el conocimiento y el único mal es la ignorancia\"?", "options": [{"id": "a", "text": "Platón"}, {"id": "b", "text": "Sócrates"}, {"id": "c", "text": "Aristóteles"}, {"id": "d", "text": "Confucio"}], "explanation": "Sócrates sostenía que el conocimiento es la clave de la virtud — que las personas se equivocan por ignorancia, no por malicia. Aunque incompleta (la evasión deliberada existe), enfatiza el papel central de la razón en la ética.", "wrong_explanations": {"a": "Platón desarrolló la teoría de las Formas, pero esto es socrático.", "c": "Aristóteles equilibró virtudes intelectuales y morales de forma diferente.", "d": "Confucio se enfocaba en la armonía social y los rituales."}}, "fr": {"question": "Qui a dit : \"Le seul bien est la connaissance et le seul mal est l''ignorance\" ?", "options": [{"id": "a", "text": "Platon"}, {"id": "b", "text": "Socrate"}, {"id": "c", "text": "Aristote"}, {"id": "d", "text": "Confucius"}], "explanation": "Socrate soutenait que la connaissance est la clé de la vertu — que les gens font le mal par ignorance, pas par malveillance. Bien qu''incomplète (l''évasion délibérée existe), elle souligne le rôle central de la raison dans l''éthique.", "wrong_explanations": {"a": "Platon a développé la théorie des Formes, mais ceci est socratique.", "c": "Aristote a équilibré les vertus intellectuelles et morales différemment.", "d": "Confucius se concentrait sur l''harmonie sociale et les rituels."}}}'::jsonb WHERE question = 'Who said: "The only good is knowledge and the only evil is ignorance"?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem escreveu: \"Não é da benevolência do talhante, do cervejeiro ou do padeiro que esperamos o nosso jantar\"?", "options": [{"id": "a", "text": "David Ricardo"}, {"id": "b", "text": "Adam Smith"}, {"id": "c", "text": "John Locke"}, {"id": "d", "text": "Thomas Malthus"}], "explanation": "Adam Smith escreveu isto em \"A Riqueza das Nações\" (1776), explicando que o autointeresse, canalizado pela troca livre, serve a todos. O talhante serve-o não por caridade, mas porque lhe paga — e ambos beneficiam.", "wrong_explanations": {"a": "Ricardo desenvolveu a vantagem comparativa, mas isto é de Smith.", "c": "Locke focava-se nos direitos naturais e na propriedade.", "d": "Malthus escreveu sobre população, não sobre trocas de mercado."}}, "es": {"question": "¿Quién escribió: \"No es de la benevolencia del carnicero, el cervecero o el panadero de donde esperamos nuestra cena\"?", "options": [{"id": "a", "text": "David Ricardo"}, {"id": "b", "text": "Adam Smith"}, {"id": "c", "text": "John Locke"}, {"id": "d", "text": "Thomas Malthus"}], "explanation": "Adam Smith escribió esto en \"La Riqueza de las Naciones\" (1776), explicando que el autointerés, canalizado por el libre intercambio, sirve a todos. El carnicero te sirve no por caridad sino porque le pagas — y ambos se benefician.", "wrong_explanations": {"a": "Ricardo desarrolló la ventaja comparativa, pero esto es de Smith.", "c": "Locke se enfocaba en los derechos naturales y la propiedad.", "d": "Malthus escribió sobre población, no sobre intercambios de mercado."}}, "fr": {"question": "Qui a écrit : \"Ce n''est pas de la bienveillance du boucher, du brasseur ou du boulanger que nous attendons notre dîner\" ?", "options": [{"id": "a", "text": "David Ricardo"}, {"id": "b", "text": "Adam Smith"}, {"id": "c", "text": "John Locke"}, {"id": "d", "text": "Thomas Malthus"}], "explanation": "Adam Smith a écrit ceci dans \"La Richesse des nations\" (1776), expliquant que l''intérêt personnel, canalisé par le libre échange, sert tout le monde. Le boucher vous sert non par charité mais parce que vous le payez — et les deux en bénéficient.", "wrong_explanations": {"a": "Ricardo a développé l''avantage comparatif, mais ceci est de Smith.", "c": "Locke se concentrait sur les droits naturels et la propriété.", "d": "Malthus écrivait sur la population, pas sur les échanges de marché."}}}'::jsonb WHERE question = 'Who wrote: "It is not from the benevolence of the butcher, the brewer, or the baker that we expect our dinner"?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem disse: \"Os filósofos apenas interpretaram o mundo; o que importa é transformá-lo\"?", "options": [{"id": "a", "text": "Georg Hegel"}, {"id": "b", "text": "Karl Marx"}, {"id": "c", "text": "Friedrich Engels"}, {"id": "d", "text": "Vladimir Lenine"}], "explanation": "Marx escreveu isto nas suas \"Teses sobre Feuerbach\" (1845). Embora a ação importe, a rejeição de Marx da interpretação cuidadosa levou a mudanças que mataram milhões. Compreender o mundo corretamente ANTES de agir é essencial.", "wrong_explanations": {"a": "Hegel foi a influência filosófica de Marx, mas não escreveu isto.", "c": "Engels era colaborador de Marx, mas isto é da obra solo de Marx.", "d": "Lenine aplicou as ideias de Marx posteriormente."}}, "es": {"question": "¿Quién dijo: \"Los filósofos solo han interpretado el mundo; lo que importa es transformarlo\"?", "options": [{"id": "a", "text": "Georg Hegel"}, {"id": "b", "text": "Karl Marx"}, {"id": "c", "text": "Friedrich Engels"}, {"id": "d", "text": "Vladimir Lenin"}], "explanation": "Marx escribió esto en sus \"Tesis sobre Feuerbach\" (1845). Aunque la acción importa, el rechazo de Marx de la interpretación cuidadosa llevó a cambios que mataron a millones. Comprender el mundo correctamente ANTES de actuar es esencial.", "wrong_explanations": {"a": "Hegel fue la influencia filosófica de Marx, pero no escribió esto.", "c": "Engels era colaborador de Marx, pero esto es de la obra individual de Marx.", "d": "Lenin aplicó las ideas de Marx posteriormente."}}, "fr": {"question": "Qui a dit : \"Les philosophes n''ont fait qu''interpréter le monde ; ce qui importe, c''est de le transformer\" ?", "options": [{"id": "a", "text": "Georg Hegel"}, {"id": "b", "text": "Karl Marx"}, {"id": "c", "text": "Friedrich Engels"}, {"id": "d", "text": "Vladimir Lénine"}], "explanation": "Marx a écrit ceci dans ses \"Thèses sur Feuerbach\" (1845). Bien que l''action compte, le rejet par Marx de l''interprétation soigneuse a mené à des changements qui ont tué des millions. Comprendre correctement le monde AVANT d''agir est essentiel.", "wrong_explanations": {"a": "Hegel était l''influence philosophique de Marx, mais n''a pas écrit cela.", "c": "Engels était le collaborateur de Marx, mais ceci vient de l''œuvre personnelle de Marx.", "d": "Lénine a appliqué les idées de Marx plus tard."}}}'::jsonb WHERE question = 'Who said: "The philosophers have only interpreted the world; the point is to change it"?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Quem escreveu: \"Ser é ser percebido\"?", "options": [{"id": "a", "text": "John Locke"}, {"id": "b", "text": "George Berkeley"}, {"id": "c", "text": "David Hume"}, {"id": "d", "text": "Immanuel Kant"}], "explanation": "O \"esse est percipi\" de Berkeley nega a realidade objetiva — afirmando que as coisas só existem quando percebidas. Este idealismo contradiz a primazia da existência: a realidade existe independentemente da perceção. Quando fecha os olhos, o mundo não desaparece.", "wrong_explanations": {"a": "Locke era empirista e acreditava na realidade externa.", "c": "Hume era cético, mas não negava a existência externa de forma tão extrema.", "d": "Kant postulou coisas-em-si existindo para além da perceção."}}, "es": {"question": "¿Quién escribió: \"Ser es ser percibido\"?", "options": [{"id": "a", "text": "John Locke"}, {"id": "b", "text": "George Berkeley"}, {"id": "c", "text": "David Hume"}, {"id": "d", "text": "Immanuel Kant"}], "explanation": "El \"esse est percipi\" de Berkeley niega la realidad objetiva — afirmando que las cosas solo existen cuando son percibidas. Este idealismo contradice la primacía de la existencia: la realidad existe independientemente de la percepción. Cuando cierras los ojos, el mundo no desaparece.", "wrong_explanations": {"a": "Locke era empirista y creía en la realidad externa.", "c": "Hume era escéptico, pero no negaba la existencia externa tan extremamente.", "d": "Kant postuló cosas-en-sí existiendo más allá de la percepción."}}, "fr": {"question": "Qui a écrit : \"Être, c''est être perçu\" ?", "options": [{"id": "a", "text": "John Locke"}, {"id": "b", "text": "George Berkeley"}, {"id": "c", "text": "David Hume"}, {"id": "d", "text": "Emmanuel Kant"}], "explanation": "L''\"esse est percipi\" de Berkeley nie la réalité objective — affirmant que les choses n''existent que lorsqu''elles sont perçues. Cet idéalisme contredit la primauté de l''existence : la réalité existe indépendamment de la perception. Quand vous fermez les yeux, le monde ne disparaît pas.", "wrong_explanations": {"a": "Locke était empiriste et croyait en la réalité externe.", "c": "Hume était sceptique, mais ne niait pas l''existence externe aussi radicalement.", "d": "Kant a postulé des choses-en-soi existant au-delà de la perception."}}}'::jsonb WHERE question = 'Who wrote: "To be is to be perceived"?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Qual é o oposto de \"altruísmo\" em ética?", "options": [{"id": "a", "text": "Crueldade"}, {"id": "b", "text": "Autointeresse racional"}, {"id": "c", "text": "Indiferença"}, {"id": "d", "text": "Hedonismo"}], "explanation": "O altruísmo sustenta que o autossacrifício pelos outros é moral. O oposto é o autointeresse racional (egoísmo): perseguir a própria vida e felicidade como propósito mais elevado. Isto NÃO é crueldade — inclui respeitar os direitos dos outros.", "wrong_explanations": {"a": "Crueldade é prejudicar os outros por si só — nem altruísta nem propriamente egoísta.", "c": "Indiferença não é uma posição moral — é ausência de valoração.", "d": "Hedonismo busca prazer independentemente das consequências — não é autointeresse racional."}}, "es": {"question": "¿Cuál es el opuesto de \"altruismo\" en ética?", "options": [{"id": "a", "text": "Crueldad"}, {"id": "b", "text": "Autointerés racional"}, {"id": "c", "text": "Indiferencia"}, {"id": "d", "text": "Hedonismo"}], "explanation": "El altruismo sostiene que el autosacrificio por otros es moral. El opuesto es el autointerés racional (egoísmo): perseguir la propia vida y felicidad como propósito más elevado. Esto NO es crueldad — incluye respetar los derechos de otros.", "wrong_explanations": {"a": "La crueldad es dañar a otros por sí misma — ni altruista ni propiamente egoísta.", "c": "La indiferencia no es una posición moral — es ausencia de valoración.", "d": "El hedonismo busca placer sin importar las consecuencias — no es autointerés racional."}}, "fr": {"question": "Quel est l''opposé de l''\"altruisme\" en éthique ?", "options": [{"id": "a", "text": "La cruauté"}, {"id": "b", "text": "L''intérêt personnel rationnel"}, {"id": "c", "text": "L''indifférence"}, {"id": "d", "text": "L''hédonisme"}], "explanation": "L''altruisme soutient que le sacrifice de soi pour les autres est moral. L''opposé est l''intérêt personnel rationnel (égoïsme) : poursuivre sa propre vie et son bonheur comme but le plus élevé. Ce N''EST PAS de la cruauté — cela inclut le respect des droits des autres.", "wrong_explanations": {"a": "La cruauté consiste à nuire aux autres pour le plaisir — ni altruiste ni proprement égoïste.", "c": "L''indifférence n''est pas une position morale — c''est l''absence de valorisation.", "d": "L''hédonisme recherche le plaisir quelles que soient les conséquences — ce n''est pas l''intérêt personnel rationnel."}}}'::jsonb WHERE question = 'What is the opposite of "altruism" in ethics?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que o \"dever\" é um conceito moral inválido quando divorciado de valores?", "options": [{"id": "a", "text": "O dever é sempre válido"}, {"id": "b", "text": "Dever sem conexão com os seus valores é obediência a comandos arbitrários"}, {"id": "c", "text": "O dever é a virtude mais elevada"}, {"id": "d", "text": "Todo dever é religioso"}], "explanation": "O ''dever'' kantiano exige ação independentemente dos seus valores ou felicidade — obediência pela obediência. Mas a moralidade válida guia-o para a SUA vida e felicidade. ''Dever'' divorciado de valores é um mandamento arbitrário sem base racional.", "wrong_explanations": {"a": "O dever precisa de um propósito — servir a sua vida. Dever sem propósito é obediência cega.", "c": "Agir apenas por dever ignora o porquê de agir. O propósito vem primeiro.", "d": "A ética secular do dever existe (Kant), mas partilha o mesmo problema."}}, "es": {"question": "¿Por qué el \"deber\" es un concepto moral inválido cuando se divorcia de los valores?", "options": [{"id": "a", "text": "El deber siempre es válido"}, {"id": "b", "text": "Deber sin conexión con tus valores es obediencia a mandatos arbitrarios"}, {"id": "c", "text": "El deber es la virtud más elevada"}, {"id": "d", "text": "Todo deber es religioso"}], "explanation": "El ''deber'' kantiano exige acción sin importar tus valores o felicidad — obediencia por la obediencia. Pero la moralidad válida te guía hacia TU vida y felicidad. ''Deber'' divorciado de valores es un mandato arbitrario sin base racional.", "wrong_explanations": {"a": "El deber necesita un propósito — servir a tu vida. Deber sin propósito es obediencia ciega.", "c": "Actuar solo por deber ignora el porqué de actuar. El propósito viene primero.", "d": "La ética secular del deber existe (Kant), pero comparte el mismo problema."}}, "fr": {"question": "Pourquoi le \"devoir\" est-il un concept moral invalide lorsqu''il est séparé des valeurs ?", "options": [{"id": "a", "text": "Le devoir est toujours valide"}, {"id": "b", "text": "Le devoir sans lien avec vos valeurs est l''obéissance à des commandements arbitraires"}, {"id": "c", "text": "Le devoir est la plus haute vertu"}, {"id": "d", "text": "Tout devoir est religieux"}], "explanation": "Le ''devoir'' kantien exige l''action indépendamment de vos valeurs ou bonheur — l''obéissance pour l''obéissance. Mais la moralité valide vous guide vers VOTRE vie et bonheur. Le ''devoir'' séparé des valeurs est un commandement arbitraire sans fondement rationnel.", "wrong_explanations": {"a": "Le devoir a besoin d''un but — servir votre vie. Le devoir sans but est l''obéissance aveugle.", "c": "Agir par devoir seul ignore pourquoi on devrait agir. Le but vient en premier.", "d": "L''éthique séculière du devoir existe (Kant), mais elle partage le même problème."}}}'::jsonb WHERE question = 'Why is "duty" an invalid moral concept when divorced from values?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é o \"relativismo moral\" e por que se autorrefuta?", "options": [{"id": "a", "text": "A visão de que a moralidade é absoluta"}, {"id": "b", "text": "A afirmação de que a moralidade varia por cultura, que é em si uma afirmação moral universal"}, {"id": "c", "text": "O relativismo é completamente válido"}, {"id": "d", "text": "A visão de que algumas coisas são erradas"}], "explanation": "O relativismo moral afirma que não há verdades morais universais — a moralidade é relativa às culturas. Mas isto É uma afirmação universal sobre moralidade. Se verdadeira, aplica-se a todos, contradizendo-se. Também não pode condenar males óbvios como o genocídio.", "wrong_explanations": {"a": "Isso é o objetivismo moral, o oposto do relativismo.", "c": "O relativismo contradiz-se ao fazer uma afirmação absoluta sobre a natureza da moralidade.", "d": "Reconhecer que algumas coisas são erradas é objetivismo moral."}}, "es": {"question": "¿Qué es el \"relativismo moral\" y por qué se autorrefuta?", "options": [{"id": "a", "text": "La opinión de que la moralidad es absoluta"}, {"id": "b", "text": "La afirmación de que la moralidad varía por cultura, que es en sí una afirmación moral universal"}, {"id": "c", "text": "El relativismo es completamente válido"}, {"id": "d", "text": "La opinión de que algunas cosas están mal"}], "explanation": "El relativismo moral afirma que no hay verdades morales universales — la moralidad es relativa a las culturas. Pero esto ES una afirmación universal sobre la moralidad. Si es verdadera, se aplica a todos, contradiciéndose. Tampoco puede condenar males obvios como el genocidio.", "wrong_explanations": {"a": "Eso es el objetivismo moral, lo opuesto del relativismo.", "c": "El relativismo se contradice al hacer una afirmación absoluta sobre la naturaleza de la moralidad.", "d": "Reconocer que algunas cosas están mal es objetivismo moral."}}, "fr": {"question": "Qu''est-ce que le \"relativisme moral\" et pourquoi est-il auto-réfutant ?", "options": [{"id": "a", "text": "L''idée que la moralité est absolue"}, {"id": "b", "text": "L''affirmation que la moralité varie selon la culture, qui est elle-même une affirmation morale universelle"}, {"id": "c", "text": "Le relativisme est parfaitement valide"}, {"id": "d", "text": "L''idée que certaines choses sont mauvaises"}], "explanation": "Le relativisme moral affirme qu''il n''y a pas de vérités morales universelles — la moralité est relative aux cultures. Mais c''EST une affirmation universelle sur la moralité. Si elle est vraie, elle s''applique à tous, se contredisant. Il ne peut pas non plus condamner des maux évidents comme le génocide.", "wrong_explanations": {"a": "C''est l''objectivisme moral, l''opposé du relativisme.", "c": "Le relativisme se contredit en faisant une affirmation absolue sur la nature de la moralité.", "d": "Reconnaître que certaines choses sont mauvaises, c''est de l''objectivisme moral."}}}'::jsonb WHERE question = 'What is "moral relativism" and why is it self-refuting?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Qual é a diferença entre valor \"intrínseco\" e valor \"objetivo\"?", "options": [{"id": "a", "text": "São iguais"}, {"id": "b", "text": "O valor intrínseco existe independentemente de quem o valorize; o valor objetivo existe em relação à vida de quem valoriza"}, {"id": "c", "text": "O intrínseco é subjetivo"}, {"id": "d", "text": "O objetivo é arbitrário"}], "explanation": "O valor intrínseco afirma que as coisas são valiosas em si mesmas, independentemente de qualquer pessoa. O valor objetivo reconhece que o valor existe EM RELAÇÃO a quem valoriza e ao padrão (vida). A comida é objetivamente valiosa para os seres vivos — mas não ''intrinsecamente'' valiosa no vazio.", "wrong_explanations": {"a": "A distinção é crucial. O valor intrínseco não tem base racional; o objetivo tem.", "c": "O valor intrínseco supostamente é objetivo-sem-sujeito, o que é incoerente.", "d": "O valor objetivo fundamenta-se nos requisitos da vida — não é arbitrário."}}, "es": {"question": "¿Cuál es la diferencia entre valor \"intrínseco\" y valor \"objetivo\"?", "options": [{"id": "a", "text": "Son iguales"}, {"id": "b", "text": "El valor intrínseco existe independientemente de quien valore; el objetivo existe en relación a la vida de quien valora"}, {"id": "c", "text": "El intrínseco es subjetivo"}, {"id": "d", "text": "El objetivo es arbitrario"}], "explanation": "El valor intrínseco afirma que las cosas son valiosas en sí mismas, sin importar nadie. El valor objetivo reconoce que el valor existe EN RELACIÓN a quien valora y al estándar (vida). La comida es objetivamente valiosa para los seres vivos — pero no ''intrínsecamente'' valiosa en el vacío.", "wrong_explanations": {"a": "La distinción es crucial. El valor intrínseco no tiene base racional; el objetivo sí.", "c": "El valor intrínseco supuestamente es objetivo-sin-sujeto, lo cual es incoherente.", "d": "El valor objetivo se fundamenta en los requisitos de la vida — no es arbitrario."}}, "fr": {"question": "Quelle est la différence entre valeur \"intrinsèque\" et valeur \"objective\" ?", "options": [{"id": "a", "text": "C''est la même chose"}, {"id": "b", "text": "La valeur intrinsèque existe indépendamment de tout valorisateur ; la valeur objective existe en relation avec la vie du valorisateur"}, {"id": "c", "text": "L''intrinsèque est subjectif"}, {"id": "d", "text": "L''objectif est arbitraire"}], "explanation": "La valeur intrinsèque affirme que les choses sont précieuses en elles-mêmes, indépendamment de quiconque. La valeur objective reconnaît que la valeur existe EN RELATION avec un valorisateur et un critère (la vie). La nourriture est objectivement précieuse pour les êtres vivants — mais pas ''intrinsèquement'' dans le vide.", "wrong_explanations": {"a": "La distinction est cruciale. La valeur intrinsèque n''a pas de fondement rationnel ; l''objective en a un.", "c": "La valeur intrinsèque est censée être objective-sans-sujet, ce qui est incohérent.", "d": "La valeur objective est fondée sur les exigences de la vie — pas arbitraire."}}}'::jsonb WHERE question = 'What is the difference between "intrinsic" and "objective" value?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a \"sorte moral\" e por que desafia as intuições morais comuns?", "options": [{"id": "a", "text": "A sorte determina a moralidade"}, {"id": "b", "text": "Resultados que não controlamos afetam os juízos morais de ações idênticas"}, {"id": "c", "text": "A moralidade é aleatória"}, {"id": "d", "text": "Pessoas com sorte são mais morais"}], "explanation": "Sorte moral: dois condutores embriagados, um atropela uma criança, outro não. A mesma imprudência, resultados diferentes por sorte — contudo julgamo-los diferentemente. Isto revela que os nossos juízos morais frequentemente incluem fatores para além do controlo do agente, o que pode ser inconsistente.", "wrong_explanations": {"a": "A sorte não determina a moralidade, mas afeta os nossos julgamentos — esse é o enigma.", "c": "A moralidade não é aleatória, mas os resultados que julgamos SÃO afetados pela aleatoriedade.", "d": "O ponto não é sobre pessoas com sorte serem morais, mas sobre julgar ações vs. resultados."}}, "es": {"question": "¿Qué es la \"suerte moral\" y por qué desafía las intuiciones morales comunes?", "options": [{"id": "a", "text": "La suerte determina la moralidad"}, {"id": "b", "text": "Resultados que no controlamos afectan los juicios morales de acciones idénticas"}, {"id": "c", "text": "La moralidad es aleatoria"}, {"id": "d", "text": "Las personas con suerte son más morales"}], "explanation": "Suerte moral: dos conductores ebrios, uno atropella a un niño, el otro no. La misma imprudencia, resultados diferentes por suerte — sin embargo los juzgamos diferente. Esto revela que nuestros juicios morales a menudo incluyen factores fuera del control del agente, lo cual puede ser inconsistente.", "wrong_explanations": {"a": "La suerte no determina la moralidad, pero afecta nuestros juicios — ese es el enigma.", "c": "La moralidad no es aleatoria, pero los resultados que juzgamos SÍ son afectados por la aleatoriedad.", "d": "El punto no es sobre personas con suerte siendo morales, sino sobre juzgar acciones vs. resultados."}}, "fr": {"question": "Qu''est-ce que la \"chance morale\" et pourquoi défie-t-elle les intuitions morales communes ?", "options": [{"id": "a", "text": "La chance détermine la moralité"}, {"id": "b", "text": "Des résultats que nous ne contrôlons pas affectent les jugements moraux d''actions identiques"}, {"id": "c", "text": "La moralité est aléatoire"}, {"id": "d", "text": "Les gens chanceux sont plus moraux"}], "explanation": "La chance morale : deux conducteurs ivres, l''un renverse un enfant, l''autre non. La même imprudence, des résultats différents par chance — pourtant nous les jugeons différemment. Cela révèle que nos jugements moraux incluent souvent des facteurs hors du contrôle de l''agent, ce qui peut être incohérent.", "wrong_explanations": {"a": "La chance ne détermine pas la moralité, mais elle affecte nos jugements — c''est l''énigme.", "c": "La moralité n''est pas aléatoire, mais les résultats que nous jugeons SONT affectés par le hasard.", "d": "Le sujet n''est pas les gens chanceux étant moraux, mais juger les actions vs. les résultats."}}}'::jsonb WHERE question = 'What is "moral luck" and why does it challenge common moral intuitions?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a \"falácia naturalista\" segundo G.E. Moore?", "options": [{"id": "a", "text": "Acreditar que a natureza existe"}, {"id": "b", "text": "Definir ''bom'' em termos de propriedades naturais como prazer ou sobrevivência"}, {"id": "c", "text": "Usar lógica na ética"}, {"id": "d", "text": "Estudar ética cientificamente"}], "explanation": "Moore argumentou que não se pode definir ''bom'' como qualquer propriedade natural (prazer, sobrevivência, etc.) porque sempre se pode perguntar ''mas ISSO é bom?''. Contudo, esta crítica não refuta que a vida é o padrão — questiona se a bondade é indefinível.", "wrong_explanations": {"a": "Acreditar na natureza é metafísica, não ética.", "c": "A lógica é essencial à ética — não é uma falácia.", "d": "O estudo científico da ética é metaética, não uma falácia."}}, "es": {"question": "¿Qué es la \"falacia naturalista\" según G.E. Moore?", "options": [{"id": "a", "text": "Creer que la naturaleza existe"}, {"id": "b", "text": "Definir ''bueno'' en términos de propiedades naturales como placer o supervivencia"}, {"id": "c", "text": "Usar lógica en la ética"}, {"id": "d", "text": "Estudiar ética científicamente"}], "explanation": "Moore argumentó que no se puede definir ''bueno'' como cualquier propiedad natural (placer, supervivencia, etc.) porque siempre se puede preguntar ''¿pero ESO es bueno?''. Sin embargo, esta crítica no refuta que la vida sea el estándar — cuestiona si la bondad es indefinible.", "wrong_explanations": {"a": "Creer en la naturaleza es metafísica, no ética.", "c": "La lógica es esencial para la ética — no es una falacia.", "d": "El estudio científico de la ética es metaética, no una falacia."}}, "fr": {"question": "Qu''est-ce que le \"sophisme naturaliste\" selon G.E. Moore ?", "options": [{"id": "a", "text": "Croire que la nature existe"}, {"id": "b", "text": "Définir ''bien'' en termes de propriétés naturelles comme le plaisir ou la survie"}, {"id": "c", "text": "Utiliser la logique en éthique"}, {"id": "d", "text": "Étudier l''éthique scientifiquement"}], "explanation": "Moore a argumenté qu''on ne peut définir ''bien'' par aucune propriété naturelle (plaisir, survie, etc.) car on peut toujours demander ''mais est-ce que CELA est bien ?'' Cependant, cette critique ne réfute pas que la vie est le critère — elle questionne si le bien est indéfinissable.", "wrong_explanations": {"a": "Croire en la nature relève de la métaphysique, pas de l''éthique.", "c": "La logique est essentielle à l''éthique — ce n''est pas un sophisme.", "d": "L''étude scientifique de l''éthique est la métaéthique, pas un sophisme."}}}'::jsonb WHERE question = 'What is the "naturalistic fallacy" according to G.E. Moore?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é o \"determinismo\" em filosofia?", "options": [{"id": "a", "text": "A visão de que os humanos têm livre-arbítrio"}, {"id": "b", "text": "A visão de que todos os eventos são necessitados por causas anteriores"}, {"id": "c", "text": "A visão de que nada pode ser conhecido"}, {"id": "d", "text": "A visão de que a realidade é subjetiva"}], "explanation": "O determinismo sustenta que todos os eventos, incluindo escolhas humanas, são completamente determinados por causas anteriores — tornando o livre-arbítrio uma ilusão. Isto contradiz o facto evidente de que os humanos escolhem e podem ser responsabilizados pelas escolhas.", "wrong_explanations": {"a": "Isso é o livre-arbítrio libertário, o oposto do determinismo.", "c": "Isso é o ceticismo, uma posição epistemológica.", "d": "Isso é o subjetivismo, um erro metafísico diferente."}}, "es": {"question": "¿Qué es el \"determinismo\" en filosofía?", "options": [{"id": "a", "text": "La opinión de que los humanos tienen libre albedrío"}, {"id": "b", "text": "La opinión de que todos los eventos son necesitados por causas anteriores"}, {"id": "c", "text": "La opinión de que nada puede ser conocido"}, {"id": "d", "text": "La opinión de que la realidad es subjetiva"}], "explanation": "El determinismo sostiene que todos los eventos, incluidas las elecciones humanas, están completamente determinados por causas anteriores — haciendo del libre albedrío una ilusión. Esto contradice el hecho evidente de que los humanos eligen y pueden ser responsabilizados por sus elecciones.", "wrong_explanations": {"a": "Eso es el libre albedrío libertario, lo opuesto del determinismo.", "c": "Eso es el escepticismo, una posición epistemológica.", "d": "Eso es el subjetivismo, un error metafísico diferente."}}, "fr": {"question": "Qu''est-ce que le \"déterminisme\" en philosophie ?", "options": [{"id": "a", "text": "L''idée que les humains ont le libre arbitre"}, {"id": "b", "text": "L''idée que tous les événements sont nécessités par des causes antérieures"}, {"id": "c", "text": "L''idée que rien ne peut être connu"}, {"id": "d", "text": "L''idée que la réalité est subjective"}], "explanation": "Le déterminisme soutient que tous les événements, y compris les choix humains, sont entièrement déterminés par des causes antérieures — faisant du libre arbitre une illusion. Cela contredit le fait évident que les humains choisissent et peuvent être tenus responsables de leurs choix.", "wrong_explanations": {"a": "C''est le libre arbitre libertarien, l''opposé du déterminisme.", "c": "C''est le scepticisme, une position épistémologique.", "d": "C''est le subjectivisme, une erreur métaphysique différente."}}}'::jsonb WHERE question = 'What is "determinism" in philosophy?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é o \"dualismo\" em relação à mente e ao corpo?", "options": [{"id": "a", "text": "Mente e corpo são a mesma coisa"}, {"id": "b", "text": "Mente e corpo são duas substâncias separadas"}, {"id": "c", "text": "Só o corpo existe"}, {"id": "d", "text": "Só a mente existe"}], "explanation": "O dualismo cartesiano sustenta que mente (substância mental) e corpo (substância física) são distintos. Isto cria o ''problema da interação'': como pode a mente não física afetar o corpo físico? Uma visão melhor: a consciência é uma atividade do cérebro, não uma substância separada.", "wrong_explanations": {"a": "Isso seria monismo ou teoria da identidade.", "c": "Isso é materialismo eliminativo — negar que estados mentais existem.", "d": "Isso é idealismo — a visão de Berkeley."}}, "es": {"question": "¿Qué es el \"dualismo\" respecto a mente y cuerpo?", "options": [{"id": "a", "text": "Mente y cuerpo son lo mismo"}, {"id": "b", "text": "Mente y cuerpo son dos sustancias separadas"}, {"id": "c", "text": "Solo el cuerpo existe"}, {"id": "d", "text": "Solo la mente existe"}], "explanation": "El dualismo cartesiano sostiene que mente (sustancia mental) y cuerpo (sustancia física) son distintos. Esto crea el ''problema de la interacción'': ¿cómo puede la mente no física afectar al cuerpo físico? Una visión mejor: la conciencia es una actividad del cerebro, no una sustancia separada.", "wrong_explanations": {"a": "Eso sería monismo o teoría de la identidad.", "c": "Eso es materialismo eliminativo — negar que los estados mentales existen.", "d": "Eso es idealismo — la visión de Berkeley."}}, "fr": {"question": "Qu''est-ce que le \"dualisme\" concernant l''esprit et le corps ?", "options": [{"id": "a", "text": "L''esprit et le corps sont la même chose"}, {"id": "b", "text": "L''esprit et le corps sont deux substances séparées"}, {"id": "c", "text": "Seul le corps existe"}, {"id": "d", "text": "Seul l''esprit existe"}], "explanation": "Le dualisme cartésien soutient que l''esprit (substance mentale) et le corps (substance physique) sont distincts. Cela crée le ''problème de l''interaction'' : comment l''esprit non physique peut-il affecter le corps physique ? Une meilleure vue : la conscience est une activité du cerveau, pas une substance séparée.", "wrong_explanations": {"a": "Ce serait le monisme ou la théorie de l''identité.", "c": "C''est le matérialisme éliminatif — nier l''existence des états mentaux.", "d": "C''est l''idéalisme — la vision de Berkeley."}}}'::jsonb WHERE question = 'What is "dualism" regarding mind and body?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é o \"problema dos universais\"?", "options": [{"id": "a", "text": "Se a linguagem é universal"}, {"id": "b", "text": "O que faz múltiplas coisas serem do mesmo tipo (ex.: o que faz todas as cadeiras serem ''cadeiras'')"}, {"id": "c", "text": "Se a verdade é universal"}, {"id": "d", "text": "Se a moralidade é universal"}], "explanation": "O problema: o que faz múltiplas coisas particulares serem instâncias do mesmo tipo? O que todas as cadeiras partilham que as torna cadeiras? Realistas dizem que os universais existem; nominalistas dizem que só existem particulares. O Objetivismo sustenta que conceitos são integrações mentais válidas de semelhanças reais.", "wrong_explanations": {"a": "A universalidade linguística é uma questão diferente.", "c": "A verdade universal é epistemologia, não este problema específico.", "d": "A universalidade moral é ética."}}, "es": {"question": "¿Qué es el \"problema de los universales\"?", "options": [{"id": "a", "text": "Si el lenguaje es universal"}, {"id": "b", "text": "Qué hace que múltiples cosas sean del mismo tipo (ej.: qué hace que todas las sillas sean ''sillas'')"}, {"id": "c", "text": "Si la verdad es universal"}, {"id": "d", "text": "Si la moralidad es universal"}], "explanation": "El problema: ¿qué hace que múltiples cosas particulares sean instancias del mismo tipo? ¿Qué comparten todas las sillas que las hace sillas? Los realistas dicen que los universales existen; los nominalistas dicen que solo existen los particulares. El Objetivismo sostiene que los conceptos son integraciones mentales válidas de similitudes reales.", "wrong_explanations": {"a": "La universalidad lingüística es una cuestión diferente.", "c": "La verdad universal es epistemología, no este problema específico.", "d": "La universalidad moral es ética."}}, "fr": {"question": "Qu''est-ce que le \"problème des universaux\" ?", "options": [{"id": "a", "text": "Si le langage est universel"}, {"id": "b", "text": "Ce qui fait que plusieurs choses sont du même type (ex. : qu''est-ce qui fait que toutes les chaises sont des ''chaises'')"}, {"id": "c", "text": "Si la vérité est universelle"}, {"id": "d", "text": "Si la moralité est universelle"}], "explanation": "Le problème : qu''est-ce qui fait que plusieurs choses particulières sont des instances du même type ? Qu''est-ce que toutes les chaises partagent qui en fait des chaises ? Les réalistes disent que les universaux existent ; les nominalistes disent que seuls les particuliers existent. L''Objectivisme soutient que les concepts sont des intégrations mentales valides de similarités réelles.", "wrong_explanations": {"a": "L''universalité linguistique est une question différente.", "c": "La vérité universelle relève de l''épistémologie, pas de ce problème spécifique.", "d": "L''universalité morale relève de l''éthique."}}}'::jsonb WHERE question = 'What is the "problem of universals"?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a \"emergência\" em filosofia da mente?", "options": [{"id": "a", "text": "As mentes emergem do nada"}, {"id": "b", "text": "Propriedades complexas surgem de componentes mais simples de formas não previsíveis a partir deles"}, {"id": "c", "text": "A consciência é uma ilusão"}, {"id": "d", "text": "A mente controla o cérebro"}], "explanation": "A emergência sustenta que sistemas complexos exibem propriedades ausentes nas suas partes — a humidade da água não está no hidrogénio ou oxigénio sozinhos. A consciência pode emergir da complexidade neural. Isto explica a mente sem dualismo respeitando a sua realidade.", "wrong_explanations": {"a": "A emergência requer um substrato do qual as propriedades emergem.", "c": "A emergência trata a consciência como real, não ilusória.", "d": "Isso seria o interacionismo dualista."}}, "es": {"question": "¿Qué es la \"emergencia\" en filosofía de la mente?", "options": [{"id": "a", "text": "Las mentes emergen de la nada"}, {"id": "b", "text": "Propiedades complejas surgen de componentes más simples de formas no predecibles a partir de ellos"}, {"id": "c", "text": "La conciencia es una ilusión"}, {"id": "d", "text": "La mente controla el cerebro"}], "explanation": "La emergencia sostiene que los sistemas complejos exhiben propiedades ausentes en sus partes — la humedad del agua no está en el hidrógeno u oxígeno solos. La conciencia puede emerger de la complejidad neural. Esto explica la mente sin dualismo respetando su realidad.", "wrong_explanations": {"a": "La emergencia requiere un sustrato del cual emergen las propiedades.", "c": "La emergencia trata la conciencia como real, no ilusoria.", "d": "Eso sería el interaccionismo dualista."}}, "fr": {"question": "Qu''est-ce que l''\"émergence\" en philosophie de l''esprit ?", "options": [{"id": "a", "text": "Les esprits émergent du néant"}, {"id": "b", "text": "Des propriétés complexes naissent de composants plus simples de façons non prévisibles à partir d''eux"}, {"id": "c", "text": "La conscience est une illusion"}, {"id": "d", "text": "L''esprit contrôle le cerveau"}], "explanation": "L''émergence soutient que les systèmes complexes présentent des propriétés absentes de leurs parties — l''humidité de l''eau n''est pas dans l''hydrogène ou l''oxygène seuls. La conscience peut émerger de la complexité neurale. Cela explique l''esprit sans dualisme tout en respectant sa réalité.", "wrong_explanations": {"a": "L''émergence nécessite un substrat d''où émergent les propriétés.", "c": "L''émergence traite la conscience comme réelle, pas illusoire.", "d": "Ce serait l''interactionnisme dualiste."}}}'::jsonb WHERE question = 'What is "emergence" in philosophy of mind?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Qual é a diferença entre \"liberdade\" e \"licença\"?", "options": [{"id": "a", "text": "São iguais"}, {"id": "b", "text": "Liberdade é liberdade dentro dos direitos; licença é liberdade para violar os direitos dos outros"}, {"id": "c", "text": "Licença é mais liberdade"}, {"id": "d", "text": "Liberdade é permissão do governo"}], "explanation": "Liberdade é a liberdade de agir dentro dos limites do respeito pelos direitos dos outros. Licença é fazer o que se quer independentemente dos direitos dos outros — incluindo roubo, agressão, fraude. A verdadeira liberdade é limitada pelo princípio de não-agressão.", "wrong_explanations": {"a": "A distinção é fundamental para compreender a liberdade correta.", "c": "Licença não é mais liberdade — destrói a liberdade ao permitir violações.", "d": "A liberdade precede o governo; não é uma permissão."}}, "es": {"question": "¿Cuál es la diferencia entre \"libertad\" y \"licencia\"?", "options": [{"id": "a", "text": "Son iguales"}, {"id": "b", "text": "Libertad es libertad dentro de los derechos; licencia es libertad para violar los derechos de otros"}, {"id": "c", "text": "La licencia es más libertad"}, {"id": "d", "text": "La libertad es permiso del gobierno"}], "explanation": "La libertad es la libertad de actuar dentro de los límites del respeto por los derechos de otros. La licencia es hacer lo que se quiera sin importar los derechos de otros — incluyendo robo, agresión, fraude. La verdadera libertad está limitada por el principio de no agresión.", "wrong_explanations": {"a": "La distinción es fundamental para comprender la libertad correcta.", "c": "La licencia no es más libertad — destruye la libertad al permitir violaciones.", "d": "La libertad precede al gobierno; no es un permiso."}}, "fr": {"question": "Quelle est la différence entre \"liberté\" et \"licence\" ?", "options": [{"id": "a", "text": "C''est la même chose"}, {"id": "b", "text": "La liberté est la liberté dans le respect des droits ; la licence est la liberté de violer les droits d''autrui"}, {"id": "c", "text": "La licence est plus de liberté"}, {"id": "d", "text": "La liberté est une permission du gouvernement"}], "explanation": "La liberté est la liberté d''agir dans les limites du respect des droits des autres. La licence consiste à faire ce qu''on veut indépendamment des droits des autres — y compris le vol, l''agression, la fraude. La vraie liberté est bornée par le principe de non-agression.", "wrong_explanations": {"a": "La distinction est fondamentale pour comprendre la liberté correcte.", "c": "La licence n''est pas plus de liberté — elle détruit la liberté en permettant les violations.", "d": "La liberté précède le gouvernement ; ce n''est pas une permission."}}}'::jsonb WHERE question = 'What is the difference between "liberty" and "license"?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a \"separação de poderes\" e por que importa?", "options": [{"id": "a", "text": "Dividir o governo entre estados"}, {"id": "b", "text": "Dividir o governo em ramos para que ninguém detenha todo o poder"}, {"id": "c", "text": "Separar igreja e estado"}, {"id": "d", "text": "Dividir a economia do governo"}], "explanation": "A separação de poderes divide o governo em ramos legislativo, executivo e judicial com pesos e contrapesos. Cada ramo limita os outros, prevenindo a concentração de poder que leva à tirania. Este design institucional protege a liberdade.", "wrong_explanations": {"a": "Isso é o federalismo — distribuição entre governo federal e estadual.", "c": "A separação igreja-estado é uma aplicação específica do governo limitado.", "d": "Isso é a economia laissez-faire, não separação de poderes."}}, "es": {"question": "¿Qué es la \"separación de poderes\" y por qué importa?", "options": [{"id": "a", "text": "Dividir el gobierno entre estados"}, {"id": "b", "text": "Dividir el gobierno en ramas para que nadie tenga todo el poder"}, {"id": "c", "text": "Separar iglesia y estado"}, {"id": "d", "text": "Dividir la economía del gobierno"}], "explanation": "La separación de poderes divide el gobierno en ramas legislativa, ejecutiva y judicial con pesos y contrapesos. Cada rama limita a las otras, previniendo la concentración de poder que lleva a la tiranía. Este diseño institucional protege la libertad.", "wrong_explanations": {"a": "Eso es el federalismo — distribución entre gobierno federal y estatal.", "c": "La separación iglesia-estado es una aplicación específica del gobierno limitado.", "d": "Eso es la economía laissez-faire, no separación de poderes."}}, "fr": {"question": "Qu''est-ce que la \"séparation des pouvoirs\" et pourquoi est-elle importante ?", "options": [{"id": "a", "text": "Diviser le gouvernement entre les états"}, {"id": "b", "text": "Diviser le gouvernement en branches pour que personne ne détienne tout le pouvoir"}, {"id": "c", "text": "Séparer l''Église et l''État"}, {"id": "d", "text": "Séparer l''économie du gouvernement"}], "explanation": "La séparation des pouvoirs divise le gouvernement en branches législative, exécutive et judiciaire avec des poids et contrepoids. Chaque branche limite les autres, empêchant la concentration du pouvoir qui mène à la tyrannie. Cette conception institutionnelle protège la liberté.", "wrong_explanations": {"a": "C''est le fédéralisme — la répartition entre gouvernement fédéral et étatique.", "c": "La séparation de l''Église et de l''État est une application spécifique du gouvernement limité.", "d": "C''est l''économie de laissez-faire, pas la séparation des pouvoirs."}}}'::jsonb WHERE question = 'What is "separation of powers" and why does it matter?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a \"revisão judicial\"?", "options": [{"id": "a", "text": "Juízes a rever as suas próprias decisões"}, {"id": "b", "text": "O poder dos tribunais de anular leis que violam a Constituição"}, {"id": "c", "text": "O Congresso a rever nomeações judiciais"}, {"id": "d", "text": "O Presidente a anular decisões judiciais"}], "explanation": "A revisão judicial, estabelecida em Marbury v. Madison (1803), permite aos tribunais declarar leis inconstitucionais. Protege os direitos individuais impedindo maiorias legislativas de violar limites constitucionais. É um controlo crucial sobre excessos democráticos.", "wrong_explanations": {"a": "Isso é o processo de recurso, não revisão judicial.", "c": "Isso é a confirmação do Senado, não revisão judicial.", "d": "O executivo não pode anular os tribunais num sistema de poderes separados."}}, "es": {"question": "¿Qué es la \"revisión judicial\"?", "options": [{"id": "a", "text": "Jueces revisando sus propias decisiones"}, {"id": "b", "text": "El poder de los tribunales de anular leyes que violan la Constitución"}, {"id": "c", "text": "El Congreso revisando nombramientos judiciales"}, {"id": "d", "text": "El Presidente anulando decisiones judiciales"}], "explanation": "La revisión judicial, establecida en Marbury v. Madison (1803), permite a los tribunales declarar leyes inconstitucionales. Protege los derechos individuales impidiendo que mayorías legislativas violen los límites constitucionales. Es un control crucial sobre los excesos democráticos.", "wrong_explanations": {"a": "Eso es el proceso de apelación, no revisión judicial.", "c": "Eso es la confirmación del Senado, no revisión judicial.", "d": "El ejecutivo no puede anular los tribunales en un sistema de poderes separados."}}, "fr": {"question": "Qu''est-ce que le \"contrôle de constitutionnalité\" ?", "options": [{"id": "a", "text": "Des juges révisant leurs propres décisions"}, {"id": "b", "text": "Le pouvoir des tribunaux d''annuler les lois qui violent la Constitution"}, {"id": "c", "text": "Le Congrès examinant les nominations judiciaires"}, {"id": "d", "text": "Le Président annulant les décisions de justice"}], "explanation": "Le contrôle de constitutionnalité, établi dans Marbury v. Madison (1803), permet aux tribunaux de déclarer des lois inconstitutionnelles. Il protège les droits individuels en empêchant les majorités législatives de violer les limites constitutionnelles. C''est un contrôle crucial sur les excès démocratiques.", "wrong_explanations": {"a": "C''est la procédure d''appel, pas le contrôle de constitutionnalité.", "c": "C''est la confirmation du Sénat, pas le contrôle de constitutionnalité.", "d": "L''exécutif ne peut pas annuler les tribunaux dans un système de pouvoirs séparés."}}}'::jsonb WHERE question = 'What is "judicial review"?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que \"democracia\" não é o mesmo que \"liberdade\"?", "options": [{"id": "a", "text": "A democracia garante liberdade"}, {"id": "b", "text": "Democracia é governo da maioria; liberdade requer limites ao que as maiorias podem fazer"}, {"id": "c", "text": "São conceitos idênticos"}, {"id": "d", "text": "A democracia é mais importante que a liberdade"}], "explanation": "Democracia é um método de selecionar líderes (voto maioritário). Liberdade é proteção dos direitos individuais contra violação — incluindo por maiorias. Uma democracia pode votar para escravizar uma minoria. Os limites constitucionais que protegem direitos tornam a democracia compatível com a liberdade.", "wrong_explanations": {"a": "A democracia ilimitada pode votar para eliminar direitos. São necessários limites constitucionais.", "c": "Uma maioria pode votar para oprimir minorias. A liberdade requer limites ao poder da maioria.", "d": "A liberdade é o valor; a democracia é um meio que deve ser limitado."}}, "es": {"question": "¿Por qué \"democracia\" no es lo mismo que \"libertad\"?", "options": [{"id": "a", "text": "La democracia garantiza la libertad"}, {"id": "b", "text": "Democracia es gobierno de la mayoría; libertad requiere límites a lo que las mayorías pueden hacer"}, {"id": "c", "text": "Son conceptos idénticos"}, {"id": "d", "text": "La democracia es más importante que la libertad"}], "explanation": "Democracia es un método de seleccionar líderes (voto mayoritario). Libertad es protección de los derechos individuales contra violación — incluyendo por mayorías. Una democracia puede votar para esclavizar a una minoría. Los límites constitucionales que protegen derechos hacen la democracia compatible con la libertad.", "wrong_explanations": {"a": "La democracia ilimitada puede votar para eliminar derechos. Se necesitan límites constitucionales.", "c": "Una mayoría puede votar para oprimir minorías. La libertad requiere límites al poder de la mayoría.", "d": "La libertad es el valor; la democracia es un medio que debe ser limitado."}}, "fr": {"question": "Pourquoi la \"démocratie\" n''est-elle pas la même chose que la \"liberté\" ?", "options": [{"id": "a", "text": "La démocratie garantit la liberté"}, {"id": "b", "text": "La démocratie est le règne de la majorité ; la liberté exige des limites à ce que les majorités peuvent faire"}, {"id": "c", "text": "Ce sont des concepts identiques"}, {"id": "d", "text": "La démocratie est plus importante que la liberté"}], "explanation": "La démocratie est une méthode de sélection des dirigeants (vote majoritaire). La liberté est la protection des droits individuels contre la violation — y compris par les majorités. Une démocratie peut voter pour asservir une minorité. Les limites constitutionnelles protégeant les droits rendent la démocratie compatible avec la liberté.", "wrong_explanations": {"a": "La démocratie illimitée peut voter pour supprimer les droits. Des limites constitutionnelles sont nécessaires.", "c": "Une majorité peut voter pour opprimer les minorités. La liberté exige des limites au pouvoir de la majorité.", "d": "La liberté est la valeur ; la démocratie est un moyen qui doit être limité."}}}'::jsonb WHERE question = 'Why is "democracy" not the same as "freedom"?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que argumentaram os Federalist Papers?", "options": [{"id": "a", "text": "Contra a Constituição"}, {"id": "b", "text": "A favor da ratificação da Constituição com os seus pesos e contrapesos"}, {"id": "c", "text": "A favor da monarquia"}, {"id": "d", "text": "A favor da democracia pura"}], "explanation": "Os Federalist Papers (Hamilton, Madison, Jay) argumentaram a favor da ratificação da Constituição, explicando como a sua estrutura — separação de poderes, federalismo, poderes enumerados — protegeria a liberdade enquanto permitia um governo eficaz.", "wrong_explanations": {"a": "Os Anti-Federalistas opunham-se à Constituição; os Federalistas apoiavam-na.", "c": "Os Fundadores tinham acabado de rejeitar a monarquia na Revolução.", "d": "Os Fundadores rejeitaram a democracia pura como tirania da maioria."}}, "es": {"question": "¿Qué argumentaron los Federalist Papers?", "options": [{"id": "a", "text": "Contra la Constitución"}, {"id": "b", "text": "A favor de la ratificación de la Constitución con sus pesos y contrapesos"}, {"id": "c", "text": "A favor de la monarquía"}, {"id": "d", "text": "A favor de la democracia pura"}], "explanation": "Los Federalist Papers (Hamilton, Madison, Jay) argumentaron a favor de la ratificación de la Constitución, explicando cómo su estructura — separación de poderes, federalismo, poderes enumerados — protegería la libertad mientras permitía un gobierno eficaz.", "wrong_explanations": {"a": "Los Anti-Federalistas se oponían a la Constitución; los Federalistas la apoyaban.", "c": "Los Fundadores acababan de rechazar la monarquía en la Revolución.", "d": "Los Fundadores rechazaron la democracia pura como tiranía de la mayoría."}}, "fr": {"question": "Qu''ont défendu les Federalist Papers ?", "options": [{"id": "a", "text": "Contre la Constitution"}, {"id": "b", "text": "Pour la ratification de la Constitution avec ses poids et contrepoids"}, {"id": "c", "text": "Pour la monarchie"}, {"id": "d", "text": "Pour la démocratie pure"}], "explanation": "Les Federalist Papers (Hamilton, Madison, Jay) ont plaidé pour la ratification de la Constitution, expliquant comment sa structure — séparation des pouvoirs, fédéralisme, pouvoirs énumérés — protégerait la liberté tout en permettant un gouvernement efficace.", "wrong_explanations": {"a": "Les Anti-Fédéralistes s''opposaient à la Constitution ; les Fédéralistes la soutenaient.", "c": "Les Fondateurs venaient de rejeter la monarchie dans la Révolution.", "d": "Les Fondateurs ont rejeté la démocratie pure comme tyrannie de la majorité."}}}'::jsonb WHERE question = 'What did the Federalist Papers argue?';

-- === REMAINING SEED FILE 2: ECONOMICS ===

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a \"oferta e procura\"?", "options": [{"id": "a", "text": "O governo a fixar preços"}, {"id": "b", "text": "A interação que determina preços de mercado através de compradores e vendedores"}, {"id": "c", "text": "As operações internas de uma empresa"}, {"id": "d", "text": "A quantidade de dinheiro em circulação"}], "explanation": "A oferta e procura descreve como os preços emergem da interação de vendedores (oferta) e compradores (procura). Alta procura e baixa oferta aumentam preços; baixa procura e alta oferta diminuem-nos. Nenhuma autoridade central fixa preços — emergem de escolhas individuais.", "wrong_explanations": {"a": "A fixação governamental de preços distorce mercados. Os preços emergem da oferta e procura.", "c": "Operações internas não determinam preços de mercado.", "d": "A oferta monetária afeta a inflação, mas a oferta e procura determina os preços relativos."}}, "es": {"question": "¿Qué es la \"oferta y demanda\"?", "options": [{"id": "a", "text": "El gobierno fijando precios"}, {"id": "b", "text": "La interacción que determina precios de mercado a través de compradores y vendedores"}, {"id": "c", "text": "Las operaciones internas de una empresa"}, {"id": "d", "text": "La cantidad de dinero en circulación"}], "explanation": "La oferta y demanda describe cómo los precios emergen de la interacción de vendedores (oferta) y compradores (demanda). Alta demanda y baja oferta suben precios; baja demanda y alta oferta los bajan. Ninguna autoridad central fija precios — emergen de elecciones individuales.", "wrong_explanations": {"a": "La fijación gubernamental de precios distorsiona mercados. Los precios emergen de la oferta y demanda.", "c": "Las operaciones internas no determinan precios de mercado.", "d": "La oferta monetaria afecta la inflación, pero la oferta y demanda determina los precios relativos."}}, "fr": {"question": "Qu''est-ce que l''\"offre et la demande\" ?", "options": [{"id": "a", "text": "Le gouvernement fixant les prix"}, {"id": "b", "text": "L''interaction déterminant les prix du marché entre acheteurs et vendeurs"}, {"id": "c", "text": "Les opérations internes d''une entreprise"}, {"id": "d", "text": "La quantité de monnaie en circulation"}], "explanation": "L''offre et la demande décrit comment les prix émergent de l''interaction des vendeurs (offre) et des acheteurs (demande). Une forte demande et une faible offre font monter les prix ; une faible demande et une forte offre les font baisser. Aucune autorité centrale ne fixe les prix — ils émergent des choix individuels.", "wrong_explanations": {"a": "La fixation des prix par le gouvernement fausse les marchés. Les prix émergent de l''offre et la demande.", "c": "Les opérations internes ne déterminent pas les prix du marché.", "d": "La masse monétaire affecte l''inflation, mais l''offre et la demande détermine les prix relatifs."}}}'::jsonb WHERE question = 'What is "supply and demand"?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a \"vantagem comparativa\"?", "options": [{"id": "a", "text": "Ser melhor em tudo"}, {"id": "b", "text": "Especializar-se no que se faz relativamente mais eficientemente, mesmo que não absolutamente"}, {"id": "c", "text": "Ter mais recursos"}, {"id": "d", "text": "Subsídios governamentais"}], "explanation": "Mesmo que o país A seja melhor a produzir TUDO que o país B, ambos beneficiam do comércio se cada um se especializar no que faz RELATIVAMENTE melhor. É por isso que o comércio não é soma zero — a especialização aumenta a produção total.", "wrong_explanations": {"a": "Isso é vantagem absoluta. A vantagem comparativa aplica-se mesmo sem ser o melhor em nada.", "c": "Os recursos importam, mas a vantagem comparativa é sobre eficiência relativa.", "d": "Os subsídios distorcem a vantagem comparativa."}}, "es": {"question": "¿Qué es la \"ventaja comparativa\"?", "options": [{"id": "a", "text": "Ser mejor en todo"}, {"id": "b", "text": "Especializarse en lo que se hace relativamente más eficientemente, incluso si no absolutamente"}, {"id": "c", "text": "Tener más recursos"}, {"id": "d", "text": "Subsidios gubernamentales"}], "explanation": "Incluso si el país A es mejor produciendo TODO que el país B, ambos se benefician del comercio si cada uno se especializa en lo que hace RELATIVAMENTE mejor. Por eso el comercio no es suma cero — la especialización aumenta la producción total.", "wrong_explanations": {"a": "Eso es ventaja absoluta. La ventaja comparativa se aplica incluso sin ser el mejor en nada.", "c": "Los recursos importan, pero la ventaja comparativa trata de eficiencia relativa.", "d": "Los subsidios distorsionan la ventaja comparativa."}}, "fr": {"question": "Qu''est-ce que l''\"avantage comparatif\" ?", "options": [{"id": "a", "text": "Être meilleur en tout"}, {"id": "b", "text": "Se spécialiser dans ce qu''on fait relativement plus efficacement, même si pas absolument"}, {"id": "c", "text": "Avoir plus de ressources"}, {"id": "d", "text": "Les subventions gouvernementales"}], "explanation": "Même si le pays A est meilleur pour produire TOUT que le pays B, les deux bénéficient du commerce si chacun se spécialise dans ce qu''il fait RELATIVEMENT mieux. C''est pourquoi le commerce n''est pas à somme nulle — la spécialisation augmente la production totale.", "wrong_explanations": {"a": "C''est l''avantage absolu. L''avantage comparatif s''applique même sans être le meilleur en rien.", "c": "Les ressources comptent, mais l''avantage comparatif concerne l''efficacité relative.", "d": "Les subventions faussent l''avantage comparatif."}}}'::jsonb WHERE question = 'What is "comparative advantage"?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é o \"custo de oportunidade\"?", "options": [{"id": "a", "text": "O preço que se paga por algo"}, {"id": "b", "text": "O valor da melhor alternativa a que se renunciou"}, {"id": "c", "text": "O custo de oportunidades perdidas no passado"}, {"id": "d", "text": "O custo de negócios perdidos"}], "explanation": "O custo de oportunidade é o que se sacrifica ao escolher uma opção em vez de outra. Se passa uma hora a jogar em vez de trabalhar, o custo de oportunidade é o que poderia ter ganho. Toda escolha tem um custo de oportunidade.", "wrong_explanations": {"a": "Isso é o custo monetário. O custo de oportunidade inclui alternativas não monetárias.", "c": "Trata-se de escolhas atuais, não de arrependimento por decisões passadas.", "d": "Negócios perdidos são um tipo, mas o custo de oportunidade aplica-se a todas as decisões."}}, "es": {"question": "¿Qué es el \"costo de oportunidad\"?", "options": [{"id": "a", "text": "El precio que pagas por algo"}, {"id": "b", "text": "El valor de la siguiente mejor alternativa a la que renunciaste"}, {"id": "c", "text": "El costo de oportunidades perdidas en el pasado"}, {"id": "d", "text": "El costo de negocios perdidos"}], "explanation": "El costo de oportunidad es lo que sacrificas al elegir una opción sobre otra. Si pasas una hora jugando en vez de trabajar, el costo de oportunidad es lo que podrías haber ganado. Toda elección tiene un costo de oportunidad.", "wrong_explanations": {"a": "Eso es costo monetario. El costo de oportunidad incluye alternativas no monetarias.", "c": "Se trata de elecciones actuales, no de arrepentimiento por decisiones pasadas.", "d": "Negocios perdidos son un tipo, pero el costo de oportunidad se aplica a todas las decisiones."}}, "fr": {"question": "Qu''est-ce que le \"coût d''opportunité\" ?", "options": [{"id": "a", "text": "Le prix que vous payez pour quelque chose"}, {"id": "b", "text": "La valeur de la meilleure alternative à laquelle vous avez renoncé"}, {"id": "c", "text": "Le coût des opportunités manquées dans le passé"}, {"id": "d", "text": "Le coût d''affaires perdues"}], "explanation": "Le coût d''opportunité est ce que vous sacrifiez en choisissant une option plutôt qu''une autre. Si vous passez une heure à jouer au lieu de travailler, le coût d''opportunité est ce que vous auriez pu gagner. Tout choix a un coût d''opportunité.", "wrong_explanations": {"a": "C''est le coût monétaire. Le coût d''opportunité inclut les alternatives non monétaires.", "c": "Il s''agit de choix actuels, pas de regret pour des décisions passées.", "d": "Les affaires perdues sont un type, mais le coût d''opportunité s''applique à toutes les décisions."}}}'::jsonb WHERE question = 'What is "opportunity cost"?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que os monopólios tendem a formar-se apenas com ajuda governamental?", "options": [{"id": "a", "text": "Os mercados livres criam naturalmente monopólios"}, {"id": "b", "text": "Sem barreiras governamentais, a concorrência e inovação desafiam as empresas dominantes"}, {"id": "c", "text": "Os monopólios são sempre bons"}, {"id": "d", "text": "Os monopólios não podem existir"}], "explanation": "Em mercados livres, as empresas dominantes enfrentam pressão constante de concorrentes e inovadores. O governo cria monopólios duráveis através de requisitos de licenciamento, regulações que favorecem grandes empresas, patentes e outras barreiras à entrada.", "wrong_explanations": {"a": "Exemplos históricos de monopólios duradouros quase todos envolvem proteção governamental.", "c": "Os monopólios são problemáticos quando usam força governamental; a dominância natural é desafiada pela concorrência.", "d": "A dominância a curto prazo pode existir, mas monopólios persistentes precisam de barreiras governamentais."}}, "es": {"question": "¿Por qué los monopolios tienden a formarse solo con ayuda gubernamental?", "options": [{"id": "a", "text": "Los mercados libres crean naturalmente monopolios"}, {"id": "b", "text": "Sin barreras gubernamentales, la competencia e innovación desafían a las empresas dominantes"}, {"id": "c", "text": "Los monopolios siempre son buenos"}, {"id": "d", "text": "Los monopolios no pueden existir"}], "explanation": "En mercados libres, las empresas dominantes enfrentan presión constante de competidores e innovadores. El gobierno crea monopolios duraderos a través de requisitos de licencia, regulaciones que favorecen a grandes empresas, patentes y otras barreras de entrada.", "wrong_explanations": {"a": "Los ejemplos históricos de monopolios duraderos casi todos involucran protección gubernamental.", "c": "Los monopolios son problemáticos cuando usan fuerza gubernamental; la dominancia natural es desafiada por la competencia.", "d": "La dominancia a corto plazo puede existir, pero monopolios persistentes necesitan barreras gubernamentales."}}, "fr": {"question": "Pourquoi les monopoles tendent-ils à ne se former qu''avec l''aide du gouvernement ?", "options": [{"id": "a", "text": "Les marchés libres créent naturellement des monopoles"}, {"id": "b", "text": "Sans barrières gouvernementales, la concurrence et l''innovation défient les entreprises dominantes"}, {"id": "c", "text": "Les monopoles sont toujours bons"}, {"id": "d", "text": "Les monopoles ne peuvent pas exister"}], "explanation": "Dans les marchés libres, les entreprises dominantes font face à une pression constante des concurrents et innovateurs. Le gouvernement crée des monopoles durables par des exigences de licence, des réglementations favorisant les grandes entreprises, des brevets et d''autres barrières à l''entrée.", "wrong_explanations": {"a": "Les exemples historiques de monopoles durables impliquent presque tous une protection gouvernementale.", "c": "Les monopoles sont problématiques quand ils utilisent la force gouvernementale ; la dominance naturelle est défiée par la concurrence.", "d": "La dominance à court terme peut exister, mais les monopoles persistants nécessitent des barrières gouvernementales."}}}'::jsonb WHERE question = 'Why do monopolies tend to form only with government help?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é o \"risco moral\" em economia?", "options": [{"id": "a", "text": "Práticas empresariais imorais"}, {"id": "b", "text": "Quando seguros ou resgates encorajam comportamento arriscado ao remover consequências"}, {"id": "c", "text": "O perigo de demasiada moralidade"}, {"id": "d", "text": "Trabalhadores antiéticos"}], "explanation": "Risco moral: quando as pessoas estão protegidas das consequências do risco, assumem mais riscos. Os resgates bancários encorajam empréstimos imprudentes; o seguro-desemprego pode reduzir a urgência na procura de emprego. A proteção contra consequências muda o comportamento.", "wrong_explanations": {"a": "Não se trata de imoralidade, mas de estruturas de incentivos.", "c": "Não se trata de demasiada moralidade, mas de remover consequências.", "d": "Aplica-se a qualquer pessoa cujos riscos são cobertos por outros, não apenas a trabalhadores."}}, "es": {"question": "¿Qué es el \"riesgo moral\" en economía?", "options": [{"id": "a", "text": "Prácticas empresariales inmorales"}, {"id": "b", "text": "Cuando seguros o rescates alientan comportamiento arriesgado al eliminar consecuencias"}, {"id": "c", "text": "El peligro de demasiada moralidad"}, {"id": "d", "text": "Trabajadores no éticos"}], "explanation": "Riesgo moral: cuando las personas están protegidas de las consecuencias del riesgo, asumen más riesgos. Los rescates bancarios alientan préstamos imprudentes; el seguro de desempleo puede reducir la urgencia en la búsqueda de empleo. La protección contra consecuencias cambia el comportamiento.", "wrong_explanations": {"a": "No se trata de inmoralidad, sino de estructuras de incentivos.", "c": "No se trata de demasiada moralidad, sino de eliminar consecuencias.", "d": "Se aplica a cualquiera cuyos riesgos son cubiertos por otros, no solo a trabajadores."}}, "fr": {"question": "Qu''est-ce que l''\"aléa moral\" en économie ?", "options": [{"id": "a", "text": "Des pratiques commerciales immorales"}, {"id": "b", "text": "Quand les assurances ou les sauvetages encouragent les comportements risqués en supprimant les conséquences"}, {"id": "c", "text": "Le danger de trop de moralité"}, {"id": "d", "text": "Des travailleurs non éthiques"}], "explanation": "L''aléa moral : quand les gens sont protégés des conséquences du risque, ils prennent plus de risques. Les sauvetages bancaires encouragent les prêts imprudents ; l''assurance chômage peut réduire l''urgence de la recherche d''emploi. La protection contre les conséquences change le comportement.", "wrong_explanations": {"a": "Il ne s''agit pas d''immoralité mais de structures d''incitation.", "c": "Il ne s''agit pas de trop de moralité mais de supprimer les conséquences.", "d": "Cela s''applique à quiconque dont les risques sont couverts par d''autres, pas seulement aux travailleurs."}}}'::jsonb WHERE question = 'What is "moral hazard" in economics?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a \"Lei de Say\"?", "options": [{"id": "a", "text": "A procura cria a sua própria oferta"}, {"id": "b", "text": "A produção (oferta) cria os meios para comprar (procura)"}, {"id": "c", "text": "Os preços devem ser fixados por lei"}, {"id": "d", "text": "A poupança prejudica a economia"}], "explanation": "Lei de Say: ''Os produtos são pagos com produtos.'' A produção cria rendimento que cria procura. Não se pode ter procura sem primeiro produzir algo para trocar. Isto refuta a falácia de que o consumo impulsiona a economia — a produção vem primeiro.", "wrong_explanations": {"a": "Essa é a inversão keynesiana da Lei de Say.", "c": "Say defendia mercados livres, não controlos de preços.", "d": "A poupança é consumo diferido que financia investimento — ajuda a economia."}}, "es": {"question": "¿Qué es la \"Ley de Say\"?", "options": [{"id": "a", "text": "La demanda crea su propia oferta"}, {"id": "b", "text": "La producción (oferta) crea los medios para comprar (demanda)"}, {"id": "c", "text": "Los precios deben ser fijados por ley"}, {"id": "d", "text": "El ahorro perjudica la economía"}], "explanation": "Ley de Say: ''Los productos se pagan con productos.'' La producción crea ingreso que crea demanda. No se puede tener demanda sin primero producir algo para intercambiar. Esto refuta la falacia de que el consumo impulsa la economía — la producción viene primero.", "wrong_explanations": {"a": "Esa es la inversión keynesiana de la Ley de Say.", "c": "Say abogaba por los mercados libres, no por controles de precios.", "d": "El ahorro es consumo diferido que financia inversión — ayuda a la economía."}}, "fr": {"question": "Qu''est-ce que la \"Loi de Say\" ?", "options": [{"id": "a", "text": "La demande crée sa propre offre"}, {"id": "b", "text": "La production (offre) crée les moyens d''acheter (demande)"}, {"id": "c", "text": "Les prix doivent être fixés par la loi"}, {"id": "d", "text": "L''épargne nuit à l''économie"}], "explanation": "Loi de Say : ''Les produits se paient avec des produits.'' La production crée le revenu qui crée la demande. On ne peut avoir de demande sans d''abord produire quelque chose à échanger. Cela réfute le sophisme selon lequel la consommation stimule l''économie — la production vient d''abord.", "wrong_explanations": {"a": "C''est l''inversion keynésienne de la Loi de Say.", "c": "Say défendait les marchés libres, pas les contrôles de prix.", "d": "L''épargne est une consommation différée qui finance l''investissement — elle aide l''économie."}}}'::jsonb WHERE question = 'What is "Say''s Law"?';

-- === REMAINING SEED FILE 2: HISTORY ===

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Qual era o princípio central do Iluminismo?", "options": [{"id": "a", "text": "Fé acima da razão"}, {"id": "b", "text": "A razão como meio primário de conhecimento e progresso"}, {"id": "c", "text": "Retorno às tradições antigas"}, {"id": "d", "text": "Expressão emocional"}], "explanation": "O Iluminismo (séculos XVII-XVIII) defendeu a razão, a ciência, os direitos individuais e o progresso contra a tradição, autoridade e superstição. Produziu a Revolução Americana, avanços científicos e as bases filosóficas da liberdade.", "wrong_explanations": {"a": "O Iluminismo desafiou a autoridade baseada na fé com a razão.", "c": "Rompeu com as tradições antigas através da investigação racional.", "d": "O Romantismo posteriormente enfatizou a emoção; o Iluminismo priorizou a razão."}}, "es": {"question": "¿Cuál era el principio central de la Ilustración?", "options": [{"id": "a", "text": "Fe sobre razón"}, {"id": "b", "text": "La razón como medio primario de conocimiento y progreso"}, {"id": "c", "text": "Retorno a tradiciones antiguas"}, {"id": "d", "text": "Expresión emocional"}], "explanation": "La Ilustración (siglos XVII-XVIII) defendió la razón, la ciencia, los derechos individuales y el progreso contra la tradición, la autoridad y la superstición. Produjo la Revolución Americana, avances científicos y las bases filosóficas de la libertad.", "wrong_explanations": {"a": "La Ilustración desafió la autoridad basada en la fe con la razón.", "c": "Rompió con las tradiciones antiguas a través de la investigación racional.", "d": "El Romanticismo posteriormente enfatizó la emoción; la Ilustración priorizó la razón."}}, "fr": {"question": "Quel était le principe central des Lumières ?", "options": [{"id": "a", "text": "La foi avant la raison"}, {"id": "b", "text": "La raison comme moyen premier de connaissance et de progrès"}, {"id": "c", "text": "Le retour aux traditions anciennes"}, {"id": "d", "text": "L''expression émotionnelle"}], "explanation": "Les Lumières (XVIIe-XVIIIe siècles) ont défendu la raison, la science, les droits individuels et le progrès contre la tradition, l''autorité et la superstition. Elles ont produit la Révolution américaine, des avancées scientifiques et les fondements philosophiques de la liberté.", "wrong_explanations": {"a": "Les Lumières ont défié l''autorité fondée sur la foi par la raison.", "c": "Elles ont rompu avec les traditions anciennes par l''enquête rationnelle.", "d": "Le Romantisme a ensuite mis l''accent sur l''émotion ; les Lumières ont priorisé la raison."}}}'::jsonb WHERE question = 'What was the Enlightenment''s core principle?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que a coletivização soviética causou a fome ucraniana (Holodomor)?", "options": [{"id": "a", "text": "Seca natural"}, {"id": "b", "text": "A apreensão de cereais dos agricultores produtivos destruiu a produção agrícola"}, {"id": "c", "text": "Os ucranianos recusaram-se a trabalhar"}, {"id": "d", "text": "Superpopulação"}], "explanation": "A coletivização de Estaline apreendeu cereais e gado, eliminou kulaks produtivos e destruiu incentivos para produzir. A fome de 1932-33 matou 3-7 milhões de ucranianos. Foi um desastre provocado pelo homem, causado pelo planeamento central socialista.", "wrong_explanations": {"a": "O clima não foi a causa — as políticas soviéticas criaram a fome.", "c": "Os agricultores perderam incentivo para produzir porque a sua produção era apreendida.", "d": "A Ucrânia era o celeiro da Europa — o problema foi a política, não a população."}}, "es": {"question": "¿Por qué la colectivización soviética causó la hambruna ucraniana (Holodomor)?", "options": [{"id": "a", "text": "Sequía natural"}, {"id": "b", "text": "La confiscación de granos de los agricultores productivos destruyó la producción agrícola"}, {"id": "c", "text": "Los ucranianos se negaron a trabajar"}, {"id": "d", "text": "Sobrepoblación"}], "explanation": "La colectivización de Stalin confiscó granos y ganado, eliminó kulaks productivos y destruyó incentivos para producir. La hambruna de 1932-33 mató a 3-7 millones de ucranianos. Fue un desastre provocado por el hombre, causado por la planificación central socialista.", "wrong_explanations": {"a": "El clima no fue la causa — las políticas soviéticas crearon la hambruna.", "c": "Los agricultores perdieron incentivo para producir porque su producción era confiscada.", "d": "Ucrania era el granero de Europa — el problema fue la política, no la población."}}, "fr": {"question": "Pourquoi la collectivisation soviétique a-t-elle causé la famine ukrainienne (Holodomor) ?", "options": [{"id": "a", "text": "La sécheresse naturelle"}, {"id": "b", "text": "La saisie des céréales des agriculteurs productifs a détruit la production agricole"}, {"id": "c", "text": "Les Ukrainiens ont refusé de travailler"}, {"id": "d", "text": "La surpopulation"}], "explanation": "La collectivisation de Staline a saisi céréales et bétail, éliminé les koulaks productifs et détruit les incitations à produire. La famine de 1932-33 a tué 3 à 7 millions d''Ukrainiens. C''était un désastre provoqué par l''homme, causé par la planification centrale socialiste.", "wrong_explanations": {"a": "Le climat n''était pas la cause — les politiques soviétiques ont créé la famine.", "c": "Les agriculteurs ont perdu l''incitation à produire car leur production était saisie.", "d": "L''Ukraine était le grenier de l''Europe — le problème était la politique, pas la population."}}}'::jsonb WHERE question = 'Why did Soviet collectivization cause the Ukrainian famine (Holodomor)?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que foi o \"Grande Salto em Frente\" e as suas consequências?", "options": [{"id": "a", "text": "Um programa de modernização bem-sucedido"}, {"id": "b", "text": "A industrialização forçada de Mao que causou 15-55 milhões de mortes"}, {"id": "c", "text": "As reformas económicas da China nos anos 1980"}, {"id": "d", "text": "Um programa espacial"}], "explanation": "O Grande Salto em Frente de Mao (1958-1962) forçou camponeses em comunas e na produção de aço, destruindo a agricultura. A fome resultante matou estimados 15-55 milhões de pessoas — a fome mais mortífera da história humana, causada pelo planeamento central.", "wrong_explanations": {"a": "Foi um fracasso catastrófico que matou dezenas de milhões.", "c": "As reformas de Deng Xiaoping vieram depois e introduziram elementos de mercado.", "d": "O programa espacial chinês veio muito depois."}}, "es": {"question": "¿Qué fue el \"Gran Salto Adelante\" y sus consecuencias?", "options": [{"id": "a", "text": "Un programa de modernización exitoso"}, {"id": "b", "text": "La industrialización forzada de Mao que causó 15-55 millones de muertes"}, {"id": "c", "text": "Las reformas económicas de China en los años 1980"}, {"id": "d", "text": "Un programa espacial"}], "explanation": "El Gran Salto Adelante de Mao (1958-1962) forzó a los campesinos en comunas y producción de acero, destruyendo la agricultura. La hambruna resultante mató a entre 15 y 55 millones de personas — la hambruna más mortífera de la historia, causada por la planificación central.", "wrong_explanations": {"a": "Fue un fracaso catastrófico que mató a decenas de millones.", "c": "Las reformas de Deng Xiaoping vinieron después e introdujeron elementos de mercado.", "d": "El programa espacial chino vino mucho después."}}, "fr": {"question": "Qu''était le \"Grand Bond en avant\" et ses conséquences ?", "options": [{"id": "a", "text": "Un programme de modernisation réussi"}, {"id": "b", "text": "L''industrialisation forcée de Mao qui a causé 15 à 55 millions de morts"}, {"id": "c", "text": "Les réformes économiques de la Chine dans les années 1980"}, {"id": "d", "text": "Un programme spatial"}], "explanation": "Le Grand Bond en avant de Mao (1958-1962) a forcé les paysans dans des communes et la production d''acier, détruisant l''agriculture. La famine qui en a résulté a tué entre 15 et 55 millions de personnes — la famine la plus meurtrière de l''histoire humaine, causée par la planification centrale.", "wrong_explanations": {"a": "Ce fut un échec catastrophique qui a tué des dizaines de millions.", "c": "Les réformes de Deng Xiaoping sont venues après et ont introduit des éléments de marché.", "d": "Le programme spatial chinois est venu bien plus tard."}}}'::jsonb WHERE question = 'What was the "Great Leap Forward" and its consequences?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Qual foi o significado filosófico da Magna Carta (1215)?", "options": [{"id": "a", "text": "Estabeleceu a democracia"}, {"id": "b", "text": "Limitou o poder do rei e estabeleceu princípios do estado de direito"}, {"id": "c", "text": "Aboliu a monarquia"}, {"id": "d", "text": "Estabeleceu a liberdade religiosa"}], "explanation": "A Magna Carta estabeleceu que mesmo o rei está vinculado pela lei — um princípio revolucionário. Garantiu o devido processo legal e direitos de propriedade. Embora de alcance limitado inicialmente, lançou as bases para o governo constitucional e os direitos individuais.", "wrong_explanations": {"a": "Não estabeleceu a democracia, mas limitou o poder monárquico.", "c": "A Inglaterra permaneceu monarquia; a Magna Carta limitou o poder real.", "d": "A liberdade religiosa veio depois; esta focou-se nos direitos baroniais e no devido processo."}}, "es": {"question": "¿Cuál fue la significación filosófica de la Carta Magna (1215)?", "options": [{"id": "a", "text": "Estableció la democracia"}, {"id": "b", "text": "Limitó el poder del rey y estableció principios del estado de derecho"}, {"id": "c", "text": "Abolió la monarquía"}, {"id": "d", "text": "Estableció la libertad religiosa"}], "explanation": "La Carta Magna estableció que incluso el rey está sujeto a la ley — un principio revolucionario. Garantizó el debido proceso legal y derechos de propiedad. Aunque de alcance limitado inicialmente, sentó las bases para el gobierno constitucional y los derechos individuales.", "wrong_explanations": {"a": "No estableció la democracia, sino que limitó el poder monárquico.", "c": "Inglaterra siguió siendo monarquía; la Carta Magna limitó el poder real.", "d": "La libertad religiosa vino después; esta se centró en los derechos baroniales y el debido proceso."}}, "fr": {"question": "Quelle fut la signification philosophique de la Magna Carta (1215) ?", "options": [{"id": "a", "text": "Elle a établi la démocratie"}, {"id": "b", "text": "Elle a limité le pouvoir du roi et établi les principes de l''état de droit"}, {"id": "c", "text": "Elle a aboli la monarchie"}, {"id": "d", "text": "Elle a établi la liberté religieuse"}], "explanation": "La Magna Carta a établi que même le roi est lié par la loi — un principe révolutionnaire. Elle a garanti la procédure régulière et les droits de propriété. Bien que de portée limitée initialement, elle a posé les fondements du gouvernement constitutionnel et des droits individuels.", "wrong_explanations": {"a": "Elle n''a pas établi la démocratie mais limité le pouvoir monarchique.", "c": "L''Angleterre est restée une monarchie ; la Magna Carta a limité le pouvoir royal.", "d": "La liberté religieuse est venue plus tard ; celle-ci portait sur les droits des barons et la procédure régulière."}}}'::jsonb WHERE question = 'What was the philosophical significance of the Magna Carta (1215)?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que a imprensa é filosoficamente significativa?", "options": [{"id": "a", "text": "Tornou os livros mais baratos"}, {"id": "b", "text": "Permitiu a distribuição generalizada de ideias, quebrando o controlo da autoridade sobre o conhecimento"}, {"id": "c", "text": "Empregou muitos trabalhadores"}, {"id": "d", "text": "Foi inventada na América"}], "explanation": "A imprensa de Gutenberg (c. 1440) democratizou o conhecimento. Antes, as autoridades controlavam a informação através de textos manuscritos escassos. Livros impressos em massa permitiram a Reforma, a Revolução Científica e o Iluminismo ao espalhar ideias para além do controlo institucional.", "wrong_explanations": {"a": "A redução de custos foi o meio; desafiar a autoridade foi o significado.", "c": "O emprego é um impacto económico, não filosófico.", "d": "Foi inventada na Alemanha, não na América."}}, "es": {"question": "¿Por qué la imprenta es filosóficamente significativa?", "options": [{"id": "a", "text": "Hizo los libros más baratos"}, {"id": "b", "text": "Permitió la distribución generalizada de ideas, rompiendo el control de la autoridad sobre el conocimiento"}, {"id": "c", "text": "Empleó a muchos trabajadores"}, {"id": "d", "text": "Fue inventada en América"}], "explanation": "La imprenta de Gutenberg (c. 1440) democratizó el conocimiento. Antes, las autoridades controlaban la información a través de textos manuscritos escasos. Los libros impresos en masa permitieron la Reforma, la Revolución Científica y la Ilustración al difundir ideas más allá del control institucional.", "wrong_explanations": {"a": "La reducción de costos fue el medio; desafiar la autoridad fue la significación.", "c": "El empleo es un impacto económico, no filosófico.", "d": "Fue inventada en Alemania, no en América."}}, "fr": {"question": "Pourquoi l''imprimerie est-elle philosophiquement significative ?", "options": [{"id": "a", "text": "Elle a rendu les livres moins chers"}, {"id": "b", "text": "Elle a permis la diffusion généralisée des idées, brisant le contrôle de l''autorité sur la connaissance"}, {"id": "c", "text": "Elle a employé beaucoup de travailleurs"}, {"id": "d", "text": "Elle a été inventée en Amérique"}], "explanation": "L''imprimerie de Gutenberg (v. 1440) a démocratisé la connaissance. Avant, les autorités contrôlaient l''information par des textes manuscrits rares. Les livres imprimés en masse ont permis la Réforme, la Révolution scientifique et les Lumières en diffusant les idées au-delà du contrôle institutionnel.", "wrong_explanations": {"a": "La réduction des coûts était le moyen ; défier l''autorité était la signification.", "c": "L''emploi est un impact économique, pas philosophique.", "d": "Elle a été inventée en Allemagne, pas en Amérique."}}}'::jsonb WHERE question = 'Why is the printing press philosophically significant?';

-- === REMAINING SEED FILE 2: APPLIED ===

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que o socialismo falha economicamente?", "options": [{"id": "a", "text": "Não foi tentado corretamente"}, {"id": "b", "text": "Sem preços de mercado, os planeadores não podem alocar recursos racionalmente"}, {"id": "c", "text": "Só falha devido a intervenção estrangeira"}, {"id": "d", "text": "O socialismo tem sucesso económico"}], "explanation": "Sem propriedade privada e preços de mercado, os planeadores centrais não podem saber o que produzir, quanto, ou por que métodos. Os preços sinalizam escassez e valor; o socialismo destrói estes sinais. Este ''problema do cálculo'' (Mises) explica o fracasso socialista.", "wrong_explanations": {"a": "A URSS, China, Cuba, Venezuela, Coreia do Norte tentaram — falha sempre.", "c": "O fracasso económico interno precedeu qualquer pressão externa na maioria dos casos.", "d": "Toda economia socialista produziu pobreza comparada com alternativas livres."}}, "es": {"question": "¿Por qué el socialismo fracasa económicamente?", "options": [{"id": "a", "text": "No se ha intentado correctamente"}, {"id": "b", "text": "Sin precios de mercado, los planificadores no pueden asignar recursos racionalmente"}, {"id": "c", "text": "Solo fracasa por intervención extranjera"}, {"id": "d", "text": "El socialismo tiene éxito económico"}], "explanation": "Sin propiedad privada y precios de mercado, los planificadores centrales no pueden saber qué producir, cuánto ni con qué métodos. Los precios señalizan escasez y valor; el socialismo destruye estas señales. Este ''problema del cálculo'' (Mises) explica el fracaso socialista.", "wrong_explanations": {"a": "La URSS, China, Cuba, Venezuela, Corea del Norte lo intentaron — siempre fracasa.", "c": "El fracaso económico interno precedió cualquier presión externa en la mayoría de los casos.", "d": "Toda economía socialista ha producido pobreza comparada con alternativas libres."}}, "fr": {"question": "Pourquoi le socialisme échoue-t-il économiquement ?", "options": [{"id": "a", "text": "Il n''a pas été correctement essayé"}, {"id": "b", "text": "Sans prix de marché, les planificateurs ne peuvent allouer les ressources rationnellement"}, {"id": "c", "text": "Il n''échoue qu''en raison d''interventions étrangères"}, {"id": "d", "text": "Le socialisme réussit économiquement"}], "explanation": "Sans propriété privée et prix de marché, les planificateurs centraux ne peuvent savoir quoi produire, combien ni par quelles méthodes. Les prix signalent la rareté et la valeur ; le socialisme détruit ces signaux. Ce ''problème du calcul'' (Mises) explique l''échec socialiste.", "wrong_explanations": {"a": "L''URSS, la Chine, Cuba, le Venezuela, la Corée du Nord ont essayé — ça échoue toujours.", "c": "L''échec économique interne a précédé toute pression étrangère dans la plupart des cas.", "d": "Toute économie socialiste a produit la pauvreté comparée aux alternatives libres."}}}'::jsonb WHERE question = 'Why does socialism fail economically?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a \"destruição criativa\" em economia?", "options": [{"id": "a", "text": "Vandalismo de propriedade"}, {"id": "b", "text": "Inovação a substituir indústrias antigas por novas e melhores"}, {"id": "c", "text": "O governo a destruir a concorrência"}, {"id": "d", "text": "A guerra a estimular a economia"}], "explanation": "A ''destruição criativa'' de Schumpeter: novas inovações substituem indústrias antigas. Os carros substituíram os cavalos; os computadores substituíram as máquinas de escrever. Este processo, embora doloroso para trabalhadores deslocados, impulsiona o progresso. Bloqueá-lo através de proteção congela as economias no passado.", "wrong_explanations": {"a": "É metafórica — negócios antigos ''destruídos'' por serem superados pela concorrência.", "c": "A proteção governamental impede a destruição criativa, prejudicando o progresso.", "d": "A guerra destrói capital; a destruição criativa realoca-o para melhores usos."}}, "es": {"question": "¿Qué es la \"destrucción creativa\" en economía?", "options": [{"id": "a", "text": "Vandalismo de propiedad"}, {"id": "b", "text": "La innovación reemplazando industrias viejas con nuevas y mejores"}, {"id": "c", "text": "El gobierno destruyendo la competencia"}, {"id": "d", "text": "La guerra estimulando la economía"}], "explanation": "La ''destrucción creativa'' de Schumpeter: nuevas innovaciones desplazan industrias viejas. Los autos reemplazaron a los caballos; las computadoras reemplazaron a las máquinas de escribir. Este proceso, aunque doloroso para los trabajadores desplazados, impulsa el progreso. Bloquearlo mediante protección congela las economías en el pasado.", "wrong_explanations": {"a": "Es metafórica — negocios viejos ''destruidos'' al ser superados por la competencia.", "c": "La protección gubernamental impide la destrucción creativa, perjudicando el progreso.", "d": "La guerra destruye capital; la destrucción creativa lo reubica hacia mejores usos."}}, "fr": {"question": "Qu''est-ce que la \"destruction créatrice\" en économie ?", "options": [{"id": "a", "text": "Le vandalisme de propriété"}, {"id": "b", "text": "L''innovation remplaçant les vieilles industries par de nouvelles et meilleures"}, {"id": "c", "text": "Le gouvernement détruisant la concurrence"}, {"id": "d", "text": "La guerre stimulant l''économie"}], "explanation": "La ''destruction créatrice'' de Schumpeter : les nouvelles innovations remplacent les vieilles industries. Les voitures ont remplacé les chevaux ; les ordinateurs ont remplacé les machines à écrire. Ce processus, bien que douloureux pour les travailleurs déplacés, stimule le progrès. Le bloquer par la protection fige les économies dans le passé.", "wrong_explanations": {"a": "C''est métaphorique — les vieilles entreprises ''détruites'' en étant surpassées par la concurrence.", "c": "La protection gouvernementale empêche la destruction créatrice, nuisant au progrès.", "d": "La guerre détruit le capital ; la destruction créatrice le réalloue vers de meilleurs usages."}}}'::jsonb WHERE question = 'What is "creative destruction" in economics?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que impostos elevados reduzem o crescimento económico?", "options": [{"id": "a", "text": "Não reduzem — os impostos ajudam a economia"}, {"id": "b", "text": "Reduzem os incentivos para produzir, investir e assumir riscos"}, {"id": "c", "text": "Só os impostos sobre os pobres importam"}, {"id": "d", "text": "Os impostos são sempre demasiado baixos"}], "explanation": "Impostos elevados reduzem a recompensa da atividade produtiva. Se ficar apenas com 40% dos ganhos adicionais, o incentivo para ganhar mais diminui. O capital foge para jurisdições com impostos mais baixos; os empreendedores assumem menos riscos. A produção cai.", "wrong_explanations": {"a": "A evidência económica mostra consistentemente que impostos elevados reduzem o crescimento.", "c": "Impostos sobre qualquer pessoa reduzem os incentivos para essa pessoa produzir.", "d": "A questão é que nível otimiza liberdade e prosperidade — não se os impostos são ''suficientes''."}}, "es": {"question": "¿Por qué los impuestos altos reducen el crecimiento económico?", "options": [{"id": "a", "text": "No lo reducen — los impuestos ayudan a la economía"}, {"id": "b", "text": "Reducen los incentivos para producir, invertir y asumir riesgos"}, {"id": "c", "text": "Solo importan los impuestos a los pobres"}, {"id": "d", "text": "Los impuestos siempre son demasiado bajos"}], "explanation": "Los impuestos altos reducen la recompensa de la actividad productiva. Si solo te quedas con el 40% de las ganancias adicionales, el incentivo para ganar más disminuye. El capital huye a jurisdicciones con impuestos más bajos; los emprendedores asumen menos riesgos. La producción cae.", "wrong_explanations": {"a": "La evidencia económica muestra consistentemente que los impuestos altos reducen el crecimiento.", "c": "Los impuestos sobre cualquiera reducen los incentivos de esa persona para producir.", "d": "La cuestión es qué nivel optimiza libertad y prosperidad — no si los impuestos son ''suficientes''."}}, "fr": {"question": "Pourquoi les impôts élevés réduisent-ils la croissance économique ?", "options": [{"id": "a", "text": "Ils ne la réduisent pas — les impôts aident l''économie"}, {"id": "b", "text": "Ils réduisent les incitations à produire, investir et prendre des risques"}, {"id": "c", "text": "Seuls les impôts sur les pauvres comptent"}, {"id": "d", "text": "Les impôts sont toujours trop bas"}], "explanation": "Les impôts élevés réduisent la récompense de l''activité productive. Si vous ne gardez que 40% des gains supplémentaires, l''incitation à gagner plus diminue. Le capital fuit vers des juridictions à fiscalité plus faible ; les entrepreneurs prennent moins de risques. La production baisse.", "wrong_explanations": {"a": "Les preuves économiques montrent systématiquement que les impôts élevés réduisent la croissance.", "c": "Les impôts sur n''importe qui réduisent les incitations de cette personne à produire.", "d": "La question est quel niveau optimise liberté et prospérité — pas si les impôts sont ''suffisants''."}}}'::jsonb WHERE question = 'Why do high taxes reduce economic growth?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é a \"Curva de Laffer\"?", "options": [{"id": "a", "text": "Uma piada económica engraçada"}, {"id": "b", "text": "A relação que mostra que a receita fiscal sobe e depois desce à medida que as taxas aumentam"}, {"id": "c", "text": "Uma curva que mostra a inflação"}, {"id": "d", "text": "Um indicador do mercado de ações"}], "explanation": "A Curva de Laffer mostra que a 0% de taxa de imposto, a receita é zero; a 100%, a receita também é zero (ninguém trabalha). Entre estes extremos, há uma taxa que maximiza a receita. Para além dela, taxas mais altas reduzem a receita à medida que as pessoas trabalham menos ou fogem aos impostos.", "wrong_explanations": {"a": "É um princípio económico sério, nomeado pelo economista Arthur Laffer.", "c": "Relaciona-se com taxas de imposto e receita, não com inflação.", "d": "Trata-se de receita governamental, não de mercados de ações."}}, "es": {"question": "¿Qué es la \"Curva de Laffer\"?", "options": [{"id": "a", "text": "Un chiste económico gracioso"}, {"id": "b", "text": "La relación que muestra que la recaudación fiscal sube y luego baja a medida que las tasas aumentan"}, {"id": "c", "text": "Una curva que muestra la inflación"}, {"id": "d", "text": "Un indicador del mercado de valores"}], "explanation": "La Curva de Laffer muestra que al 0% de impuesto, la recaudación es cero; al 100%, también es cero (nadie trabaja). Entre estos extremos, hay una tasa que maximiza la recaudación. Más allá de ella, tasas más altas reducen la recaudación a medida que la gente trabaja menos o evade impuestos.", "wrong_explanations": {"a": "Es un principio económico serio, nombrado por el economista Arthur Laffer.", "c": "Se relaciona con tasas impositivas y recaudación, no con inflación.", "d": "Se trata de ingresos gubernamentales, no de mercados de valores."}}, "fr": {"question": "Qu''est-ce que la \"Courbe de Laffer\" ?", "options": [{"id": "a", "text": "Une blague économique amusante"}, {"id": "b", "text": "La relation montrant que les recettes fiscales augmentent puis diminuent à mesure que les taux augmentent"}, {"id": "c", "text": "Une courbe montrant l''inflation"}, {"id": "d", "text": "Un indicateur boursier"}], "explanation": "La Courbe de Laffer montre qu''à un taux d''imposition de 0%, les recettes sont nulles ; à 100%, elles sont aussi nulles (personne ne travaille). Entre ces extrêmes, il y a un taux qui maximise les recettes. Au-delà, des taux plus élevés réduisent les recettes car les gens travaillent moins ou évitent l''impôt.", "wrong_explanations": {"a": "C''est un principe économique sérieux, nommé d''après l''économiste Arthur Laffer.", "c": "Elle concerne les taux d''imposition et les recettes, pas l''inflation.", "d": "Il s''agit de recettes gouvernementales, pas de marchés boursiers."}}}'::jsonb WHERE question = 'What is the "Laffer Curve"?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que a \"teoria da escolha pública\" é importante?", "options": [{"id": "a", "text": "Prova que o governo é sempre bom"}, {"id": "b", "text": "Analisa os atores governamentais como autointeressados como todos os outros"}, {"id": "c", "text": "Prova que os mercados falham sempre"}, {"id": "d", "text": "É sobre tecnologia de votação"}], "explanation": "A escolha pública (Buchanan, Tullock) aplica o raciocínio económico à política. Políticos, burocratas e eleitores agem por autointeresse, não apenas pelo bem público. Isto explica por que programas governamentais servem interesses especiais e persistem apesar do fracasso.", "wrong_explanations": {"a": "Mostra que a falha governamental é sistemática, não acidental.", "c": "Demonstra falha governamental juntamente com a análise de mercado.", "d": "Trata de incentivos nas decisões políticas, não de máquinas de votar."}}, "es": {"question": "¿Por qué es importante la \"teoría de la elección pública\"?", "options": [{"id": "a", "text": "Prueba que el gobierno siempre es bueno"}, {"id": "b", "text": "Analiza a los actores gubernamentales como autointeresados como todos los demás"}, {"id": "c", "text": "Prueba que los mercados siempre fracasan"}, {"id": "d", "text": "Es sobre tecnología de votación"}], "explanation": "La elección pública (Buchanan, Tullock) aplica el razonamiento económico a la política. Políticos, burócratas y votantes actúan por autointerés, no solo por el bien público. Esto explica por qué los programas gubernamentales sirven a intereses especiales y persisten a pesar del fracaso.", "wrong_explanations": {"a": "Muestra que el fracaso gubernamental es sistemático, no accidental.", "c": "Demuestra fracaso gubernamental junto con el análisis de mercado.", "d": "Trata de incentivos en las decisiones políticas, no de máquinas de votar."}}, "fr": {"question": "Pourquoi la \"théorie du choix public\" est-elle importante ?", "options": [{"id": "a", "text": "Elle prouve que le gouvernement est toujours bon"}, {"id": "b", "text": "Elle analyse les acteurs gouvernementaux comme intéressés par eux-mêmes comme tout le monde"}, {"id": "c", "text": "Elle prouve que les marchés échouent toujours"}, {"id": "d", "text": "C''est sur la technologie de vote"}], "explanation": "Le choix public (Buchanan, Tullock) applique le raisonnement économique à la politique. Politiciens, bureaucrates et électeurs agissent par intérêt personnel, pas seulement pour le bien public. Cela explique pourquoi les programmes gouvernementaux servent des intérêts particuliers et persistent malgré l''échec.", "wrong_explanations": {"a": "Elle montre que l''échec gouvernemental est systématique, pas accidentel.", "c": "Elle démontre l''échec gouvernemental aux côtés de l''analyse de marché.", "d": "Il s''agit d''incitations dans les décisions politiques, pas de machines à voter."}}}'::jsonb WHERE question = 'Why is "public choice theory" important?';

-- === REMAINING SEED FILE 2: AMERICAN EXCEPTIONALISM ===

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que significa \"E Pluribus Unum\"?", "options": [{"id": "a", "text": "Em Deus confiamos"}, {"id": "b", "text": "De muitos, um"}, {"id": "c", "text": "Liberdade e justiça"}, {"id": "d", "text": "Não me pise"}], "explanation": "\"E Pluribus Unum\" (De muitos, um) era o lema original dos EUA. Referia-se à unidade de muitos estados — e depois, muitos povos unidos por princípios partilhados de liberdade. Unidade baseada em IDEIAS, não etnia ou religião.", "wrong_explanations": {"a": "''In God We Trust'' tornou-se o lema oficial em 1956.", "c": "''Liberdade e justiça para todos'' é do Juramento à Bandeira.", "d": "''Don''t Tread on Me'' é da Bandeira de Gadsden."}}, "es": {"question": "¿Qué significa \"E Pluribus Unum\"?", "options": [{"id": "a", "text": "En Dios confiamos"}, {"id": "b", "text": "De muchos, uno"}, {"id": "c", "text": "Libertad y justicia"}, {"id": "d", "text": "No me pises"}], "explanation": "\"E Pluribus Unum\" (De muchos, uno) era el lema original de EE.UU. Se refería a la unidad de muchos estados — y después, muchos pueblos unidos por principios compartidos de libertad. Unidad basada en IDEAS, no etnicidad o religión.", "wrong_explanations": {"a": "''In God We Trust'' se convirtió en el lema oficial en 1956.", "c": "''Libertad y justicia para todos'' es del Juramento a la Bandera.", "d": "''Don''t Tread on Me'' es de la Bandera de Gadsden."}}, "fr": {"question": "Que signifie \"E Pluribus Unum\" ?", "options": [{"id": "a", "text": "En Dieu nous avons confiance"}, {"id": "b", "text": "De plusieurs, un"}, {"id": "c", "text": "Liberté et justice"}, {"id": "d", "text": "Ne me marchez pas dessus"}], "explanation": "\"E Pluribus Unum\" (De plusieurs, un) était la devise originale des États-Unis. Elle faisait référence à l''unité de nombreux états — puis de nombreux peuples unis par des principes partagés de liberté. L''unité fondée sur des IDÉES, pas l''ethnie ou la religion.", "wrong_explanations": {"a": "''In God We Trust'' est devenu la devise officielle en 1956.", "c": "''Liberté et justice pour tous'' vient du Serment d''allégeance.", "d": "''Don''t Tread on Me'' vient du drapeau de Gadsden."}}}'::jsonb WHERE question = 'What does "E Pluribus Unum" mean?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Qual é a importância da Carta de Direitos?", "options": [{"id": "a", "text": "Concede direitos aos cidadãos"}, {"id": "b", "text": "Limita explicitamente o poder governamental para proteger direitos naturais preexistentes"}, {"id": "c", "text": "Estabelece a democracia"}, {"id": "d", "text": "Cria os três ramos do governo"}], "explanation": "A Carta de Direitos não concede direitos — proíbe o governo de violar direitos que já existem. ''O Congresso não fará nenhuma lei...'' Os direitos precedem o governo; as emendas limitam o poder governamental para protegê-los.", "wrong_explanations": {"a": "Os direitos não são concedidos por documentos — são inerentes à natureza humana.", "c": "A Constituição principal estabeleceu a estrutura governamental.", "d": "O corpo da Constituição cria os ramos; a Carta de Direitos limita o seu poder."}}, "es": {"question": "¿Cuál es la importancia de la Carta de Derechos?", "options": [{"id": "a", "text": "Otorga derechos a los ciudadanos"}, {"id": "b", "text": "Limita explícitamente el poder gubernamental para proteger derechos naturales preexistentes"}, {"id": "c", "text": "Establece la democracia"}, {"id": "d", "text": "Crea las tres ramas del gobierno"}], "explanation": "La Carta de Derechos no otorga derechos — prohíbe al gobierno violar derechos que ya existen. ''El Congreso no hará ninguna ley...'' Los derechos preceden al gobierno; las enmiendas limitan el poder gubernamental para protegerlos.", "wrong_explanations": {"a": "Los derechos no son otorgados por documentos — son inherentes a la naturaleza humana.", "c": "La Constitución principal estableció la estructura gubernamental.", "d": "El cuerpo de la Constitución crea las ramas; la Carta de Derechos limita su poder."}}, "fr": {"question": "Quelle est l''importance de la Déclaration des droits ?", "options": [{"id": "a", "text": "Elle accorde des droits aux citoyens"}, {"id": "b", "text": "Elle limite explicitement le pouvoir gouvernemental pour protéger des droits naturels préexistants"}, {"id": "c", "text": "Elle établit la démocratie"}, {"id": "d", "text": "Elle crée les trois branches du gouvernement"}], "explanation": "La Déclaration des droits n''accorde pas de droits — elle interdit au gouvernement de violer des droits qui existent déjà. ''Le Congrès ne fera aucune loi...'' Les droits précèdent le gouvernement ; les amendements limitent le pouvoir gouvernemental pour les protéger.", "wrong_explanations": {"a": "Les droits ne sont pas accordés par des documents — ils sont inhérents à la nature humaine.", "c": "La Constitution principale a établi la structure gouvernementale.", "d": "Le corps de la Constitution crée les branches ; la Déclaration des droits limite leur pouvoir."}}}'::jsonb WHERE question = 'What is the significance of the Bill of Rights?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que Tocqueville admirava a sociedade civil americana?", "options": [{"id": "a", "text": "Governo central forte"}, {"id": "b", "text": "Associações voluntárias a resolver problemas sem governo"}, {"id": "c", "text": "Tradições aristocráticas"}, {"id": "d", "text": "Uniformidade religiosa"}], "explanation": "Em \"A Democracia na América\" (1835), Tocqueville maravilhou-se com a forma como os americanos formavam associações voluntárias para resolver problemas — escolas, hospitais, instituições de caridade — sem esperar pelo governo. Esta sociedade civil encarnava o autogoverno e a iniciativa individual.", "wrong_explanations": {"a": "Notou o governo descentralizado e limitado da América como uma força.", "c": "A América rejeitou a aristocracia em favor da igualdade perante a lei.", "d": "A América tinha diversidade religiosa mas princípios políticos partilhados."}}, "es": {"question": "¿Por qué Tocqueville admiraba la sociedad civil americana?", "options": [{"id": "a", "text": "Gobierno central fuerte"}, {"id": "b", "text": "Asociaciones voluntarias resolviendo problemas sin gobierno"}, {"id": "c", "text": "Tradiciones aristocráticas"}, {"id": "d", "text": "Uniformidad religiosa"}], "explanation": "En \"La Democracia en América\" (1835), Tocqueville se maravilló con cómo los americanos formaban asociaciones voluntarias para resolver problemas — escuelas, hospitales, obras de caridad — sin esperar al gobierno. Esta sociedad civil encarnaba el autogobierno y la iniciativa individual.", "wrong_explanations": {"a": "Notó el gobierno descentralizado y limitado de América como una fortaleza.", "c": "América rechazó la aristocracia en favor de la igualdad ante la ley.", "d": "América tenía diversidad religiosa pero principios políticos compartidos."}}, "fr": {"question": "Pourquoi Tocqueville admirait-il la société civile américaine ?", "options": [{"id": "a", "text": "Un gouvernement central fort"}, {"id": "b", "text": "Des associations volontaires résolvant les problèmes sans gouvernement"}, {"id": "c", "text": "Des traditions aristocratiques"}, {"id": "d", "text": "L''uniformité religieuse"}], "explanation": "Dans \"De la Démocratie en Amérique\" (1835), Tocqueville s''émerveilla de la façon dont les Américains formaient des associations volontaires pour résoudre les problèmes — écoles, hôpitaux, œuvres caritatives — sans attendre le gouvernement. Cette société civile incarnait l''autogouvernement et l''initiative individuelle.", "wrong_explanations": {"a": "Il a noté le gouvernement décentralisé et limité de l''Amérique comme une force.", "c": "L''Amérique a rejeté l''aristocratie en faveur de l''égalité devant la loi.", "d": "L''Amérique avait une diversité religieuse mais des principes politiques partagés."}}}'::jsonb WHERE question = 'Why did de Tocqueville admire American civil society?';

