UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Qual é a diferença entre \"naturalismo\" e \"romantismo\" na arte?", "options": [{"id": "a", "text": "São iguais"}, {"id": "b", "text": "O naturalismo copia a realidade tal como é; o romantismo retrata a realidade como poderia e deveria ser"}, {"id": "c", "text": "O naturalismo é melhor"}, {"id": "d", "text": "O romantismo ignora a realidade"}], "explanation": "O naturalismo visa reproduzir a realidade exatamente como observada, incluindo a fealdade e a falta de sentido. O romantismo seleciona e integra elementos para apresentar ideais — a realidade como poderia ser segundo os seus valores. O Realismo Romântico combina ambos.", "wrong_explanations": {"a": "Representam abordagens diferentes ao propósito da arte.", "c": "Cada um tem valor, mas o romantismo acrescenta significado e valores à observação.", "d": "O romantismo é seletivo quanto à realidade, não desligado dela."}}, "es": {"question": "¿Cuál es la diferencia entre \"naturalismo\" y \"romanticismo\" en el arte?", "options": [{"id": "a", "text": "Son iguales"}, {"id": "b", "text": "El naturalismo copia la realidad tal como es; el romanticismo retrata la realidad como podría y debería ser"}, {"id": "c", "text": "El naturalismo es mejor"}, {"id": "d", "text": "El romanticismo ignora la realidad"}], "explanation": "El naturalismo busca reproducir la realidad exactamente como se observa, incluyendo la fealdad y la falta de sentido. El romanticismo selecciona e integra elementos para presentar ideales — la realidad como podría ser según los valores de uno. El Realismo Romántico combina ambos.", "wrong_explanations": {"a": "Representan enfoques diferentes al propósito del arte.", "c": "Cada uno tiene valor, pero el romanticismo añade significado y valores a la observación.", "d": "El romanticismo es selectivo respecto a la realidad, no desconectado de ella."}}, "fr": {"question": "Quelle est la différence entre le \"naturalisme\" et le \"romantisme\" en art ?", "options": [{"id": "a", "text": "C''est la même chose"}, {"id": "b", "text": "Le naturalisme copie la réalité telle quelle ; le romantisme dépeint la réalité telle qu''elle pourrait et devrait être"}, {"id": "c", "text": "Le naturalisme est meilleur"}, {"id": "d", "text": "Le romantisme ignore la réalité"}], "explanation": "Le naturalisme vise à reproduire la réalité exactement telle qu''observée, y compris la laideur et l''absurdité. Le romantisme sélectionne et intègre des éléments pour présenter des idéaux — la réalité telle qu''elle pourrait être selon ses valeurs. Le Réalisme Romantique combine les deux.", "wrong_explanations": {"a": "Ils représentent des approches différentes du but de l''art.", "c": "Chacun a de la valeur, mais le romantisme ajoute du sens et des valeurs à l''observation.", "d": "Le romantisme est sélectif vis-à-vis de la réalité, pas déconnecté d''elle."}}}'::jsonb WHERE question = 'What is the difference between "naturalism" and "romanticism" in art?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que Ayn Rand considerava Victor Hugo o maior romancista?", "options": [{"id": "a", "text": "As suas opiniões políticas"}, {"id": "b", "text": "A sua capacidade de criar heróis maiores que a vida que encarnam valores"}, {"id": "c", "text": "As suas frases complexas"}, {"id": "d", "text": "A sua nacionalidade francesa"}], "explanation": "Rand admirava o método Romântico de Hugo: criar personagens heroicas como Jean Valjean que encarnam valores e enfrentam escolhas morais dramáticas. Hugo projetava um universo benevolente onde a bondade pode triunfar — arte como combustível para viver.", "wrong_explanations": {"a": "Rand discordava do socialismo de Hugo, mas admirava o seu método artístico.", "c": "O estilo importa, mas Rand enfatizava o conteúdo temático e a visão heroica.", "d": "A nacionalidade é irrelevante para o mérito artístico."}}, "es": {"question": "¿Por qué Ayn Rand consideraba a Victor Hugo el mayor novelista?", "options": [{"id": "a", "text": "Sus opiniones políticas"}, {"id": "b", "text": "Su capacidad de crear héroes más grandes que la vida que encarnan valores"}, {"id": "c", "text": "Sus frases complejas"}, {"id": "d", "text": "Su nacionalidad francesa"}], "explanation": "Rand admiraba el método Romántico de Hugo: crear personajes heroicos como Jean Valjean que encarnan valores y enfrentan elecciones morales dramáticas. Hugo proyectaba un universo benevolente donde la bondad puede triunfar — arte como combustible para vivir.", "wrong_explanations": {"a": "Rand discrepaba con el socialismo de Hugo, pero admiraba su método artístico.", "c": "El estilo importa, pero Rand enfatizaba el contenido temático y la visión heroica.", "d": "La nacionalidad es irrelevante para el mérito artístico."}}, "fr": {"question": "Pourquoi Ayn Rand considérait-elle Victor Hugo comme le plus grand romancier ?", "options": [{"id": "a", "text": "Ses opinions politiques"}, {"id": "b", "text": "Sa capacité à créer des héros plus grands que nature incarnant des valeurs"}, {"id": "c", "text": "Ses phrases complexes"}, {"id": "d", "text": "Sa nationalité française"}], "explanation": "Rand admirait la méthode Romantique de Hugo : créer des personnages héroïques comme Jean Valjean qui incarnent des valeurs et font face à des choix moraux dramatiques. Hugo projetait un univers bienveillant où le bien peut triompher — l''art comme carburant pour vivre.", "wrong_explanations": {"a": "Rand était en désaccord avec le socialisme de Hugo, mais admirait sa méthode artistique.", "c": "Le style compte, mais Rand mettait l''accent sur le contenu thématique et la vision héroïque.", "d": "La nationalité est sans rapport avec le mérite artistique."}}}'::jsonb WHERE question = 'Why did Ayn Rand consider Victor Hugo the greatest novelist?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que é o \"kitsch\" em termos estéticos?", "options": [{"id": "a", "text": "Arte tradicional de alta qualidade"}, {"id": "b", "text": "Arte que manipula emoções através de clichés sem significado genuíno"}, {"id": "c", "text": "Arte abstrata moderna"}, {"id": "d", "text": "Qualquer objeto decorativo"}], "explanation": "O kitsch usa clichés sentimentais para provocar emoções fáceis sem conteúdo artístico genuíno — cachorrinhos bonitos, pores do sol, slogans inspiracionais. Fornece gratificação emocional sem o conteúdo cognitivo da arte real. É arte como comida rápida emocional.", "wrong_explanations": {"a": "A arte tradicional pode ser excelente ou kitsch dependendo da execução.", "c": "A arte abstrata pode ou não ser kitsch — depende do conteúdo.", "d": "A decoração pode ter valor estético genuíno ou ser kitsch."}}, "es": {"question": "¿Qué es el \"kitsch\" en términos estéticos?", "options": [{"id": "a", "text": "Arte tradicional de alta calidad"}, {"id": "b", "text": "Arte que manipula emociones a través de clichés sin significado genuino"}, {"id": "c", "text": "Arte abstracto moderno"}, {"id": "d", "text": "Cualquier objeto decorativo"}], "explanation": "El kitsch usa clichés sentimentales para provocar emociones fáciles sin contenido artístico genuino — perritos bonitos, atardeceres, eslóganes inspiracionales. Proporciona gratificación emocional sin el contenido cognitivo del arte real. Es arte como comida chatarra emocional.", "wrong_explanations": {"a": "El arte tradicional puede ser excelente o kitsch dependiendo de la ejecución.", "c": "El arte abstracto puede o no ser kitsch — depende del contenido.", "d": "La decoración puede tener valor estético genuino o ser kitsch."}}, "fr": {"question": "Qu''est-ce que le \"kitsch\" en termes esthétiques ?", "options": [{"id": "a", "text": "L''art traditionnel de haute qualité"}, {"id": "b", "text": "L''art qui manipule les émotions par des clichés sans signification véritable"}, {"id": "c", "text": "L''art abstrait moderne"}, {"id": "d", "text": "N''importe quel objet décoratif"}], "explanation": "Le kitsch utilise des clichés sentimentaux pour déclencher des émotions faciles sans véritable contenu artistique — chiots mignons, couchers de soleil, slogans inspirants. Il fournit une gratification émotionnelle sans le contenu cognitif du vrai art. C''est l''art comme malbouffe émotionnelle.", "wrong_explanations": {"a": "L''art traditionnel peut être excellent ou kitsch selon l''exécution.", "c": "L''art abstrait peut ou non être du kitsch — cela dépend du contenu.", "d": "La décoration peut avoir une véritable valeur esthétique ou être du kitsch."}}}'::jsonb WHERE question = 'What is "kitsch" in aesthetic terms?';

