UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que demonstra \"12 Homens em Fúria\" (1957) sobre razão e persuasão?", "options": [{"id": "a", "text": "O governo da maioria está sempre certo"}, {"id": "b", "text": "Uma pessoa racional pode persuadir os outros através de evidência e lógica"}, {"id": "c", "text": "A emoção é mais poderosa que a razão"}, {"id": "d", "text": "Os júris devem ser eliminados"}], "explanation": "O Jurado nº 8 (Henry Fonda) fica sozinho contra 11 outros, apresentando sistematicamente evidências e levantando dúvidas razoáveis. Através de argumentação racional, persuade os outros um a um. Celebra o poder da razão contra o conformismo e o preconceito.", "wrong_explanations": {"a": "O filme mostra que a maioria estava inicialmente errada devido a preconceito e pressa.", "c": "A razão acaba por superar as reações emocionais de vários jurados.", "d": "Celebra a deliberação do júri quando feita adequadamente."}}, "es": {"question": "¿Qué demuestra \"12 Hombres en Pugna\" (1957) sobre razón y persuasión?", "options": [{"id": "a", "text": "El gobierno de la mayoría siempre tiene razón"}, {"id": "b", "text": "Una persona racional puede persuadir a otros mediante evidencia y lógica"}, {"id": "c", "text": "La emoción es más poderosa que la razón"}, {"id": "d", "text": "Los jurados deben ser eliminados"}], "explanation": "El Jurado nº 8 (Henry Fonda) se mantiene solo contra 11 otros, presentando sistemáticamente evidencias y planteando dudas razonables. A través de argumentación racional, persuade a los otros uno por uno. Celebra el poder de la razón contra el conformismo y el prejuicio.", "wrong_explanations": {"a": "La película muestra que la mayoría estaba inicialmente equivocada debido a prejuicio y prisa.", "c": "La razón finalmente supera las reacciones emocionales de varios jurados.", "d": "Celebra la deliberación del jurado cuando se hace adecuadamente."}}, "fr": {"question": "Que démontre \"Douze hommes en colère\" (1957) sur la raison et la persuasion ?", "options": [{"id": "a", "text": "La règle de la majorité a toujours raison"}, {"id": "b", "text": "Une personne rationnelle peut persuader les autres par les preuves et la logique"}, {"id": "c", "text": "L''émotion est plus puissante que la raison"}, {"id": "d", "text": "Les jurys devraient être supprimés"}], "explanation": "Le juré nº 8 (Henry Fonda) se tient seul contre 11 autres, présentant systématiquement des preuves et soulevant des doutes raisonnables. Par l''argumentation rationnelle, il persuade les autres un par un. Le film célèbre le pouvoir de la raison contre le conformisme et les préjugés.", "wrong_explanations": {"a": "Le film montre que la majorité avait initialement tort à cause de préjugés et de précipitation.", "c": "La raison finit par surmonter les réactions émotionnelles de plusieurs jurés.", "d": "Il célèbre la délibération du jury quand elle est bien menée."}}}'::jsonb WHERE question = 'What does "12 Angry Men" (1957) demonstrate about reason and persuasion?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que critica filosoficamente \"Wall-E\" (2008)?", "options": [{"id": "a", "text": "O ambientalismo"}, {"id": "b", "text": "O consumismo levando à passividade e perda de agência humana"}, {"id": "c", "text": "A tecnologia em geral"}, {"id": "d", "text": "A exploração espacial"}], "explanation": "Wall-E retrata humanos como consumidores passivos que perderam a capacidade de andar, pensar ou agir independentemente. Embora existam temas ambientalistas, a crítica mais profunda é da perda de agência humana pelo conforto e consumo — tornar-se menos que humano.", "wrong_explanations": {"a": "Os temas ambientais existem mas não são a mensagem mais profunda.", "c": "O próprio Wall-E é um retrato positivo de curiosidade e propósito.", "d": "O espaço é o cenário, não o alvo da crítica."}}, "es": {"question": "¿Qué critica filosóficamente \"Wall-E\" (2008)?", "options": [{"id": "a", "text": "El ambientalismo"}, {"id": "b", "text": "El consumismo llevando a la pasividad y pérdida de agencia humana"}, {"id": "c", "text": "La tecnología en general"}, {"id": "d", "text": "La exploración espacial"}], "explanation": "Wall-E retrata a los humanos como consumidores pasivos que han perdido la capacidad de caminar, pensar o actuar independientemente. Aunque existen temas ambientalistas, la crítica más profunda es de la pérdida de agencia humana por la comodidad y el consumo — volverse menos que humano.", "wrong_explanations": {"a": "Los temas ambientales existen pero no son el mensaje más profundo.", "c": "El propio Wall-E es un retrato positivo de curiosidad y propósito.", "d": "El espacio es el escenario, no el objetivo de la crítica."}}, "fr": {"question": "Que critique philosophiquement \"Wall-E\" (2008) ?", "options": [{"id": "a", "text": "L''environnementalisme"}, {"id": "b", "text": "Le consumérisme menant à la passivité et à la perte d''agence humaine"}, {"id": "c", "text": "La technologie en général"}, {"id": "d", "text": "L''exploration spatiale"}], "explanation": "Wall-E dépeint les humains comme des consommateurs passifs qui ont perdu la capacité de marcher, penser ou agir indépendamment. Bien que des thèmes environnementaux existent, la critique plus profonde est celle de la perte d''agence humaine par le confort et la consommation — devenir moins qu''humain.", "wrong_explanations": {"a": "Les thèmes environnementaux existent mais ne sont pas le message le plus profond.", "c": "Wall-E lui-même est un portrait positif de curiosité et de but.", "d": "L''espace est le décor, pas la cible de la critique."}}}'::jsonb WHERE question = 'What does "Wall-E" (2008) philosophically critique?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que \"Os Condenados de Shawshank\" é filosoficamente poderoso?", "options": [{"id": "a", "text": "O cenário prisional"}, {"id": "b", "text": "Mostra que a esperança e o espírito humano podem superar circunstâncias aparentemente impossíveis"}, {"id": "c", "text": "O final surpreendente"}, {"id": "d", "text": "A sua violência"}], "explanation": "Andy Dufresne mantém esperança, propósito e dignidade apesar da prisão injusta. Planeia metódicamente, ajuda os outros e alcança a liberdade através de esforço sustentado. ''Ou vives ou morres'' capta a escolha entre agência e rendição.", "wrong_explanations": {"a": "A prisão é o cenário; o tema é a agência humana e a esperança.", "c": "O final reforça o tema; não é mera surpresa.", "d": "A violência é mínima; o filme é sobre transcender as circunstâncias."}}, "es": {"question": "¿Por qué \"Cadena Perpetua\" es filosóficamente poderosa?", "options": [{"id": "a", "text": "Su escenario carcelario"}, {"id": "b", "text": "Muestra que la esperanza y el espíritu humano pueden superar circunstancias aparentemente imposibles"}, {"id": "c", "text": "Su final sorprendente"}, {"id": "d", "text": "Su violencia"}], "explanation": "Andy Dufresne mantiene esperanza, propósito y dignidad a pesar del encarcelamiento injusto. Planifica metódicamente, ayuda a otros y logra la libertad a través del esfuerzo sostenido. ''O te pones a vivir o te pones a morir'' captura la elección entre agencia y rendición.", "wrong_explanations": {"a": "La prisión es el escenario; el tema es la agencia humana y la esperanza.", "c": "El final refuerza el tema; no es mera sorpresa.", "d": "La violencia es mínima; la película trata de trascender las circunstancias."}}, "fr": {"question": "Pourquoi \"Les Évadés\" est-il philosophiquement puissant ?", "options": [{"id": "a", "text": "Son cadre carcéral"}, {"id": "b", "text": "Il montre que l''espoir et l''esprit humain peuvent surmonter des circonstances apparemment impossibles"}, {"id": "c", "text": "Sa fin surprenante"}, {"id": "d", "text": "Sa violence"}], "explanation": "Andy Dufresne maintient l''espoir, le but et la dignité malgré un emprisonnement injuste. Il planifie méthodiquement, aide les autres et atteint la liberté par un effort soutenu. ''Il faut s''occuper de vivre ou s''occuper de mourir'' capture le choix entre l''agence et la reddition.", "wrong_explanations": {"a": "La prison est le cadre ; le thème est l''agence humaine et l''espoir.", "c": "La fin renforce le thème ; ce n''est pas une simple surprise.", "d": "La violence est minimale ; le film parle de transcender les circonstances."}}}'::jsonb WHERE question = 'Why is "The Shawshank Redemption" philosophically powerful?';

