UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Que valor filosófico celebra \"Eye of the Tiger\" dos Survivor?", "options": [{"id": "a", "text": "Agressão e dominação"}, {"id": "b", "text": "Perseverança, autodisciplina e a vontade de alcançar"}, {"id": "c", "text": "Violência no desporto"}, {"id": "d", "text": "Fama e fortuna"}], "explanation": "A canção celebra a disciplina e determinação necessárias para superar desafios. ''Rising up to the challenge of our rival'' — é sobre esforço focado, treino e vontade. O tigre é um símbolo de poder controlado e propósito.", "wrong_explanations": {"a": "É sobre competição disciplinada, não agressão.", "c": "O boxe é o contexto; o tema é a realização mais ampla.", "d": "O objetivo é a vitória pelo esforço, não a fama."}}, "es": {"question": "¿Qué valor filosófico celebra \"Eye of the Tiger\" de Survivor?", "options": [{"id": "a", "text": "Agresión y dominación"}, {"id": "b", "text": "Perseverancia, autodisciplina y la voluntad de lograr"}, {"id": "c", "text": "Violencia en el deporte"}, {"id": "d", "text": "Fama y fortuna"}], "explanation": "La canción celebra la disciplina y determinación necesarias para superar desafíos. ''Rising up to the challenge of our rival'' — se trata de esfuerzo enfocado, entrenamiento y voluntad. El tigre es un símbolo de poder controlado y propósito.", "wrong_explanations": {"a": "Se trata de competencia disciplinada, no agresión.", "c": "El boxeo es el contexto; el tema es el logro más amplio.", "d": "El objetivo es la victoria por el esfuerzo, no la fama."}}, "fr": {"question": "Quelle valeur philosophique célèbre \"Eye of the Tiger\" de Survivor ?", "options": [{"id": "a", "text": "L''agression et la domination"}, {"id": "b", "text": "La persévérance, l''autodiscipline et la volonté d''accomplir"}, {"id": "c", "text": "La violence dans le sport"}, {"id": "d", "text": "La gloire et la fortune"}], "explanation": "La chanson célèbre la discipline et la détermination nécessaires pour surmonter les défis. ''Rising up to the challenge of our rival'' — c''est l''effort concentré, l''entraînement et la volonté. Le tigre est un symbole de puissance contrôlée et de but.", "wrong_explanations": {"a": "Il s''agit de compétition disciplinée, pas d''agression.", "c": "La boxe est le contexte ; le thème est l''accomplissement au sens large.", "d": "L''objectif est la victoire par l''effort, pas la gloire."}}}'::jsonb WHERE question = 'What philosophical value does "Eye of the Tiger" by Survivor celebrate?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "O que torna \"Bohemian Rhapsody\" filosoficamente interessante?", "options": [{"id": "a", "text": "A sua duração"}, {"id": "b", "text": "Explora culpa, consequência e a impossibilidade de escapar às próprias ações"}, {"id": "c", "text": "A secção de ópera"}, {"id": "d", "text": "O seu sucesso comercial"}], "explanation": "A canção narra um homem que cometeu um assassínio enfrentando as consequências. ''Mama, just killed a man... too late, my time has come.'' Explora culpa, arrependimento e como as ações têm consequências inescapáveis — não se pode desfazer o que se fez.", "wrong_explanations": {"a": "A duração é estrutural; o conteúdo é filosoficamente rico.", "c": "A secção de ópera expressa o conflito interno de forma dramática.", "d": "O sucesso reflete ressonância, mas o significado é o que o torna importante."}}, "es": {"question": "¿Qué hace que \"Bohemian Rhapsody\" sea filosóficamente interesante?", "options": [{"id": "a", "text": "Su duración"}, {"id": "b", "text": "Explora culpa, consecuencia y la imposibilidad de escapar de las propias acciones"}, {"id": "c", "text": "La sección de ópera"}, {"id": "d", "text": "Su éxito comercial"}], "explanation": "La canción narra a un hombre que ha cometido un asesinato enfrentando las consecuencias. ''Mama, just killed a man... too late, my time has come.'' Explora culpa, arrepentimiento y cómo las acciones tienen consecuencias inescapables — no se puede deshacer lo hecho.", "wrong_explanations": {"a": "La duración es estructural; el contenido es filosóficamente rico.", "c": "La sección de ópera expresa el conflicto interno dramáticamente.", "d": "El éxito refleja resonancia, pero el significado es lo que lo hace importante."}}, "fr": {"question": "Qu''est-ce qui rend \"Bohemian Rhapsody\" philosophiquement intéressant ?", "options": [{"id": "a", "text": "Sa durée"}, {"id": "b", "text": "Elle explore la culpabilité, les conséquences et l''impossibilité d''échapper à ses actes"}, {"id": "c", "text": "La section opéra"}, {"id": "d", "text": "Son succès commercial"}], "explanation": "La chanson raconte un homme qui a commis un meurtre face aux conséquences. ''Mama, just killed a man... too late, my time has come.'' Elle explore la culpabilité, le regret et comment les actes ont des conséquences inévitables — on ne peut défaire ce qui a été fait.", "wrong_explanations": {"a": "La durée est structurelle ; le contenu est philosophiquement riche.", "c": "La section opéra exprime le conflit interne de manière dramatique.", "d": "Le succès reflète la résonance, mais c''est le sens qui le rend important."}}}'::jsonb WHERE question = 'What makes "Bohemian Rhapsody" philosophically interesting?';

UPDATE quiz_questions SET translations = translations || '{"pt": {"question": "Por que \"Working Class Hero\" de John Lennon contém contradições filosóficas?", "options": [{"id": "a", "text": "Não contém — é perfeitamente coerente"}, {"id": "b", "text": "Critica ''o sistema'' enquanto Lennon lucrou enormemente com o capitalismo"}, {"id": "c", "text": "A música contradiz a letra"}, {"id": "d", "text": "É demasiado curta"}], "explanation": "Lennon critica o capitalismo e as classes enquanto era uma estrela de rock milionária. A canção condena ser ''drogado com religião e sexo e TV'' enquanto Lennon usava a sua celebridade para vender discos e espalhar a sua mensagem através de... TV. A ação contradiz a mensagem.", "wrong_explanations": {"a": "A contradição entre opiniões declaradas e vida vivida é notável.", "c": "Musicalmente é coerente; a contradição é ideológica.", "d": "A duração é irrelevante para a consistência ideológica."}}, "es": {"question": "¿Por qué \"Working Class Hero\" de John Lennon contiene contradicciones filosóficas?", "options": [{"id": "a", "text": "No las contiene — es perfectamente coherente"}, {"id": "b", "text": "Critica ''el sistema'' mientras Lennon lucró enormemente del capitalismo"}, {"id": "c", "text": "La música contradice la letra"}, {"id": "d", "text": "Es demasiado corta"}], "explanation": "Lennon critica el capitalismo y las clases mientras era una estrella de rock millonaria. La canción condena ser ''drogado con religión y sexo y TV'' mientras Lennon usaba su celebridad para vender discos y difundir su mensaje a través de... TV. La acción contradice el mensaje.", "wrong_explanations": {"a": "La contradicción entre opiniones declaradas y vida vivida es notable.", "c": "Musicalmente es coherente; la contradicción es ideológica.", "d": "La duración es irrelevante para la consistencia ideológica."}}, "fr": {"question": "Pourquoi \"Working Class Hero\" de John Lennon contient-elle des contradictions philosophiques ?", "options": [{"id": "a", "text": "Elle n''en contient pas — elle est parfaitement cohérente"}, {"id": "b", "text": "Elle critique ''le système'' alors que Lennon a énormément profité du capitalisme"}, {"id": "c", "text": "La musique contredit les paroles"}, {"id": "d", "text": "Elle est trop courte"}], "explanation": "Lennon critique le capitalisme et les classes tout en étant une rock star millionnaire. La chanson dénonce le fait d''être ''drogué à la religion et au sexe et à la télé'' alors que Lennon utilisait sa célébrité pour vendre des disques et répandre son message via... la télé. L''action contredit le message.", "wrong_explanations": {"a": "La contradiction entre les opinions déclarées et la vie vécue est notable.", "c": "Musicalement c''est cohérent ; la contradiction est idéologique.", "d": "La durée est sans rapport avec la cohérence idéologique."}}}'::jsonb WHERE question = 'Why does "Working Class Hero" by John Lennon contain philosophical contradictions?';
